const getSubscriptions = (): AlertSubscription[] => {
  const stored = localStorage.getItem(SUBS_KEY);
  return stored ? JSON.parse(stored) : [];
};

const saveSubscriptions = (subs: AlertSubscription[]) => {
  localStorage.setItem(SUBS_KEY, JSON.stringify(subs));
};

const getNotifications = (): AppNotification[] => {
  const stored = localStorage.getItem(NOTIFS_KEY);
  return stored ? JSON.parse(stored) : [];
};

const saveNotifications = (notifs: AppNotification[]) => {
  localStorage.setItem(NOTIFS_KEY, JSON.stringify(notifs));
  // Dispatch event so UI updates immediately
  window.dispatchEvent(new Event('miculproducator:notifications_updated'));
};

const checkAndTriggerAlerts = (newAd: Ad) => {
  const subs = getSubscriptions();
  const currentNotifs = getNotifications();
  let hasMatch = false;

  subs.forEach(sub => {
    let match = false;

    if (sub.type === 'category' && sub.criteria.category) {
      if (newAd.categories.includes(sub.criteria.category)) {
        match = true;
      }
    }

    // Simple criteria check for county
    if (sub.type === 'search' && sub.criteria.county) {
        if(newAd.location.county === sub.criteria.county) {
            match = true;
        }
    }

    if (match) {
      hasMatch = true;
      const notif: AppNotification = {
        id: generateId(),
        title: 'New Product Alert!',
        message: `A new product matching "${sub.criteria.category || sub.criteria.county}" has been posted: ${newAd.title}`,
        adId: newAd.id,
        isRead: false,
        timestamp: Date.now()
      };
      currentNotifs.unshift(notif); // Add to top
    }
  });

  if (hasMatch) {
    saveNotifications(currentNotifs);
  }
};

