export const addReview = async (adId: string, review: Omit<Review, 'id' | 'createdAt'>): Promise<Review> => {
  await delay(500);
  const ads = getAdsFromStorage();
  const index = ads.findIndex(a => a.id === adId);

  if (index === -1) throw new Error("Ad not found");

  const newReview: Review = {
      ...review,
      id: generateId(),
      createdAt: Date.now()
  };

  const updatedReviews = [...(ads[index].reviews || []), newReview];

  // Recalculate rating
  const totalStars = updatedReviews.reduce((sum, r) => sum + r.rating, 0);
  const newRating = totalStars / updatedReviews.length;

  ads[index] = {
      ...ads[index],
      reviews: updatedReviews,
      rating: newRating
  };

  saveAdsToStorage(ads);
  return newReview;
};

