export const createAd = async (payload: CreateAdPayload): Promise<{ adId: string; token: string; paymentUrl: string }> => {
  const token = generateId().replace(/-/g, '') + generateId().replace(/-/g, '');

  if (USE_SUPABASE && supabase) {
      // 1. Upload Images
      const imageUrls: string[] = [];
      for (const file of payload.images) {
          try {
              const url = await uploadImageToSupabase(file);
              imageUrls.push(url);
          } catch (e) {
              console.error("Image upload failed", e);
          }
      }

      // 2. Insert DB Row
      const { data, error } = await supabase
        .from('ads')
        .insert({
            title: payload.title,
            description: payload.description,
            price: payload.price,
            categories: payload.categories,
            email: payload.email,
            phone_number: payload.phoneNumber,
            location: payload.location, // Supabase handles JSONB
            images: imageUrls,
            token: token,
            status: AdStatus.PENDING,
            rating: 0,
            reviews: []
        })
        .select()
        .single();

      if (error) throw new Error(error.message);

      return {
          adId: data.id,
          token: token,
          paymentUrl: 'mock-stripe-checkout'
      };
  }

  // Fallback Mock
  await delay(1000);
  const newId = generateId();

  let imageUrls: string[] = [];
  // Mock image processing
  if (payload.images.length > 0) {
      imageUrls = [`https://via.placeholder.com/400x300.png?text=Mock+Image`];
  }

  const newAd: Ad = {
    id: newId,
    title: payload.title,
    description: payload.description,
    price: payload.price,
    categories: payload.categories, 
    email: payload.email,
    phoneNumber: payload.phoneNumber,
    location: payload.location,
    images: imageUrls,
    token: token,
    status: AdStatus.PENDING, 
    createdAt: Date.now(),
    expiresAt: null,
    reviews: [],
    rating: 0
  };

  const ads = getAdsFromStorage();
  saveAdsToStorage([...ads, newAd]);
  return { adId: newId, token: token, paymentUrl: `mock-stripe-checkout` };
};

export const simulatePaymentSuccess = async (adId: string): Promise<void> => {
  if (USE_SUPABASE && supabase) {
      const expiresAt = new Date();
      expiresAt.setDate(expiresAt.getDate() + 28); // +28 days

      await supabase
        .from('ads')
        .update({ 
            status: AdStatus.ACTIVE,
            expires_at: expiresAt.toISOString()
        })
        .eq('id', adId);
      return;
  }

  await delay(1500);
  const ads = getAdsFromStorage();
  const updatedAds = ads.map(ad => {
    if (ad.id === adId) {
      return {
        ...ad,
        status: AdStatus.ACTIVE,
        expiresAt: Date.now() + (28 * 24 * 60 * 60 * 1000)
      };
    }
    return ad;
  });
  saveAdsToStorage(updatedAds);
};

export const verifyManageToken = async (id: string, token: string): Promise<Ad | null> => {
  if (USE_SUPABASE && supabase) {
      const { data, error } = await supabase
        .from('ads')
        .select('*')
        .eq('id', id)
        .eq('token', token)
        .single();

      if (error || !data) return null;
      return mapAdFromDB(data);
  }

  await delay(500);
  const ads = getAdsFromStorage();
  const ad = ads.find(a => a.id === id);
  if (ad && ad.token === token) return ad;
  return null;
