export const updateAd = async (id: string, token: string, updates: Partial<Ad>): Promise<boolean> => {
  if (USE_SUPABASE && supabase) {
      // Map App types back to DB types if necessary (e.g. location)
      const dbUpdates: any = { ...updates };
      if (updates.phoneNumber) dbUpdates.phone_number = updates.phoneNumber; // mapping

      const { error } = await supabase
        .from('ads')
        .update(dbUpdates)
        .eq('id', id)
        .eq('token', token);

      return !error;
  }

  await delay(800);
  const ads = getAdsFromStorage();
  const index = ads.findIndex(a => a.id === id && a.token === token);
  if (index === -1) return false;
  ads[index] = { ...ads[index], ...updates };
  saveAdsToStorage(ads);
  return true;
};

export const deleteAd = async (id: string, token: string): Promise<boolean> => {
  if (USE_SUPABASE && supabase) {
      const { error } = await supabase
        .from('ads')
        .delete()
        .eq('id', id)
        .eq('token', token);
      return !error;
  }

  await delay(500);
  const ads = getAdsFromStorage();
  const filtered = ads.filter(a => !(a.id === id && a.token === token));
  saveAdsToStorage(filtered);
  return true;
};

export const addReview = async (adId: string, review: Omit<Review, 'id' | 'createdAt'>): Promise<Review> => {
  const newReview: Review = {
      ...review,
      id: generateId(),
      createdAt: Date.now()
  };

  if (USE_SUPABASE && supabase) {
      // Fetch current reviews
      const { data: currentAd } = await supabase.from('ads').select('reviews, rating').eq('id', adId).single();

      const currentReviews = currentAd?.reviews || [];
      const updatedReviews = [...currentReviews, newReview];

      // Calculate rating
      const totalStars = updatedReviews.reduce((sum: number, r: any) => sum + r.rating, 0);
      const newRating = totalStars / updatedReviews.length;

      await supabase
        .from('ads')
        .update({
            reviews: updatedReviews,
            rating: newRating
        })
        .eq('id', adId);

      return newReview;
  }

  await delay(500);
  const ads = getAdsFromStorage();
  const index = ads.findIndex(a => a.id === adId);
  if (index === -1) throw new Error("Ad not found");

  const updatedReviews = [...(ads[index].reviews || []), newReview];
  const totalStars = updatedReviews.reduce((sum, r) => sum + r.rating, 0);
  const newRating = totalStars / updatedReviews.length;

  ads[index] = { ...ads[index], reviews: updatedReviews, rating: newRating };
  saveAdsToStorage(ads);
  return newReview;
};

