// Map Supabase Row to App Type
const mapAdFromDB = (row: any): Ad => {
    return {
        ...row,
        // Supabase returns string dates, App uses timestamps (number)
        createdAt: new Date(row.created_at).getTime(),
        expiresAt: row.expires_at ? new Date(row.expires_at).getTime() : null,
        // Ensure reviews is array
        reviews: Array.isArray(row.reviews) ? row.reviews : [],
        // Ensure price is number
        price: Number(row.price),
        rating: Number(row.rating)
    };
};

// Image Compression Helper
const compressImage = async (file: File): Promise<File> => {
  // If not an image, return original
  if (!file.type.startsWith('image/')) return file;

  return new Promise((resolve) => {
    const img = new Image();
    const objectUrl = URL.createObjectURL(file);
    img.src = objectUrl;

    img.onload = () => {
      URL.revokeObjectURL(objectUrl);
      const canvas = document.createElement('canvas');
      const MAX_WIDTH = 1200; 
      const MAX_HEIGHT = 1200;
      let width = img.width;
      let height = img.height;

      // Calculate new dimensions
      if (width > height) {
        if (width > MAX_WIDTH) {
          height *= MAX_WIDTH / width;
          width = MAX_WIDTH;
        }
      } else {
        if (height > MAX_HEIGHT) {
          width *= MAX_HEIGHT / height;
          height = MAX_HEIGHT;
        }
      }

      canvas.width = width;
      canvas.height = height;

      const ctx = canvas.getContext('2d');
      if (!ctx) {
          resolve(file); // Fallback if context fails
          return;
      }

      // High quality smoothing
      ctx.imageSmoothingEnabled = true;
      ctx.imageSmoothingQuality = 'high';
      ctx.drawImage(img, 0, 0, width, height);

      canvas.toBlob((blob) => {
        if (blob) {
            // Force JPEG for consistent compression
            const newFile = new File([blob], file.name.split('.')[0] + ".jpg", {
                type: 'image/jpeg',
                lastModified: Date.now(),
            });
            resolve(newFile);
        } else {
            resolve(file); // Fallback
        }
      }, 'image/jpeg', 0.8); // 80% Quality
    };

    img.onerror = () => {
        URL.revokeObjectURL(objectUrl);
        resolve(file); // Fallback on error
    };
  });
};

const uploadImageToSupabase = async (file: File): Promise<string> => {
    if (!supabase) throw new Error("Supabase not initialized");

    const fileExt = file.name.split('.').pop();
    const fileName = `${generateId()}.${fileExt}`;
    const filePath = `${fileName}`;

    const { error: uploadError } = await supabase.storage
        .from('images')
        .upload(filePath, file);

    if (uploadError) {
        console.error("Upload error details:", JSON.stringify(uploadError, null, 2));
        throw uploadError;
    }

    const { data } = supabase.storage.from('images').getPublicUrl(filePath);
    return data.publicUrl;
};

