export const createAd = async (payload: CreateAdPayload): Promise<{ adId: string; token: string; paymentUrl: string }> => {
  const token = generateId().replace(/-/g, '') + generateId().replace(/-/g, '');

  // Default to ACTIVE for MVP so users see their ads immediately. 
  // In a stricter V2, this would be PENDING until payment.
  const initialStatus = AdStatus.ACTIVE; 

  if (USE_SUPABASE && supabase) {
      try {
        // 1. Upload Images (With Compression)
        const imageUrls: string[] = [];
        for (const file of payload.images) {
            try {
                // Compress before upload to speed up rendering and save bandwidth
                const compressedFile = await compressImage(file);
                const url = await uploadImageToSupabase(compressedFile);
                imageUrls.push(url);
            } catch (e) {
                console.error("Image upload failed", e);
                // Continue with other images or mock url if needed, but for now we just skip
            }
        }

        // 2. Insert DB Row
        const { data, error } = await supabase
            .from('ads')
            .insert({
                title: payload.title,
                description: payload.description,
                price: payload.price,
                categories: payload.categories,
                email: payload.email,
                phone_number: payload.phoneNumber,
                location: payload.location, // Supabase handles JSONB
                images: imageUrls,
                token: token,
                status: initialStatus,
                rating: 0,
                reviews: []
            })
            .select()
            .single();

        if (error) throw error;

        return {
            adId: data.id,
            token: token,
            paymentUrl: 'mock-stripe-checkout'
        };
      } catch (e) {
         console.error("Supabase createAd failed (Using Mock Fallback). Error:", JSON.stringify(e, null, 2));
         // Fallback to mock
      }
  }

  // Fallback Mock
  await delay(1000);
  const newId = generateId();

  let imageUrls: string[] = [];
  // Mock image processing
  if (payload.images.length > 0) {
      imageUrls = [`https://via.placeholder.com/400x300.png?text=Mock+Image`];
  }

  const newAd: Ad = {
    id: newId,
    title: payload.title,
    description: payload.description,
    price: payload.price,
    categories: payload.categories, 
    email: payload.email,
    phoneNumber: payload.phoneNumber,
    location: payload.location,
    images: imageUrls,
    token: token,
    status: initialStatus,
    createdAt: Date.now(),
    expiresAt: null,
    reviews: [],
    rating: 0
  };

  const ads = getAdsFromStorage();
  saveAdsToStorage([...ads, newAd]);
  return { adId: newId, token: token, paymentUrl: `mock-stripe-checkout` };
};

