  }, [county, city]);

  const [createdAdData, setCreatedAdData] = useState<{ adId: string; token: string } | null>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const newFiles: File[] = Array.from(e.target.files);
      if (images.length + newFiles.length > 5) {
        alert("Puteți încărca maxim 5 imagini.");
        return;
      }
      setImages(prev => [...prev, ...newFiles]);
      const newPreviews = newFiles.map(file => URL.createObjectURL(file));
      setPreviews(prev => [...prev, ...newPreviews]);
    }
  };

  const removeImage = (index: number) => {
    setImages(prev => prev.filter((_, i) => i !== index));
    setPreviews(prev => {
      if (prev[index]) URL.revokeObjectURL(prev[index]);
      return prev.filter((_, i) => i !== index);
    });
  };

  const toggleCategory = (cat: string) => {
    if (!selectedPlan) return;
    if (selectedCategories.includes(cat)) {
      setSelectedCategories(prev => prev.filter(c => c !== cat));
    } else {
      if (selectedCategories.length < selectedPlan.productCount) {
        setSelectedCategories(prev => [...prev, cat]);
      } else {
        alert(`Planul ${selectedPlan.name} permite maxim ${selectedPlan.productCount} categorii.`);
      }
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (title.length < 5) { alert("Titlul trebuie să aibă cel puțin 5 caractere."); return; }
    if (Number(price) <= 0) { alert("Te rugăm să introduci un preț valid."); return; }
    if (selectedCategories.length === 0) { alert("Te rugăm să selectezi cel puțin o categorie."); return; }
    if (!agreedToTerms) { alert("Te rugăm să accepți Termenii și Condițiile."); return; }

    setLoading(true);
    try {
      const result = await createAd({
        title,
        description,
        categories: selectedCategories,
        price: Number(price),
        email,
        phoneNumber,
        location: { county, city, village: village || undefined },
        images,
      });
      setCreatedAdData({ adId: result.adId, token: result.token });
      setStep('payment');
    } catch (error) {
      alert('Eroare la crearea anunțului.');
    } finally {
      setLoading(false);
    }
  };

  if (step === 'success' && createdAdData) {
    return (
      <div className="px-4 py-8 text-center animate-fade-in">
        <div className="mx-auto flex items-center justify-center h-16 w-16 rounded-full bg-green-100 mb-6">
          <svg className="h-8 w-8 text-green-600" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" /></svg>
        </div>
        <h2 className="text-2xl font-bold text-gray-900 mb-2">Anunț Trimis!</h2>
        <p className="text-gray-500 mb-8 text-sm">Anunțul tău va fi publicat după o scurtă verificare.</p>
        <div className="bg-indigo-50 border border-indigo-200 rounded-lg p-6 text-left mb-8">
          <h3 className="text-sm font-bold text-indigo-800 uppercase mb-2">ID Anunț pentru Modificări</h3>
          <div className="bg-white border rounded-md p-4 text-center font-mono text-2xl font-bold tracking-widest text-indigo-700 shadow-inner">
            {createdAdData.adId.slice(0, 8).toUpperCase()}
          </div>
          <p className="text-xs text-indigo-600 mt-4 leading-relaxed">
            Te rugăm să salvezi acest ID. Dacă dorești să <strong>editezi</strong> sau să <strong>ștergi</strong> anunțul, contactează administratorul și comunică acest cod.
          </p>
        </div>
        <Button className="w-full" onClick={() => { if (onClose) onClose(); else onNavigate('/'); }}>Închide și Revino la Marketplace</Button>
      </div>
    );
  }

  if (step === 'payment') {
    return (
      <div className="px-4 py-8 text-center">
        <h2 className="text-xl font-bold mb-4">Anunțul tău este pregătit!</h2>
        <p className="text-gray-500 mb-8">Finalizează plata pentru a activa anunțul timp de {selectedPlan?.duration} zile.</p>
        <div className="bg-white p-6 rounded-lg border mb-8 text-left">
          <div className="flex justify-between mb-2"><span>Plan: {selectedPlan?.name}</span><span>{selectedPlan?.price} RON</span></div>
          <div className="flex justify-between border-t pt-4 font-bold"><span>Total</span><span className="text-indigo-600">{selectedPlan?.price} RON</span></div>
        </div>
        <Button isLoading={loading} onClick={async () => { setLoading(true); await simulatePaymentSuccess(createdAdData!.adId); setStep('success'); }} className="w-full h-12 mb-4">Plătește și Activează</Button>
        <button onClick={() => setStep('success')} className="text-sm text-gray-400 underline">Omite plata (Demo)</button>
      </div>
    );
  }

  if (step === 'plan') {
    return (
      <div className="w-full">
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          {PLANS.map(plan => (
            <div key={plan.id} onClick={() => { setSelectedPlan(plan); setStep('form'); }} className={`border-2 rounded-xl p-6 cursor-pointer hover:border-indigo-500 bg-white transition-all`}>
              <h3 className="text-lg font-bold text-center">{plan.name}</h3>
              <div className="mt-4 text-center font-extrabold text-3xl">{plan.price} RON</div>
              <ul className="mt-6 space-y-2 text-sm text-gray-600">
                {plan.features.map((f, i) => <li key={i} className="flex items-center"><svg className="h-4 w-4 text-green-500 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>{f}</li>)}
              </ul>
              <div className="mt-8 text-center bg-indigo-600 text-white py-2 rounded-md font-bold">Alege</div>
            </div>
          ))}
        </div>
      </div>
    );
  }

  return (
    <form onSubmit={handleSubmit} className="space-y-6">
      <div className="bg-blue-50 p-4 rounded-lg border border-blue-100 mb-4">
         <p className="text-xs text-blue-700 leading-relaxed">
           <strong>Notă:</strong> Utilizatorii nu au cont. Vei primi un ID unic după postare. Contactează adminul pentru orice modificare ulterioară folosind acel ID.
         </p>
      </div>

      <div>
        <label className="block text-sm font-medium text-gray-700">Titlu Anunț</label>
        <input type="text" required value={title} onChange={e => setTitle(e.target.value)} className="w-full border rounded-md p-2.5" placeholder="ex: Miere de Salcâm Proaspătă" />
      </div>

      <div>
        <label className="block text-sm font-medium text-gray-700 mb-2">Categorii (Maxim {selectedPlan?.productCount})</label>
        <div className="flex flex-wrap gap-2">
          {PRODUCT_CATEGORIES.map(cat => (
            <button key={cat} type="button" onClick={() => toggleCategory(cat)} className={`px-3 py-1.5 rounded-full text-xs font-medium border ${selectedCategories.includes(cat) ? 'bg-indigo-600 text-white' : 'bg-white text-gray-700'}`}>{cat}</button>
          ))}
        </div>
      </div>

      <div className="grid grid-cols-2 gap-4">
        <select required value={county} onChange={e => setCounty(e.target.value)} className="border rounded-md p-2.5"><option value="">Județ...</option>{getCounties().map(c => <option key={c} value={c}>{c}</option>)}</select>
        <select required disabled={!county} value={city} onChange={e => setCity(e.target.value)} className="border rounded-md p-2.5"><option value="">Oraș...</option>{availableCities.map(c => <option key={c} value={c}>{c}</option>)}</select>
      </div>

      <div className="grid grid-cols-2 gap-4">
        <input type="number" required value={price} onChange={e => setPrice(e.target.value)} className="border rounded-md p-2.5" placeholder="Preț (RON)" />
        <input type="tel" required value={phoneNumber} onChange={e => setPhoneNumber(e.target.value)} className="border rounded-md p-2.5" placeholder="Telefon (WhatsApp)" />
      </div>

      <input type="email" required value={email} onChange={e => setEmail(e.target.value)} className="w-full border rounded-md p-2.5" placeholder="Email contact" />

      <div>
        <label className="block text-sm font-medium text-gray-700">Descriere</label>
        <textarea required rows={4} value={description} onChange={e => setDescription(e.target.value)} className="w-full border rounded-md p-2.5" placeholder="Detalii produs..." />
      </div>

      <div className="space-y-4 pt-4 border-t">
        <div className="flex items-start">
          <input id="agree" type="checkbox" checked={agreedToTerms} onChange={e => setAgreedToTerms(e.target.checked)} className="mt-1 h-4 w-4 text-indigo-600 border-gray-300 rounded" required />
          <label htmlFor="agree" className="ml-2 block text-sm text-gray-600">
            Sunt de acord cu <button type="button" onClick={() => onOpenTerms && onOpenTerms()} className="text-indigo-600 underline">Termenii și Condițiile</button> și <button type="button" onClick={() => onOpenPrivacy && onOpenPrivacy()} className="text-indigo-600 underline">Politica GDPR</button>.
          </label>
        </div>
        <p className="text-[10px] text-gray-400 italic">
          Disclaimer: Platforma nu este responsabilă pentru veridicitatea anunțurilor. Utilizatorii sunt responsabili pentru propriile tranzacții.
        </p>
      </div>

      <div className="flex justify-end gap-3">
        <Button type="button" variant="outline" onClick={() => { if (onClose) onClose(); else onNavigate('/'); }}>Anulează</Button>
        <Button type="submit" isLoading={loading}>Continuă spre Plată</Button>
      </div>
    </form>
  );
};

import React, { useEffect, useState, useRef } from 'react';
import { Home } from './pages/Home';
import { CreateAd } from './pages/CreateAd';
import { AdDetails } from './pages/AdDetails';
import { Admin } from './pages/Admin';
import { Terms } from './pages/Terms';
import { Privacy } from './pages/Privacy';
import { Modal } from './components/Modal';
import { ToastContainer } from './components/Toast';
import { Ad, AppNotification, ToastMessage, ToastType } from './types';
import { fetchNotifications, clearAllNotifications } from './services/mockBackend';

const App: React.FC = () => {
  const [currentPath, setCurrentPath] = useState(window.location.hash || '#/');

  const [isCreateModalOpen, setIsCreateModalOpen] = useState(false);
  const [isTermsModalOpen, setIsTermsModalOpen] = useState(false);
  const [isPrivacyModalOpen, setIsPrivacyModalOpen] = useState(false);

  const [selectedAd, setSelectedAd] = useState<Ad | null>(null);
  const [toasts, setToasts] = useState<ToastMessage[]>([]);
  const [favorites, setFavorites] = useState<string[]>([]);
  const [notifications, setNotifications] = useState<AppNotification[]>([]);
  const [showNotifDropdown, setShowNotifDropdown] = useState(false);
  const notifDropdownRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const saved = localStorage.getItem('miculproducator_favorites');
    if (saved) setFavorites(JSON.parse(saved));
    loadNotifications();

    const handleNotifUpdate = () => loadNotifications();
    window.addEventListener('miculproducator:notifications_updated', handleNotifUpdate);

    const handleClickOutside = (event: MouseEvent) => {
        if (notifDropdownRef.current && !notifDropdownRef.current.contains(event.target as Node)) {
            setShowNotifDropdown(false);
        }
    };
    document.addEventListener('mousedown', handleClickOutside);

    return () => {
        window.removeEventListener('miculproducator:notifications_updated', handleNotifUpdate);
        document.removeEventListener('mousedown', handleClickOutside);
    };
  }, []);

  const loadNotifications = async () => {
      const data = await fetchNotifications();
      setNotifications(data);
  };

  const addToast = (type: ToastType, message: string) => {
    const id = Math.random().toString(36).substr(2, 9);
    setToasts((prev) => [...prev, { id, type, message }]);
  };

  const removeToast = (id: string) => {
    setToasts((prev) => prev.filter((t) => t.id !== id));
  };

  const handleToggleFavorite = (id: string) => {
    let newFavs: string[];
    if (favorites.includes(id)) {
      newFavs = favorites.filter(fav => fav !== id);
      addToast('info', 'Eliminat de la favorite');
    } else {
      newFavs = [...favorites, id];
      addToast('success', 'Adăugat la favorite');
    }
    setFavorites(newFavs);
    localStorage.setItem('miculproducator_favorites', JSON.stringify(newFavs));
  };

  const navigate = (path: string) => {
    window.location.hash = path;
    window.scrollTo(0, 0);
  };

  useEffect(() => {
    const handleHashChange = () => setCurrentPath(window.location.hash || '#/');
    window.addEventListener('hashchange', handleHashChange);
    return () => window.removeEventListener('hashchange', handleHashChange);
  }, []);

  const renderRoute = () => {
    const path = currentPath.replace('#', '');
    const cleanPath = path.split('?')[0];

    if (cleanPath === '/' || cleanPath === '') {
      return (
        <Home 
          onNavigate={navigate} 
          onOpenCreateModal={() => setIsCreateModalOpen(true)}
          onAdClick={(ad) => setSelectedAd(ad)}
          favoriteIds={favorites}
          onToggleFavorite={handleToggleFavorite}
          onAddToast={addToast}
        />
      );
    }

    if (cleanPath === '/admin') return <Admin onNavigate={navigate} />;

    if (cleanPath.startsWith('/ad/')) {
      const id = cleanPath.split('/ad/')[1];
      return (
        <AdDetails 
          id={id} 
          onNavigate={navigate} 
          isFavorite={favorites.includes(id)}
          onToggleFavorite={() => handleToggleFavorite(id)}
          onAddToast={addToast}
        />
      );
    }

    return <div className="p-8 text-center">404 - Pagina nu a fost găsită</div>;
  };

  const unreadCount = notifications.filter(n => !n.isRead).length;

  return (
    <div className="min-h-screen flex flex-col font-sans">
      <header className="bg-white shadow-sm sticky top-0 z-30 border-b border-gray-100">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-16 items-center">
            <div className="flex cursor-pointer" onClick={() => navigate('/')}>
              <span className="text-2xl font-black text-indigo-600 tracking-tight">MiculProducator</span>
            </div>

            <div className="flex items-center space-x-2">
              <div className="relative" ref={notifDropdownRef}>
                  <button onClick={() => setShowNotifDropdown(!showNotifDropdown)} className="p-2 rounded-full text-gray-500 hover:bg-gray-100 relative">
                      <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 17h5l-1.405-1.405A2.032 2.032 0 0118 14.158V11a6.002 6.002 0 00-4-5.659V5a2 2 0 10-4 0v.341C7.67 6.165 6 8.388 6 11v3.159c0 .538-.214 1.055-.595 1.436L4 17h5m6 0v1a3 3 0 11-6 0v-1m6 0H9" /></svg>
                      {unreadCount > 0 && <span className="absolute top-1.5 right-1.5 block h-2.5 w-2.5 rounded-full bg-red-500 ring-2 ring-white"></span>}
                  </button>
                  {showNotifDropdown && (
                      <div className="absolute right-0 mt-2 w-80 bg-white rounded-md shadow-lg z-50 border border-gray-100">
                          <div className="py-2 px-4 bg-gray-50 border-b flex justify-between items-center text-sm font-bold">
                              <span>Notificări</span>
                              <button onClick={async () => { await clearAllNotifications(); loadNotifications(); }} className="text-xs text-indigo-600">Șterge tot</button>
                          </div>
                          <div className="max-h-96 overflow-y-auto">
                              {notifications.length === 0 ? <div className="p-4 text-center text-sm text-gray-500">Nicio notificare.</div> : 
                                notifications.map(n => (
                                  <div key={n.id} className={`px-4 py-3 border-b text-sm cursor-pointer hover:bg-gray-50 ${!n.isRead ? 'bg-indigo-50' : ''}`}>
                                    <p className="font-semibold">{n.title}</p>
                                    <p className="text-xs text-gray-600">{n.message}</p>
                                  </div>
                                ))
                              }
                          </div>
                      </div>
                  )}
              </div>
              <button onClick={() => setIsCreateModalOpen(true)} className="px-4 py-2 text-sm font-semibold rounded-full shadow-md text-white bg-indigo-600 hover:bg-indigo-700 transition-all">
                + Adaugă Anunț
              </button>
            </div>
          </div>
        </div>
      </header>

      <main className="flex-grow bg-gray-50">{renderRoute()}</main>

      <footer className="bg-white border-t border-gray-200 mt-12 py-10">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
            <div className="space-y-4">
              <span className="text-xl font-bold text-indigo-600">MiculProducator</span>
              <p className="text-sm text-gray-500 max-w-xs">
                Susținem producătorii locali din România prin conectarea directă cu clienții.
              </p>
            </div>
            <div className="space-y-4">
              <h4 className="text-sm font-bold text-gray-900 uppercase">Link-uri Utile</h4>
              <ul className="space-y-2 text-sm text-gray-600">
                <li><button onClick={() => setIsTermsModalOpen(true)} className="hover:text-indigo-600 text-left">Termeni și Condiții</button></li>
                <li><button onClick={() => setIsPrivacyModalOpen(true)} className="hover:text-indigo-600 text-left">Politică de Confidențialitate</button></li>
                <li><button onClick={() => navigate('/admin')} className="hover:text-indigo-600 text-left">Admin</button></li>
              </ul>
            </div>
            <div className="space-y-4">
              <h4 className="text-sm font-bold text-gray-900 uppercase">Disclaimer</h4>
              <p className="text-xs text-gray-400 leading-relaxed italic">
                Platforma MiculProducator nu este responsabilă pentru conținutul anunțurilor postate de utilizatori sau pentru corectitudinea tranzacțiilor desfășurate între aceștia. Vă rugăm să verificați întotdeauna marfa înainte de plată.
              </p>
            </div>
          </div>
          <div className="border-t border-gray-100 mt-10 pt-6 text-center text-xs text-gray-400">
            &copy; {new Date().getFullYear()} MiculProducator. Toate drepturile rezervate.
          </div>
        </div>
      </footer>

      {/* Modals */}
      <Modal isOpen={isCreateModalOpen} onClose={() => setIsCreateModalOpen(false)} title="Publică un Anunț Nou">
        <CreateAd 
          onNavigate={navigate} 
          onClose={() => setIsCreateModalOpen(false)} 
          onOpenTerms={() => setIsTermsModalOpen(true)}
          onOpenPrivacy={() => setIsPrivacyModalOpen(true)}
        />
      </Modal>

      <Modal isOpen={isTermsModalOpen} onClose={() => setIsTermsModalOpen(false)} title="Termeni și Condiții">
        <Terms />
      </Modal>

      <Modal isOpen={isPrivacyModalOpen} onClose={() => setIsPrivacyModalOpen(false)} title="Politică de Confidențialitate">
        <Privacy />
      </Modal>

      <Modal isOpen={!!selectedAd} onClose={() => setSelectedAd(null)} title="Detalii Anunț">
        {selectedAd && <AdDetails id={selectedAd.id} initialData={selectedAd} onClose={() => setSelectedAd(null)} isFavorite={favorites.includes(selectedAd.id)} onToggleFavorite={() => handleToggleFavorite(selectedAd.id)} onAddToast={addToast} />}
      </Modal>

      <ToastContainer toasts={toasts} removeToast={removeToast} />
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Button } from '../components/Button';
import { createAd, simulatePaymentSuccess } from '../services/mockBackend';
import { getCounties, getCities, getVillages } from '../data/locations';
import { PRODUCT_CATEGORIES } from '../types';

interface CreateAdProps {
  onNavigate: (path: string) => void;
  onClose?: () => void;
  onOpenTerms?: () => void;
  onOpenPrivacy?: () => void;
}

interface Plan {
  id: 'basic' | 'standard' | 'premium';
  name: string;
  productCount: number;
  price: number;
  duration: number; 
  features: string[];
  color: string;
}

const PLANS: Plan[] = [
  {
    id: 'basic',
    name: 'Starter',
    productCount: 1,
    price: 10,
    duration: 28,
    features: ['Vinde 1 tip de produs', 'Vizibil în 1 Categorie', 'Valabilitate 28 Zile'],
    color: 'bg-blue-50 border-blue-200 text-blue-700'
  },
  {
    id: 'standard',
    name: 'Grower',
    productCount: 3,
    price: 20,
    duration: 28,
    features: ['Vinde până la 3 produse', 'Vizibil în 3 Categorii', 'Valabilitate 28 Zile', 'Recomandat'],
    color: 'bg-indigo-50 border-indigo-200 text-indigo-700'
  },
  {
    id: 'premium',
    name: 'Pro Market',
    productCount: 5,
    price: 30,
    duration: 28,
    features: ['Vinde până la 5 produse', 'Vizibil în 5 Categorii', 'Valabilitate 28 Zile', 'Suport Prioritar'],
    color: 'bg-purple-50 border-purple-200 text-purple-700'
  }
];

export const CreateAd: React.FC<CreateAdProps> = ({ onNavigate, onClose, onOpenTerms, onOpenPrivacy }) => {
  const [step, setStep] = useState<'plan' | 'form' | 'payment' | 'success'>('plan');
  const [loading, setLoading] = useState(false);
  const [selectedPlan, setSelectedPlan] = useState<Plan | null>(null);

  // Form State
  const [title, setTitle] = useState('');
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [price, setPrice] = useState('');
  const [description, setDescription] = useState('');
  const [email, setEmail] = useState('');
  const [phoneNumber, setPhoneNumber] = useState('');
  const [images, setImages] = useState<File[]>([]);
  const [previews, setPreviews] = useState<string[]>([]);
  const [agreedToTerms, setAgreedToTerms] = useState(false);

  // Location State
  const [county, setCounty] = useState('');
  const [city, setCity] = useState('');
  const [village, setVillage] = useState('');
  const [availableCities, setAvailableCities] = useState<string[]>([]);
  const [availableVillages, setAvailableVillages] = useState<string[]>([]);

  useEffect(() => {
    if (county) {
      setAvailableCities(getCities(county));
      setCity('');
      setVillage('');
    }
  }, [county]);

  useEffect(() => {
    if (county && city) {
      setAvailableVillages(getVillages(county, city));
    }
  }, [county, city]);

  const [createdAdData, setCreatedAdData] = useState<{ adId: string } | null>(null);

  const toggleCategory = (cat: string) => {
    if (!selectedPlan) return;
    if (selectedCategories.includes(cat)) {
      setSelectedCategories(prev => prev.filter(c => c !== cat));
    } else {
      if (selectedCategories.length < selectedPlan.productCount) {
        setSelectedCategories(prev => [...prev, cat]);
      } else {
        alert(`Planul ${selectedPlan.name} permite maxim ${selectedPlan.productCount} categorii.`);
      }
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (title.length < 5) return alert("Titlul e prea scurt.");
    if (selectedCategories.length === 0) return alert("Selectează o categorie.");
    if (!agreedToTerms) return alert("Acceptă termenii.");

    setLoading(true);
    try {
      const result = await createAd({
        title,
        description,
        categories: selectedCategories,
        price: Number(price),
        email,
        phoneNumber,
        location: { county, city, village: village || undefined },
        images,
      });
      setCreatedAdData({ adId: result.adId });
      setStep('payment');
    } catch (error) {
      alert('Eroare la crearea anunțului.');
    } finally {
      setLoading(false);
    }
  };

  if (step === 'success' && createdAdData) {
    return (
      <div className="px-4 py-8 text-center animate-fade-in">
        <div className="mx-auto flex items-center justify-center h-20 w-20 rounded-full bg-green-100 mb-6">
          <svg className="h-10 w-10 text-green-600" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" /></svg>
        </div>
        <h2 className="text-2xl font-bold text-gray-900 mb-2">Anunț înregistrat!</h2>
        <p className="text-gray-500 mb-8 text-sm">Vei primi un email de confirmare. Anunțul va apărea pe marketplace după plată/validare.</p>

        <div className="bg-white border-2 border-indigo-100 rounded-2xl p-8 max-w-sm mx-auto shadow-sm mb-8">
          <h3 className="text-xs font-black text-indigo-400 uppercase tracking-widest mb-4">Cod Unic Identificare (ID)</h3>
          <div className="bg-indigo-50 border border-indigo-100 rounded-lg p-4 font-mono text-2xl font-bold text-indigo-700 select-all">
            {createdAdData.adId.slice(0, 8).toUpperCase()}
          </div>
          <div className="mt-6 text-left space-y-3">
            <p className="text-xs text-gray-600 leading-relaxed">
              <strong>Important:</strong> Utilizatorii nu au cont de client. Orice modificare sau ștergere se face contactând administratorul.
            </p>
            <p className="text-xs text-gray-600 leading-relaxed">
              Furnizează acest <strong>ID</strong> administratorului pentru a valida identitatea ta și a efectua modificările dorite.
            </p>
          </div>
        </div>

        <Button className="w-full h-12" onClick={() => { if (onClose) onClose(); else onNavigate('/'); }}>Revino la Marketplace</Button>
      </div>
    );
  }

  if (step === 'payment') {
    return (
      <div className="px-4 py-8 text-center">
        <h2 className="text-xl font-bold mb-4">Ultimul pas: Plata</h2>
        <p className="text-gray-500 mb-8">Anunțul tău va fi activ imediat după confirmarea plății.</p>
        <div className="bg-indigo-50 p-6 rounded-xl border border-indigo-100 mb-8 text-left">
          <div className="flex justify-between items-center mb-2">
            <span className="text-sm font-medium">Plan selectat:</span>
            <span className="font-bold">{selectedPlan?.name}</span>
          </div>
          <div className="flex justify-between items-center border-t border-indigo-200 pt-4">
            <span className="text-sm font-medium">De plată:</span>
            <span className="text-2xl font-black text-indigo-700">{selectedPlan?.price} RON</span>
          </div>
        </div>
        <Button isLoading={loading} onClick={async () => { setLoading(true); await simulatePaymentSuccess(createdAdData!.adId); setStep('success'); }} className="w-full h-14 text-lg">Plătește prin Stripe</Button>
        <button onClick={() => setStep('success')} className="mt-4 text-xs text-gray-400 hover:text-gray-600 transition-colors">Demo: Omite plata și finalizează</button>
      </div>
    );
  }

  if (step === 'plan') {
    return (
      <div className="w-full">
        <div className="text-center mb-8">
           <h2 className="text-xl font-bold">Alege un plan de promovare</h2>
           <p className="text-sm text-gray-500">Susține producătorii locali și vinde-ți produsele rapid.</p>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          {PLANS.map(plan => (
            <div key={plan.id} onClick={() => { setSelectedPlan(plan); setStep('form'); }} className="group relative bg-white border-2 border-gray-100 rounded-2xl p-6 cursor-pointer hover:border-indigo-500 hover:shadow-xl transition-all duration-300">
              {plan.id === 'standard' && <div className="absolute -top-3 left-1/2 -translate-x-1/2 bg-indigo-600 text-white text-[10px] font-bold px-3 py-1 rounded-full uppercase">Cel mai popular</div>}
              <h3 className="text-lg font-bold text-gray-900">{plan.name}</h3>
              <div className="mt-4 flex items-baseline">
                <span className="text-3xl font-black">{plan.price}</span>
                <span className="ml-1 text-gray-500 text-sm font-medium">RON</span>
              </div>
              <ul className="mt-6 space-y-3">
                {plan.features.map((f, i) => (
                  <li key={i} className="flex items-center text-sm text-gray-600">
                    <svg className="h-4 w-4 text-indigo-500 mr-2 flex-shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>
                    {f}
                  </li>
                ))}
              </ul>
              <div className="mt-8 text-center bg-gray-50 group-hover:bg-indigo-600 group-hover:text-white py-3 rounded-xl font-bold transition-colors">Selectează</div>
            </div>
          ))}
        </div>
      </div>
    );
  }

  return (
    <form onSubmit={handleSubmit} className="space-y-6">
      <div className="bg-amber-50 border border-amber-200 p-4 rounded-xl flex items-start gap-3">
        <svg className="w-5 h-5 text-amber-600 mt-0.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
        <p className="text-xs text-amber-800 leading-relaxed font-medium">
          Această platformă funcționează fără cont de utilizator. Orice modificare a anunțului se face contactând administratorul prin furnizarea ID-ului unic primit la final.
        </p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div>
          <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Titlu Produs</label>
          <input type="text" required value={title} onChange={e => setTitle(e.target.value)} className="w-full border-gray-200 rounded-xl p-3 bg-gray-50 focus:bg-white focus:ring-2 focus:ring-indigo-500 transition-all" placeholder="ex: Miere bio de salcâm" />
        </div>
        <div>
          <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Preț (RON)</label>
          <input type="number" required value={price} onChange={e => setPrice(e.target.value)} className="w-full border-gray-200 rounded-xl p-3 bg-gray-50 focus:bg-white focus:ring-2 focus:ring-indigo-500 transition-all" placeholder="ex: 35" />
        </div>
      </div>

      <div>
        <label className="block text-xs font-bold text-gray-500 uppercase mb-2">Categorii (Maxim {selectedPlan?.productCount})</label>
        <div className="flex flex-wrap gap-2">
          {PRODUCT_CATEGORIES.map(cat => (
            <button key={cat} type="button" onClick={() => toggleCategory(cat)} className={`px-4 py-2 rounded-full text-xs font-bold border-2 transition-all ${selectedCategories.includes(cat) ? 'bg-indigo-600 border-indigo-600 text-white' : 'bg-white border-gray-100 text-gray-500 hover:border-gray-200'}`}>{cat}</button>
          ))}
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div>
          <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Județ</label>
          <select required value={county} onChange={e => setCounty(e.target.value)} className="w-full border-gray-200 rounded-xl p-3 bg-gray-50">
            <option value="">Alege județ...</option>
            {getCounties().map(c => <option key={c} value={c}>{c}</option>)}
          </select>
        </div>
        <div>
          <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Localitate</label>
          <select required disabled={!county} value={city} onChange={e => setCity(e.target.value)} className="w-full border-gray-200 rounded-xl p-3 bg-gray-50 disabled:opacity-50">
            <option value="">Alege oraș...</option>
            {availableCities.map(c => <option key={c} value={c}>{c}</option>)}
          </select>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div>
          <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Email (pentru confirmare)</label>
          <input type="email" required value={email} onChange={e => setEmail(e.target.value)} className="w-full border-gray-200 rounded-xl p-3 bg-gray-50 focus:bg-white focus:ring-2 focus:ring-indigo-500 transition-all" placeholder="contact@producator.ro" />
        </div>
        <div>
          <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Telefon (WhatsApp)</label>
          <input type="tel" required value={phoneNumber} onChange={e => setPhoneNumber(e.target.value)} className="w-full border-gray-200 rounded-xl p-3 bg-gray-50 focus:bg-white focus:ring-2 focus:ring-indigo-500 transition-all" placeholder="07xx xxx xxx" />
        </div>
      </div>

      <div>
        <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Descriere Detaliată</label>
        <textarea required rows={4} value={description} onChange={e => setDescription(e.target.value)} className="w-full border-gray-200 rounded-xl p-3 bg-gray-50 focus:bg-white focus:ring-2 focus:ring-indigo-500 transition-all" placeholder="Povestește-ne despre produsul tău..." />
      </div>

      <div className="pt-6 border-t border-gray-100 flex items-center justify-between gap-4">
        <div className="flex items-center gap-2">
          <input type="checkbox" id="agreed" checked={agreedToTerms} onChange={e => setAgreedToTerms(e.target.checked)} className="rounded text-indigo-600 focus:ring-indigo-500 w-5 h-5" required />
          <label htmlFor="agreed" className="text-xs text-gray-500 leading-tight">Sunt de acord cu <button type="button" onClick={onOpenTerms} className="text-indigo-600 underline">Termenii</button> și <button type="button" onClick={onOpenPrivacy} className="text-indigo-600 underline">Confidențialitatea</button>.</label>
        </div>
        <div className="flex gap-3">
          <Button type="button" variant="outline" onClick={() => { if (onClose) onClose(); else onNavigate('/'); }}>Anulează</Button>
          <Button type="submit" isLoading={loading}>Continuă</Button>
        </div>
      </div>
    </form>
  );
};

import React, { useEffect, useState, useMemo } from 'react';
import { getAllAds, adminDeleteAd, resetDatabase, adminUpdateAd } from '../services/mockBackend';
import { Ad, AdStatus } from '../types';
import { Button } from '../components/Button';
import { Modal } from '../components/Modal';
import { getCounties, getCities, getVillages } from '../data/locations';

interface AdminProps {
  onNavigate: (path: string) => void;
}

export const Admin: React.FC<AdminProps> = ({ onNavigate }) => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [pin, setPin] = useState('');

  // Data State
  const [ads, setAds] = useState<Ad[]>([]);
  const [loading, setLoading] = useState(false);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'moderation' | 'system'>('dashboard');

  // Edit Modal State
  const [editingAd, setEditingAd] = useState<Ad | null>(null);
  const [editTitle, setEditTitle] = useState('');
  const [editDesc, setEditDesc] = useState('');
  const [editPrice, setEditPrice] = useState('');
  const [editPhone, setEditPhone] = useState('');
  const [editCategories, setEditCategories] = useState<string[]>([]);
  const [editCounty, setEditCounty] = useState('');
  const [editCity, setEditCity] = useState('');
  const [editVillage, setEditVillage] = useState('');
  const [availableCities, setAvailableCities] = useState<string[]>([]);
  const [availableVillages, setAvailableVillages] = useState<string[]>([]);
  const [saving, setSaving] = useState(false);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (pin === '0000') {
      setIsAuthenticated(true);
      fetchData();
    } else {
      alert('Invalid PIN');
    }
  };

  const fetchData = async () => {
    setLoading(true);
    try {
      const data = await getAllAds();
      setAds(data);
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (id: string) => {
    if (!confirm("Sigur vrei să ștergi acest anunț? (Admin Override)")) return;
    try {
      const success = await adminDeleteAd(id);
      if (success) {
        alert("Anunț șters cu succes!");
        fetchData();
      } else {
        alert("Ștergerea a eșuat. Anunțul nu a fost găsit.");
      }
    } catch (e) {
      alert("Eroare de sistem la ștergere.");
    }
  };

  const openEditModal = (ad: Ad) => {
    setEditingAd(ad);
    setEditTitle(ad.title);
    setEditDesc(ad.description);
    setEditPrice(String(ad.price));
    setEditPhone(ad.phoneNumber);
    setEditCategories(ad.categories);
    setEditCounty(ad.location.county);
    setEditCity(ad.location.city);
    setEditVillage(ad.location.village || '');
    setAvailableCities(getCities(ad.location.county));
    setAvailableVillages(getVillages(ad.location.county, ad.location.city));
  };

  useEffect(() => {
    if (editCounty) setAvailableCities(getCities(editCounty));
  }, [editCounty]);

  useEffect(() => {
    if (editCounty && editCity) setAvailableVillages(getVillages(editCounty, editCity));
  }, [editCounty, editCity]);

  const handleSaveEdit = async () => {
    if (!editingAd) return;
    setSaving(true);
    try {
      const updates: Partial<Ad> = {
        title: editTitle,
        description: editDesc,
        price: Number(editPrice),
        phoneNumber: editPhone,
        categories: editCategories,
        location: {
          county: editCounty,
          city: editCity,
          village: editVillage || undefined
        }
      };
      await adminUpdateAd(editingAd.id, updates);
      setEditingAd(null);
      fetchData();
      alert("Anunț actualizat cu succes!");
    } catch (e) {
      alert("Actualizarea a eșuat.");
    } finally {
      setSaving(false);
    }
  };

  const stats = useMemo(() => {
    const totalAds = ads.length;
    const totalActive = ads.filter(a => a.status === AdStatus.ACTIVE).length;
    const uniqueSellers = new Set(ads.map(a => a.email)).size;
    return { totalAds, totalActive, uniqueSellers };
  }, [ads]);

  if (!isAuthenticated) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-900 px-4">
        <div className="max-w-md w-full bg-white rounded-3xl shadow-2xl p-10">
          <div className="text-center mb-10">
            <div className="inline-flex items-center justify-center w-16 h-16 bg-indigo-100 rounded-full mb-4">
               <svg className="w-8 h-8 text-indigo-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z" /></svg>
            </div>
            <h2 className="text-2xl font-black text-gray-900 uppercase tracking-tighter">Admin Control</h2>
            <p className="text-xs text-gray-400 mt-1 uppercase font-bold">Introdu codul PIN (0000)</p>
          </div>
          <form onSubmit={handleLogin} className="space-y-6">
            <input 
              type="password" 
              value={pin}
              onChange={(e) => setPin(e.target.value)}
              className="mt-1 block w-full border-2 border-gray-100 rounded-2xl p-4 focus:ring-4 focus:ring-indigo-100 focus:border-indigo-500 text-center text-3xl tracking-[1em] font-mono outline-none transition-all"
              maxLength={4}
              autoFocus
            />
            <Button type="submit" className="w-full h-14 text-lg">Deblochează Dashboard</Button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 pb-20">
      <nav className="bg-white border-b border-gray-100 sticky top-0 z-40">
         <div className="max-w-7xl mx-auto px-4 h-20 flex items-center justify-between">
            <div className="flex items-center gap-3">
               <span className="text-2xl font-black text-indigo-600 tracking-tighter">MP<span className="text-gray-900">ADMIN</span></span>
               <span className="bg-indigo-50 text-indigo-600 text-[10px] font-black px-2 py-0.5 rounded-full uppercase tracking-widest">v1.0.4</span>
            </div>
            <button onClick={() => setIsAuthenticated(false)} className="text-xs font-bold text-gray-400 hover:text-red-500 transition-colors uppercase tracking-widest">Sesiune Finalizată</button>
