                     </div>
                     <div className="bg-white p-8 rounded-3xl border border-gray-100 shadow-sm">
                        <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">Vânzători</p>
                        <p className="text-4xl font-black text-gray-900">{stats.uniqueSellers}</p>
                        <p className="text-xs text-gray-500 mt-2 font-medium">Producători unici activi</p>
                     </div>
                     <div className="bg-white p-8 rounded-3xl border border-gray-100 shadow-sm">
                        <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">Stare Marketplace</p>
                        <p className="text-4xl font-black text-green-500">{stats.totalActive}</p>
                        <p className="text-xs text-gray-500 mt-2 font-medium">Anunțuri active în prezent</p>
                     </div>
                  </div>
