                           <thead>
                              <tr className="text-[10px] font-black text-gray-400 uppercase tracking-widest border-b border-gray-50">
                                 <th className="px-8 py-4">AD ID (Public)</th>
                                 <th className="px-8 py-4">Detalii Produs</th>
                                 <th className="px-8 py-4">Preț / Contact</th>
                                 <th className="px-8 py-4">Stare</th>
                                 <th className="px-8 py-4 text-right">Intervenție</th>
