      setIsAuthenticated(true);
      fetchData();
    } else {
      alert('PIN incorect. Încearcă 0000.');
    }
  };

  const fetchData = useCallback(async () => {
    setLoading(true);
    try {
      const data = await getAllAds();
      setAds(data);
    } catch (e) {
      console.error("Fetch error:", e);
    } finally {
      setLoading(false);
    }
  }, []);

  const handleDelete = async (id: string) => {
    if (!confirm("Ești sigur că vrei să ștergi acest anunț definitiv?")) return;

    // Optimistic UI: remove immediately, then confirm with backend
    const originalAds = [...ads];
    setAds(prev => prev.filter(a => a.id !== id));
    setDeletingId(id);

    try {
      const success = await adminDeleteAd(id);
      if (!success) {
        // Rollback on failure
        setAds(originalAds);
        alert("Ștergerea a eșuat. Verifică conexiunea.");
      }
    } catch (e) {
