import { fetchNotifications, clearAllNotifications } from './services/mockBackend';

const App: React.FC = () => {
  const [currentPath, setCurrentPath] = useState(window.location.hash || '#/');

  const [isCreateModalOpen, setIsCreateModalOpen] = useState(false);
  const [isTermsModalOpen, setIsTermsModalOpen] = useState(false);
  const [isPrivacyModalOpen, setIsPrivacyModalOpen] = useState(false);

  const [selectedAd, setSelectedAd] = useState<Ad | null>(null);
  const [toasts, setToasts] = useState<ToastMessage[]>([]);
  const [favorites, setFavorites] = useState<string[]>([]);
  const [notifications, setNotifications] = useState<AppNotification[]>([]);
  const [showNotifDropdown, setShowNotifDropdown] = useState(false);
  const notifDropdownRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const saved = localStorage.getItem('miculproducator_favorites');
    if (saved) setFavorites(JSON.parse(saved));
    loadNotifications();

    const handleNotifUpdate = () => loadNotifications();
    window.addEventListener('miculproducator:notifications_updated', handleNotifUpdate);

    const handleClickOutside = (event: MouseEvent) => {
        if (notifDropdownRef.current && !notifDropdownRef.current.contains(event.target as Node)) {
            setShowNotifDropdown(false);
        }
    };
    document.addEventListener('mousedown', handleClickOutside);

    return () => {
        window.removeEventListener('miculproducator:notifications_updated', handleNotifUpdate);
        document.removeEventListener('mousedown', handleClickOutside);
    };
  }, []);

  const loadNotifications = async () => {
      const data = await fetchNotifications();
      setNotifications(data);
  };

  const addToast = (type: ToastType, message: string) => {
    const id = Math.random().toString(36).substr(2, 9);
    setToasts((prev) => [...prev, { id, type, message }]);
  };

  const removeToast = (id: string) => {
    setToasts((prev) => prev.filter((t) => t.id !== id));
  };

  const handleToggleFavorite = (id: string) => {
    let newFavs: string[];
    if (favorites.includes(id)) {
      newFavs = favorites.filter(fav => fav !== id);
      addToast('info', 'Eliminat de la favorite');
    } else {
      newFavs = [...favorites, id];
      addToast('success', 'Adăugat la favorite');
    }
    setFavorites(newFavs);
    localStorage.setItem('miculproducator_favorites', JSON.stringify(newFavs));
  };

  const navigate = (path: string) => {
    window.location.hash = path;
    window.scrollTo(0, 0);
  };

  useEffect(() => {
    const handleHashChange = () => setCurrentPath(window.location.hash || '#/');
    window.addEventListener('hashchange', handleHashChange);
    return () => window.removeEventListener('hashchange', handleHashChange);
  }, []);

  const renderRoute = () => {
    const path = currentPath.replace('#', '');
    const cleanPath = path.split('?')[0];

    if (cleanPath === '/' || cleanPath === '') {
      return (
        <Home 
          onNavigate={navigate} 
          onOpenCreateModal={() => setIsCreateModalOpen(true)}
          onAdClick={(ad) => setSelectedAd(ad)}
          favoriteIds={favorites}
          onToggleFavorite={handleToggleFavorite}
          onAddToast={addToast}
        />
      );
    }

    if (cleanPath === '/admin') return <Admin onNavigate={navigate} />;
    if (cleanPath === '/payment-success') return <PaymentSuccess onNavigate={navigate} />;

    if (cleanPath.startsWith('/ad/')) {
      const id = cleanPath.split('/ad/')[1];
      return (
        <AdDetails 
          id={id} 
          onNavigate={navigate} 
          isFavorite={favorites.includes(id)}
          onToggleFavorite={() => handleToggleFavorite(id)}
          onAddToast={addToast}
        />
      );
    }

    return <div className="p-8 text-center">404 - Pagina nu a fost găsită</div>;
  };

  const unreadCount = notifications.filter(n => !n.isRead).length;

  return (
    <div className="min-h-screen flex flex-col font-sans text-gray-900">
      <header className="bg-white shadow-sm sticky top-0 z-30 border-b border-gray-100">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-16 items-center">
            <div className="flex cursor-pointer" onClick={() => navigate('/')}>
              <span className="text-2xl font-black text-indigo-600 tracking-tight">MiculProducator</span>
            </div>

            <div className="flex items-center space-x-2">
              <div className="relative" ref={notifDropdownRef}>
                  <button onClick={() => setShowNotifDropdown(!showNotifDropdown)} className="p-2 rounded-full text-gray-500 hover:bg-gray-100 relative">
                      <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 17h5l-1.405-1.405A2.032 2.032 0 0118 14.158V11a6.002 6.002 0 00-4-5.659V5a2 2 0 10-4 0v.341C7.67 6.165 6 8.388 6 11v3.159c0 .538-.214 1.055-.595 1.436L4 17h5m6 0v1a3 3 0 11-6 0v-1m6 0H9" /></svg>
                      {unreadCount > 0 && <span className="absolute top-1.5 right-1.5 block h-2.5 w-2.5 rounded-full bg-red-500 ring-2 ring-white"></span>}
                  </button>
                  {showNotifDropdown && (
                      <div className="absolute right-0 mt-2 w-80 bg-white rounded-md shadow-lg z-50 border border-gray-100 animate-scale-in">
                          <div className="py-2 px-4 bg-gray-50 border-b flex justify-between items-center text-sm font-bold">
                              <span>Notificări</span>
                              <button onClick={async () => { await clearAllNotifications(); loadNotifications(); }} className="text-xs text-indigo-600 hover:underline">Șterge tot</button>
                          </div>
                          <div className="max-h-96 overflow-y-auto">
                              {notifications.length === 0 ? <div className="p-4 text-center text-sm text-gray-500 italic">Nicio notificare momentan.</div> : 
                                notifications.map(n => (
                                  <div key={n.id} className={`px-4 py-3 border-b text-sm cursor-pointer hover:bg-gray-50 ${!n.isRead ? 'bg-indigo-50' : ''}`}>
                                    <p className="font-semibold text-indigo-900">{n.title}</p>
                                    <p className="text-xs text-gray-600 line-clamp-2">{n.message}</p>
                                  </div>
                                ))
                              }
                          </div>
                      </div>
                  )}
              </div>
              <button onClick={() => setIsCreateModalOpen(true)} className="px-4 py-2 text-sm font-semibold rounded-full shadow-md text-white bg-indigo-600 hover:bg-indigo-700 transition-all hover:scale-105 active:scale-95">
                + Adaugă Anunț
              </button>
            </div>
          </div>
        </div>
      </header>

      <main className="flex-grow bg-gray-50">{renderRoute()}</main>

      <footer className="bg-white border-t border-gray-200 mt-12 py-10">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-8 text-center md:text-left">
            <div className="space-y-4">
              <span className="text-xl font-black text-indigo-600 uppercase tracking-tighter">MiculProducator</span>
              <p className="text-sm text-gray-500 max-w-xs mx-auto md:mx-0">
                Susținem producătorii locali din România prin conectarea directă cu clienții din comunitate.
              </p>
            </div>
            <div className="space-y-4">
              <h4 className="text-sm font-black text-gray-900 uppercase tracking-widest">Link-uri Utile</h4>
              <ul className="space-y-2 text-sm text-gray-600">
                <li><button onClick={() => setIsTermsModalOpen(true)} className="hover:text-indigo-600 transition-colors">Termeni și Condiții</button></li>
                <li><button onClick={() => setIsPrivacyModalOpen(true)} className="hover:text-indigo-600 transition-colors">Politică de Confidențialitate</button></li>
                <li><button onClick={() => navigate('/admin')} className="hover:text-indigo-600 transition-colors font-bold">Panou Admin</button></li>
              </ul>
            </div>
            <div className="space-y-4">
              <h4 className="text-sm font-black text-gray-900 uppercase tracking-widest">Securitate</h4>
              <p className="text-xs text-gray-400 leading-relaxed italic">
                Tranzacțiile sunt securizate prin Stripe. Managementul anunțurilor se face via link securizat trimis pe email (Brevo).
              </p>
            </div>
          </div>
          <div className="border-t border-gray-100 mt-10 pt-6 text-center text-[10px] text-gray-400 uppercase font-bold tracking-widest">
            &copy; {new Date().getFullYear()} MiculProducator. Construit pentru comunitate.
          </div>
        </div>
      </footer>

      {/* Modals */}
      <Modal isOpen={isCreateModalOpen} onClose={() => setIsCreateModalOpen(false)} title="Publică un Anunț Nou">
        <CreateAd 
          onNavigate={navigate} 
          onClose={() => setIsCreateModalOpen(false)} 
          onOpenTerms={() => setIsTermsModalOpen(true)}
          onOpenPrivacy={() => setIsPrivacyModalOpen(true)}
        />
      </Modal>

      <Modal isOpen={isTermsModalOpen} onClose={() => setIsTermsModalOpen(false)} title="Termeni și Condiții">
        <Terms />
      </Modal>

      <Modal isOpen={isPrivacyModalOpen} onClose={() => setIsPrivacyModalOpen(false)} title="Politică de Confidențialitate">
        <Privacy />
      </Modal>

      <Modal isOpen={!!selectedAd} onClose={() => setSelectedAd(null)} title="Detalii Anunț">
        {selectedAd && <AdDetails id={selectedAd.id} initialData={selectedAd} onClose={() => setSelectedAd(null)} isFavorite={favorites.includes(selectedAd.id)} onToggleFavorite={() => handleToggleFavorite(selectedAd.id)} onAddToast={addToast} />}
      </Modal>

      <ToastContainer toasts={toasts} removeToast={removeToast} />
    </div>
  );
};

