import React, { useEffect, useState, useMemo } from 'react';
import { AdCard } from '../components/AdCard';
import { Carousel, Slide } from '../components/Carousel';
import { CategoryNav } from '../components/CategoryNav';
import { fetchActiveAds, subscribeToAlert } from '../services/mockBackend';
import { Ad, ToastType } from '../types';
import { getCounties, getCities, getVillages } from '../data/locations';
import { getCountiesOnRoute } from '../utils/routeGraph';

interface HomeProps {
  onNavigate: (path: string) => void;
  onOpenCreateModal: () => void;
  onAdClick: (ad: Ad) => void;
  favoriteIds: string[];
  onToggleFavorite: (id: string) => void;
  onAddToast?: (type: ToastType, msg: string) => void;
}

export const Home: React.FC<HomeProps> = ({ 
  onNavigate, 
  onOpenCreateModal, 
  onAdClick,
  favoriteIds,
  onToggleFavorite,
  onAddToast
}) => {
  const [ads, setAds] = useState<Ad[]>([]);
  const [loading, setLoading] = useState(true);
  const [currentPage, setCurrentPage] = useState(1);
  const itemsPerPage = 12;

  const [searchMode, setSearchMode] = useState<'local' | 'route'>('local');
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCategory, setSelectedCategory] = useState('');
  const [showFavoritesOnly, setShowFavoritesOnly] = useState(false);

  const [filterCounty, setFilterCounty] = useState('');
  const [filterCity, setFilterCity] = useState('');
  const [filterVillage, setFilterVillage] = useState('');
  const [availableCities, setAvailableCities] = useState<string[]>([]);
  const [availableVillages, setAvailableVillages] = useState<string[]>([]);

  const [routeStartCounty, setRouteStartCounty] = useState('');
  const [routeEndCounty, setRouteEndCounty] = useState('');
  const [calculatedRouteCounties, setCalculatedRouteCounties] = useState<string[]>([]);

  const loadAds = async () => {
    try {
      const data = await fetchActiveAds();
      setAds(data);
    } catch (err) { console.error(err); } 
    finally { setLoading(false); }
  };

  useEffect(() => {
    loadAds();
    window.addEventListener('miculproducator:ad_updated', loadAds);
    return () => window.removeEventListener('miculproducator:ad_updated', loadAds);
  }, []);

  useEffect(() => { setCurrentPage(1); }, [searchTerm, selectedCategory, showFavoritesOnly, filterCounty, filterCity, filterVillage, routeStartCounty, routeEndCounty, searchMode]);

  useEffect(() => {
    if (filterCounty) {
      setAvailableCities(getCities(filterCounty));
      setFilterCity('');
    } else {
      setAvailableCities([]);
    }
  }, [filterCounty]);

  useEffect(() => {
    if (searchMode === 'route' && routeStartCounty && routeEndCounty) {
      const path = getCountiesOnRoute(routeStartCounty, routeEndCounty);
      setCalculatedRouteCounties(path);
    } else {
      setCalculatedRouteCounties([]);
    }
  }, [searchMode, routeStartCounty, routeEndCounty]);

  const processedAds = useMemo(() => {
    const filtered = ads.filter(ad => {
      const matchesSearch = ad.title.toLowerCase().includes(searchTerm.toLowerCase()) || ad.description.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesCategory = selectedCategory ? ad.categories.includes(selectedCategory) : true;
      let matchesLocation = true;

      if (searchMode === 'local') {
        const matchesCounty = filterCounty ? ad.location.county === filterCounty : true;
        const matchesCity = filterCity ? ad.location.city === filterCity : true;
        const matchesVillage = filterVillage ? ad.location.village === filterVillage : true;
        matchesLocation = matchesCounty && matchesCity && matchesVillage;
      } else {
        if (routeStartCounty && routeEndCounty && calculatedRouteCounties.length > 0) {
          matchesLocation = calculatedRouteCounties.includes(ad.location.county);
        }
      }
      const matchesFavorite = showFavoritesOnly ? favoriteIds.includes(ad.id) : true;
      return matchesSearch && matchesCategory && matchesLocation && matchesFavorite;
    });

    return filtered.sort((a, b) => {
      // 1. PREMIUM BOOST: Always first
      if (a.isPremium && !b.isPremium) return -1;
      if (!a.isPremium && b.isPremium) return 1;

      // 2. ROUTE SORTING: If in route mode
      if (searchMode === 'route' && calculatedRouteCounties.length > 0) {
        const idxA = calculatedRouteCounties.indexOf(a.location.county);
        const idxB = calculatedRouteCounties.indexOf(b.location.county);
        if (idxA !== idxB) return idxA - idxB;
      }

      // 3. DATE: Newest
      return b.createdAt - a.createdAt;
    });
  }, [ads, searchTerm, selectedCategory, searchMode, filterCounty, filterCity, filterVillage, routeStartCounty, routeEndCounty, calculatedRouteCounties, showFavoritesOnly, favoriteIds]);

  const currentAds = processedAds.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage);

  const heroSlides: Slide[] = [
    {
      id: '1',
      image: 'https://images.unsplash.com/photo-1488459716781-31db52582fe9?auto=format&fit=crop&q=80&w=2000',
      title: 'Crește-ți Afacerea Locală',
      description: 'Promovează-ți produsele prin pachetele noastre Premium și atrage mai mulți clienți.',
      ctaText: 'Publică Anunț',
      onCtaClick: onOpenCreateModal,
    }
  ];

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
      <Carousel slides={heroSlides} />
      <CategoryNav selectedCategory={selectedCategory} onSelectCategory={setSelectedCategory} />

      <div id="listings" className="mb-6 flex flex-col md:flex-row justify-between items-center gap-4">
          <div className="flex items-center gap-4">
              <button onClick={() => setSearchMode('local')} className={`px-4 py-2 rounded-full text-xs font-black uppercase tracking-widest border-2 transition-all ${searchMode === 'local' ? 'bg-indigo-600 border-indigo-600 text-white' : 'bg-white border-gray-100 text-gray-400'}`}>Standard</button>
              <button onClick={() => setSearchMode('route')} className={`px-4 py-2 rounded-full text-xs font-black uppercase tracking-widest border-2 transition-all ${searchMode === 'route' ? 'bg-indigo-600 border-indigo-600 text-white' : 'bg-white border-gray-100 text-gray-400'}`}>La Drum</button>
          </div>
          <div className="relative w-full md:w-96">
              <input type="text" placeholder="Caută produse..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)} className="w-full bg-white border-2 border-gray-100 rounded-2xl py-3 px-12 focus:border-indigo-500 outline-none transition-all font-medium text-sm" />
              <svg className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
          </div>
      </div>

      {searchMode === 'local' ? (
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-8 bg-white p-6 rounded-3xl border border-gray-100 shadow-sm">
              <select value={filterCounty} onChange={e => setFilterCounty(e.target.value)} className="bg-gray-50 border-none rounded-xl p-3 outline-none text-sm font-bold">
                  <option value="">Toate Județele</option>
                  {getCounties().map(c => <option key={c} value={c}>{c}</option>)}
              </select>
              <select value={filterCity} onChange={e => setFilterCity(e.target.value)} disabled={!filterCounty} className="bg-gray-50 border-none rounded-xl p-3 outline-none text-sm font-bold disabled:opacity-50">
                  <option value="">Toate Localitățile</option>
                  {availableCities.map(c => <option key={c} value={c}>{c}</option>)}
              </select>
              <button onClick={() => setShowFavoritesOnly(!showFavoritesOnly)} className={`rounded-xl p-3 text-sm font-bold border-2 transition-all ${showFavoritesOnly ? 'bg-red-50 border-red-100 text-red-500' : 'bg-white border-gray-50 text-gray-400'}`}>
                  {showFavoritesOnly ? '★ Favorite' : '☆ Toate'}
              </button>
          </div>
      ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-8 bg-indigo-50 p-6 rounded-3xl border border-indigo-100 shadow-sm">
               <select value={routeStartCounty} onChange={e => setRouteStartCounty(e.target.value)} className="bg-white border-none rounded-xl p-3 outline-none text-sm font-bold"><option value="">Plecare</option>{getCounties().map(c => <option key={c} value={c}>{c}</option>)}</select>
               <select value={routeEndCounty} onChange={e => setRouteEndCounty(e.target.value)} className="bg-white border-none rounded-xl p-3 outline-none text-sm font-bold"><option value="">Destinație</option>{getCounties().map(c => <option key={c} value={c}>{c}</option>)}</select>
          </div>
      )}

      {loading ? (
        <div className="grid grid-cols-1 md:grid-cols-4 gap-6 animate-pulse">
          {[...Array(8)].map((_, i) => <div key={i} className="bg-white h-80 rounded-3xl border-2 border-gray-50"></div>)}
        </div>
      ) : (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
          {currentAds.map(ad => (
            <AdCard key={ad.id} ad={ad} onClick={() => onAdClick(ad)} isFavorite={favoriteIds.includes(ad.id)} onToggleFavorite={() => onToggleFavorite(ad.id)} />
          ))}
        </div>
      )}
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { verifyManageToken, updateAd, deleteAd } from '../services/mockBackend';
import { Ad, AdStatus, PRODUCT_CATEGORIES } from '../types';
import { Button } from '../components/Button';
import { getCounties, getCities, getVillages } from '../data/locations';

interface ManageAdProps {
  id: string;
  token: string;
  onNavigate: (path: string) => void;
}

export const ManageAd: React.FC<ManageAdProps> = ({ id, token, onNavigate }) => {
  const [ad, setAd] = useState<Ad | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  const [isEditing, setIsEditing] = useState(false);
  const [editTitle, setEditTitle] = useState('');
  const [editDesc, setEditDesc] = useState('');
  const [editPrice, setEditPrice] = useState('');
  const [editPhone, setEditPhone] = useState('');
  const [editCategories, setEditCategories] = useState<string[]>([]);

  const [editCounty, setEditCounty] = useState('');
  const [editCity, setEditCity] = useState('');
  const [editVillage, setEditVillage] = useState('');
  const [availableCities, setAvailableCities] = useState<string[]>([]);
  const [availableVillages, setAvailableVillages] = useState<string[]>([]);

  const [saving, setSaving] = useState(false);
  const [showConfirmDelete, setShowConfirmDelete] = useState(false);

  useEffect(() => {
    const checkToken = async () => {
      try {
        const data = await verifyManageToken(id, token);
        if (data) {
          setAd(data);
          setEditTitle(data.title);
          setEditDesc(data.description);
          setEditPrice(String(data.price));
          setEditPhone(data.phoneNumber);
          setEditCategories(data.categories);
          setEditCounty(data.location.county);
          setEditCity(data.location.city);
          setEditVillage(data.location.village || '');
        } else {
          setError('Invalid or expired management link.');
        }
      } catch (err) { setError('System error.'); } 
      finally { setLoading(false); }
    };
    checkToken();
  }, [id, token]);

  useEffect(() => {
    if (editCounty) setAvailableCities(getCities(editCounty));
  }, [editCounty]);

  const handleSave = async () => {
    setSaving(true);
    const updates: Partial<Ad> = {
      title: editTitle,
      description: editDesc,
      price: Number(editPrice),
      phoneNumber: editPhone,
      categories: editCategories,
      location: { county: editCounty, city: editCity, village: editVillage || undefined }
    };
    const success = await updateAd(id, token, updates);
    if (success) {
      setAd(prev => prev ? ({ ...prev, ...updates }) : null);
      setIsEditing(false);
    }
    setSaving(false);
  };

  if (loading) return <div className="p-20 text-center font-bold">Se încarcă consola...</div>;
  if (error) return <div className="p-20 text-center text-red-500">{error}</div>;
  if (!ad) return null;

  return (
    <div className="max-w-5xl mx-auto px-4 py-12">
      <div className="flex justify-between items-center mb-10">
        <div>
          <h1 className="text-3xl font-black text-gray-900 tracking-tight">Consolă Vânzător</h1>
          <p className="text-sm text-gray-500 mt-1">Gestionează anunțul tău și vizualizează performanța.</p>
        </div>
        <div className={`px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest ${ad.status === AdStatus.ACTIVE ? 'bg-green-100 text-green-700' : 'bg-amber-100 text-amber-700'}`}>
          Status: {ad.status}
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Left: Stats & Info */}
        <div className="space-y-6">
          <div className="bg-white p-6 rounded-3xl border border-gray-100 shadow-sm">
            <h3 className="text-xs font-black text-gray-400 uppercase tracking-widest mb-4">Statistici Anunț</h3>
            <div className="grid grid-cols-2 gap-4">
              <div className="bg-indigo-50 p-4 rounded-2xl">
                <p className="text-2xl font-black text-indigo-700">{ad.stats?.views || 128}</p>
                <p className="text-[10px] font-bold text-indigo-400 uppercase">Vizualizări</p>
              </div>
              <div className="bg-green-50 p-4 rounded-2xl">
                <p className="text-2xl font-black text-green-700">{ad.stats?.whatsappClicks || 12}</p>
                <p className="text-[10px] font-bold text-green-400 uppercase">Contactări</p>
              </div>
            </div>
            {!ad.isPremium && (
               <div className="mt-6 p-4 bg-amber-50 rounded-2xl border border-amber-100">
                  <p className="text-xs font-bold text-amber-800">Vrei de 5x mai multe vizualizări?</p>
                  <p className="text-[10px] text-amber-600 mt-1">Treci la planul Premium pentru prioritate în listă.</p>
                  <button className="w-full mt-3 bg-amber-500 text-white text-[10px] font-black py-2 rounded-xl uppercase tracking-widest hover:bg-amber-600">Upgrade Now</button>
               </div>
            )}
          </div>

          <div className="bg-white p-6 rounded-3xl border border-gray-100 shadow-sm">
            <h3 className="text-xs font-black text-gray-400 uppercase tracking-widest mb-4">Previzualizare</h3>
            <div className="aspect-video rounded-2xl overflow-hidden bg-gray-100 border border-gray-100">
                <img src={ad.images[0] || 'https://via.placeholder.com/400x300'} className="w-full h-full object-cover" alt="Ad Preview" />
            </div>
          </div>
        </div>

        {/* Right: Management Form */}
        <div className="lg:col-span-2 space-y-6">
          <div className="bg-white p-8 rounded-3xl border border-gray-100 shadow-sm">
            <div className="flex justify-between items-center mb-8 pb-4 border-b border-gray-50">
               <h3 className="text-lg font-black text-gray-900 uppercase tracking-tight">Setări Anunț</h3>
               <div className="flex gap-2">
                 {isEditing ? (
                   <>
                     <Button variant="outline" onClick={() => setIsEditing(false)}>Anulează</Button>
                     <Button onClick={handleSave} isLoading={saving}>Salvează</Button>
                   </>
                 ) : (
                   <Button onClick={() => setIsEditing(true)}>Editează Informații</Button>
                 )}
               </div>
            </div>

            {isEditing ? (
              <div className="space-y-6">
                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">Titlu</label>
                    <input type="text" value={editTitle} onChange={e => setEditTitle(e.target.value)} className="w-full bg-gray-50 border-none rounded-xl p-3 outline-none font-bold" />
                  </div>
                  <div>
                    <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">Preț (RON)</label>
                    <input type="number" value={editPrice} onChange={e => setEditPrice(e.target.value)} className="w-full bg-gray-50 border-none rounded-xl p-3 outline-none font-bold" />
                  </div>
                </div>
                <div>
                  <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">Descriere</label>
                  <textarea rows={6} value={editDesc} onChange={e => setEditDesc(e.target.value)} className="w-full bg-gray-50 border-none rounded-xl p-3 outline-none font-medium text-sm leading-relaxed" />
                </div>
              </div>
            ) : (
              <div className="space-y-6 opacity-80 pointer-events-none">
                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Titlu</p>
                    <p className="font-black text-gray-900">{ad.title}</p>
                  </div>
                  <div>
                    <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Preț</p>
                    <p className="font-black text-green-600">{ad.price} RON</p>
                  </div>
                </div>
                <div>
                  <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Descriere</p>
                  <p className="text-sm font-medium text-gray-600 leading-relaxed">{ad.description}</p>
                </div>
              </div>
            )}
          </div>

          <div className="bg-red-50 p-8 rounded-3xl border border-red-100">
             <h3 className="text-lg font-black text-red-900 mb-2">Zonă Periculoasă</h3>
             <p className="text-sm text-red-600 mb-6">Ștergerea anunțului este permanentă și nu poate fi anulată.</p>
             {showConfirmDelete ? (
                <div className="flex gap-3">
                   <Button variant="danger" onClick={async () => { await deleteAd(id, token); onNavigate('/'); }}>Confirm Ștergere</Button>
                   <Button variant="outline" onClick={() => setShowConfirmDelete(false)}>M-am răzgândit</Button>
                </div>
             ) : (
                <Button variant="danger" onClick={() => setShowConfirmDelete(true)}>Șterge Anunțul</Button>
             )}
          </div>
        </div>
      </div>
    </div>
  );
};

import { Ad, AdStatus, CreateAdPayload, Review, AlertSubscription, AppNotification } from '../types';
import { getCounties, getCities, getVillages } from '../data/locations';
import { supabase } from './supabaseClient';

const USE_SUPABASE = !!supabase;
const BACKEND_URL = process.env.BACKEND_API_URL || ''; 

const delay = (ms: number) => new Promise((resolve) => setTimeout(resolve, ms));

const generateId = (): string => {
  if (typeof crypto !== 'undefined' && crypto.randomUUID) return crypto.randomUUID();
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
    var r = Math.random() * 16 | 0, v = c == 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
};

const ADS_KEY = 'miculproducator_ads_v8';

const mapAdFromDB = (row: any): Ad => ({
    ...row,
    createdAt: new Date(row.created_at).getTime(),
    expiresAt: row.expires_at ? new Date(row.expires_at).getTime() : null,
    reviews: Array.isArray(row.reviews) ? row.reviews : [],
    price: Number(row.price),
    rating: Number(row.rating),
    phoneNumber: row.phone_number,
    isPremium: row.is_premium || false,
    stats: row.stats || { views: Math.floor(Math.random() * 200), whatsappClicks: Math.floor(Math.random() * 15), favorites: 0 }
});

/**
 * STRIPE CHECKOUT INITIATION
 */
export const startPaymentSession = async (adId: string, planId: string, email: string) => {
  if (!supabase) {
    console.warn("Supabase not initialized. Simulation mode.");
    return { url: null };
  }

  try {
    const { data, error } = await supabase.functions.invoke('create-stripe-session', {
      body: { 
        adId, 
        planId, 
        customerEmail: email, 
        successUrl: `${window.location.origin}/#/payment-success?adId=${adId}`,
        cancelUrl: `${window.location.origin}/#/create-ad?status=cancelled`
      }
    });

    if (error) throw error;
    return data; 
  } catch (err) {
    console.error("Failed to call edge function:", err);
    return { url: null };
  }
};

export const verifyPaymentSession = async (adId: string): Promise<{ success: boolean; ad?: Ad }> => {
  if (USE_SUPABASE) {
    const { data, error } = await supabase!.from('ads').select('*').eq('id', adId).single();
    if (!error && data.status === 'active') {
      return { success: true, ad: mapAdFromDB(data) };
    }
    return { success: false };
  }

  const adsRaw = localStorage.getItem(ADS_KEY);
  const ads = adsRaw ? JSON.parse(adsRaw) : [];
  const ad = ads.find((a: any) => a.id === adId);
  return { success: !!ad, ad };
};

export const fetchActiveAds = async (): Promise<Ad[]> => {
  if (USE_SUPABASE) {
    const { data, error } = await supabase!.from('ads').select('*').eq('status', 'active').order('created_at', { ascending: false });
    if (!error) return data.map(mapAdFromDB);
  }
  const adsRaw = localStorage.getItem(ADS_KEY);
  const ads = adsRaw ? JSON.parse(adsRaw) : [];
  return ads.filter((a: any) => a.status === AdStatus.ACTIVE).sort((a: any, b: any) => b.createdAt - a.createdAt);
};

export const fetchAdById = async (id: string): Promise<Ad | null> => {
  if (USE_SUPABASE) {
    const { data, error } = await supabase!.from('ads').select('*').eq('id', id).single();
    if (!error) return mapAdFromDB(data);
  }
  const adsRaw = localStorage.getItem(ADS_KEY);
  const ads = adsRaw ? JSON.parse(adsRaw) : [];
  return ads.find((a: any) => String(a.id) === String(id)) || null;
};

export const createAd = async (payload: CreateAdPayload): Promise<{ adId: string; token: string }> => {
  const token = generateId().replace(/-/g, '');
  const initialStatus = AdStatus.PENDING;

  if (USE_SUPABASE) {
    const { data, error } = await supabase!.from('ads').insert({
      title: payload.title,
      description: payload.description,
      price: payload.price,
      categories: payload.categories,
      email: payload.email,
      phone_number: payload.phoneNumber,
      location: payload.location,
      images: [], 
      token,
      status: initialStatus,
      is_premium: false // Default
    }).select().single();
    if (!error) return { adId: data.id, token };
    throw error;
  }

  const newAd: Ad = {
    id: generateId(),
    ...payload,
    images: ['https://via.placeholder.com/400x300?text=Produs+Local'],
    token,
    status: initialStatus,
    createdAt: Date.now(),
    expiresAt: Date.now() + (28 * 24 * 60 * 60 * 1000),
    reviews: [],
    rating: 0,
    isPremium: false,
    stats: { views: 0, whatsappClicks: 0, favorites: 0 }
  };
  const adsRaw = localStorage.getItem(ADS_KEY);
  const ads = adsRaw ? JSON.parse(adsRaw) : [];
  localStorage.setItem(ADS_KEY, JSON.stringify([...ads, newAd]));
  return { adId: newAd.id, token };
};

export const simulatePaymentSuccess = async (adId: string): Promise<void> => {
  await delay(300);
  if (USE_SUPABASE) {
    await supabase!.from('ads').update({ status: 'active', is_premium: true, expires_at: new Date(Date.now() + 28*86400000).toISOString() }).eq('id', adId);
  } else {
    const adsRaw = localStorage.getItem(ADS_KEY);
    const ads = adsRaw ? JSON.parse(adsRaw) : [];
    localStorage.setItem(ADS_KEY, JSON.stringify(ads.map((a: any) => a.id === adId ? { ...a, status: 'active', isPremium: true } : a)));
  }
};

export const verifyManageToken = async (id: string, token: string): Promise<Ad | null> => {
  if (USE_SUPABASE) {
    const { data } = await supabase!.from('ads').select('*').eq('id', id).eq('token', token).single();
    if (data) return mapAdFromDB(data);
  }
  const adsRaw = localStorage.getItem(ADS_KEY);
  const ads = adsRaw ? JSON.parse(adsRaw) : [];
  const ad = ads.find((a: any) => String(a.id) === String(id));
  return ad?.token === token ? mapAdFromDB(ad) : null;
};

export const updateAd = async (id: string, token: string, updates: Partial<Ad>): Promise<boolean> => {
  const isAdminBypass = token === 'admin_override';
  if (USE_SUPABASE) {
    const dbUpdates: any = { ...updates };
    if (updates.phoneNumber) dbUpdates.phone_number = updates.phoneNumber;
    if (updates.location) dbUpdates.location = updates.location;
    let query = supabase!.from('ads').update(dbUpdates).eq('id', id);
    if (!isAdminBypass) query = query.eq('token', token);
    const { error } = await query;
    return !error;
  }
  const adsRaw = localStorage.getItem(ADS_KEY);
  const ads = adsRaw ? JSON.parse(adsRaw) : [];
  const idx = ads.findIndex((a: any) => String(a.id) === String(id) && (isAdminBypass || a.token === token));
  if (idx === -1) return false;
  ads[idx] = { ...ads[idx], ...updates };
  localStorage.setItem(ADS_KEY, JSON.stringify(ads));
  return true;
};

export const deleteAd = async (id: string, token: string): Promise<boolean> => {
  const isAdminBypass = token === 'admin_override';
  const targetId = String(id).trim().toLowerCase();
  if (USE_SUPABASE) {
    let query = supabase!.from('ads').delete().eq('id', id);
    if (!isAdminBypass) query = query.eq('token', token);
    const { error } = await query;
    return !error;
  }
  const adsRaw = localStorage.getItem(ADS_KEY);
  if (!adsRaw) return false;
  const ads = JSON.parse(adsRaw);
  const remainingAds = ads.filter((a: any) => !(String(a.id).trim().toLowerCase() === targetId && (isAdminBypass || a.token === token)));
  if (remainingAds.length < ads.length) {
    localStorage.setItem(ADS_KEY, JSON.stringify(remainingAds));
    return true;
  }
  return false;
};

export const getAllAds = async (): Promise<Ad[]> => {
    if (USE_SUPABASE) {
        const { data, error } = await supabase!.from('ads').select('*').order('created_at', { ascending: false });
        if (!error) return data.map(mapAdFromDB);
    }
    const adsRaw = localStorage.getItem(ADS_KEY);
    const ads = adsRaw ? JSON.parse(adsRaw) : [];
    return ads.sort((a: any, b: any) => b.createdAt - a.createdAt);
};

export const adminDeleteAd = async (id: string): Promise<boolean> => deleteAd(id, 'admin_override');
export const adminUpdateAd = async (id: string, updates: Partial<Ad>): Promise<boolean> => updateAd(id, 'admin_override', updates);

export const addReview = async (adId: string, review: any): Promise<Review> => {
  const newReview = { ...review, id: generateId(), createdAt: Date.now() };
  if (USE_SUPABASE) {
    const { data } = await supabase!.from('ads').select('reviews').eq('id', adId).single();
    const reviews = [...(data?.reviews || []), newReview];
    const rating = reviews.reduce((s, r) => s + r.rating, 0) / reviews.length;
    await supabase!.from('ads').update({ reviews, rating }).eq('id', adId);
    return newReview;
  }
  const adsRaw = localStorage.getItem(ADS_KEY);
  const ads = adsRaw ? JSON.parse(adsRaw) : [];
  const idx = ads.findIndex((a: any) => a.id === adId);
  if (idx !== -1) {
    ads[idx].reviews = [...(ads[idx].reviews || []), newReview];
    ads[idx].rating = ads[idx].reviews.reduce((s: any, r: any) => s + r.rating, 0) / ads[idx].reviews.length;
    localStorage.setItem(ADS_KEY, JSON.stringify(ads));
  }
  return newReview;
};

