      is_premium: false 
    }).select().single();
    if (!error) return { adId: data.id, token };
    throw error;
  }

  // LocalStorage Fallback
  const newAd: Ad = {
    id: generateId(),
    ...payload,
    // Use first preview for mock if available, or placeholder
    images: payload.images.length > 0 
      ? ['https://images.unsplash.com/photo-1542838132-92c53300491e?auto=format&fit=crop&q=80&w=400'] 
      : ['https://via.placeholder.com/400x300?text=Produs+Local'],
    token,
    status: initialStatus,
    createdAt: Date.now(),
    expiresAt: Date.now() + (28 * 24 * 60 * 60 * 1000),
    reviews: [],
    rating: 0,
    isPremium: false,
    stats: { views: 0, whatsappClicks: 0, favorites: 0 }
  };
  const adsRaw = localStorage.getItem(ADS_KEY);
  const ads = adsRaw ? JSON.parse(adsRaw) : [];
  localStorage.setItem(ADS_KEY, JSON.stringify([...ads, newAd]));
  return { adId: newAd.id, token };
};

export const simulatePaymentSuccess = async (adId: string): Promise<void> => {
  await delay(300);
  if (USE_SUPABASE) {
    await supabase!.from('ads').update({ status: 'active', is_premium: true, expires_at: new Date(Date.now() + 28*86400000).toISOString() }).eq('id', adId);
  } else {
    const adsRaw = localStorage.getItem(ADS_KEY);
    const ads = adsRaw ? JSON.parse(adsRaw) : [];
    localStorage.setItem(ADS_KEY, JSON.stringify(ads.map((a: any) => a.id === adId ? { ...a, status: 'active', isPremium: true } : a)));
  }
};

export const verifyManageToken = async (id: string, token: string): Promise<Ad | null> => {
  if (USE_SUPABASE) {
    const { data } = await supabase!.from('ads').select('*').eq('id', id).eq('token', token).single();
    if (data) return mapAdFromDB(data);
  }
  const adsRaw = localStorage.getItem(ADS_KEY);
  const ads = adsRaw ? JSON.parse(adsRaw) : [];
  const ad = ads.find((a: any) => String(a.id) === String(id));
  return ad?.token === token ? mapAdFromDB(ad) : null;
};

export const updateAd = async (id: string, token: string, updates: Partial<Ad>): Promise<boolean> => {
  const isAdminBypass = token === 'admin_override';
  if (USE_SUPABASE) {
    const dbUpdates: any = { ...updates };
    if (updates.phoneNumber) dbUpdates.phone_number = updates.phoneNumber;
    if (updates.location) dbUpdates.location = updates.location;
    let query = supabase!.from('ads').update(dbUpdates).eq('id', id);
    if (!isAdminBypass) query = query.eq('token', token);
    const { error } = await query;
    return !error;
  }
  const adsRaw = localStorage.getItem(ADS_KEY);
  const ads = adsRaw ? JSON.parse(adsRaw) : [];
  const idx = ads.findIndex((a: any) => String(a.id) === String(id) && (isAdminBypass || a.token === token));
  if (idx === -1) return false;
  ads[idx] = { ...ads[idx], ...updates };
  localStorage.setItem(ADS_KEY, JSON.stringify(ads));
  return true;
};

export const deleteAd = async (id: string, token: string): Promise<boolean> => {
  const isAdminBypass = token === 'admin_override';
  const targetId = String(id).trim().toLowerCase();
  if (USE_SUPABASE) {
    let query = supabase!.from('ads').delete().eq('id', id);
    if (!isAdminBypass) query = query.eq('token', token);
    const { error } = await query;
    return !error;
  }
  const adsRaw = localStorage.getItem(ADS_KEY);
  if (!adsRaw) return false;
  const ads = JSON.parse(adsRaw);
  const remainingAds = ads.filter((a: any) => !(String(a.id).trim().toLowerCase() === targetId && (isAdminBypass || a.token === token)));
  if (remainingAds.length < ads.length) {
    localStorage.setItem(ADS_KEY, JSON.stringify(remainingAds));
    return true;
  }
  return false;
};

export const getAllAds = async (): Promise<Ad[]> => {
    if (USE_SUPABASE) {
        const { data, error } = await supabase!.from('ads').select('*').order('created_at', { ascending: false });
        if (!error) return data.map(mapAdFromDB);
    }
    const adsRaw = localStorage.getItem(ADS_KEY);
    const ads = adsRaw ? JSON.parse(adsRaw) : [];
    return ads.sort((a: any, b: any) => b.createdAt - a.createdAt);
};

export const adminDeleteAd = async (id: string): Promise<boolean> => deleteAd(id, 'admin_override');
export const adminUpdateAd = async (id: string, updates: Partial<Ad>): Promise<boolean> => updateAd(id, 'admin_override', updates);

export const addReview = async (adId: string, review: any): Promise<Review> => {
  const newReview = { ...review, id: generateId(), createdAt: Date.now() };
  if (USE_SUPABASE) {
    const { data } = await supabase!.from('ads').select('reviews').eq('id', adId).single();
    const reviews = [...(data?.reviews || []), newReview];
    const rating = reviews.reduce((s, r) => s + r.rating, 0) / reviews.length;
    await supabase!.from('ads').update({ reviews, rating }).eq('id', adId);
    return newReview;
  }
  const adsRaw = localStorage.getItem(ADS_KEY);
  const ads = adsRaw ? JSON.parse(adsRaw) : [];
  const idx = ads.findIndex((a: any) => a.id === adId);
  if (idx !== -1) {
    ads[idx].reviews = [...(ads[idx].reviews || []), newReview];
    ads[idx].rating = ads[idx].reviews.reduce((s: any, r: any) => s + r.rating, 0) / ads[idx].reviews.length;
    localStorage.setItem(ADS_KEY, JSON.stringify(ads));
  }
  return newReview;
};

