                                          <div className={`w-10 h-10 rounded-full flex items-center justify-center font-black text-[10px] border-2 shadow-lg ${idx === 0 || idx === calculatedRouteCounties.length - 1 ? 'bg-white text-indigo-600 border-white' : 'bg-indigo-500 text-white border-indigo-400'}`}>
                                              {county.slice(0, 2).toUpperCase()}
                                          </div>
                                          <span className="mt-2 text-[10px] font-bold uppercase tracking-widest opacity-80">{county}</span>
                                      </div>
                                      {idx < calculatedRouteCounties.length - 1 && (
                                          <div className="w-12 h-px bg-white/20 flex-shrink-0 mb-6"></div>
                                      )}
                                  </React.Fragment>
                              ))}
                          </div>
                          <div className="mt-4 flex items-center justify-between">
                            <p className="text-[10px] font-black uppercase tracking-widest text-indigo-200">
                                Traseu detectat: {calculatedRouteCounties.length} Județe
                            </p>
                            <span className="bg-white/10 px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest animate-pulse">
                                {processedAds.length} Producători pe rută
                            </span>
                          </div>
                      </div>
                  )}
              </div>
          </div>
