                <svg className={`w-5 h-5 ${isFavorite ? 'text-red-500 fill-current' : 'text-gray-400'}`} xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M20.84 4.61a5.5 5.5 0 0 0-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 0 0-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 0 0 0-7.78z"></path></svg>
            </button>

            {showRouteContext && (
                <a
                    href={mapsLink}
                    target="_blank"
                    rel="noreferrer"
                    onClick={(e) => e.stopPropagation()}
                    className="p-3 rounded-2xl bg-indigo-600 text-white shadow-xl hover:bg-indigo-700 transition-all transform active:scale-90"
                    title="Navighează"
                >
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 11a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
                </a>
            )}
        </div>

        {/* Price Tag Overlay (only in local mode) */}
        {!showRouteContext && (
            <div className="absolute bottom-4 right-4 z-20">
                <span className="inline-flex items-center px-4 py-2 rounded-2xl text-sm font-black bg-green-600 text-white shadow-2xl tracking-tight">
                    {ad.price} RON
                </span>
            </div>
        )}
      </div>

      <div className="p-6 flex flex-col flex-grow">
        <div className="mb-3">
            <h3 className="text-xl font-black text-gray-900 line-clamp-1 group-hover:text-indigo-600 transition-colors uppercase tracking-tight">
                {ad.title}
            </h3>
            <div className="flex items-center text-[10px] font-black text-gray-400 uppercase tracking-widest mt-1.5 bg-gray-50 inline-flex px-2 py-1 rounded-md">
                <svg className="w-3 h-3 mr-1.5 text-indigo-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 11a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
                {ad.location.city}, {ad.location.county}
            </div>
        </div>

        <p className="text-sm text-gray-500 line-clamp-2 mb-6 leading-relaxed font-medium italic">
            "{ad.description}"
        </p>

        <div className="pt-5 border-t border-gray-100 flex items-center justify-between mt-auto">
            <div className="flex items-center gap-3">
                {showRating && (
                    <div className="flex items-center text-xs font-black text-amber-500 bg-amber-50 px-2.5 py-1 rounded-lg">
                        <span className="mr-1.5">{ad.rating.toFixed(1)}</span>
                        <svg className="w-3.5 h-3.5 fill-current" viewBox="0 0 20 20"><path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z"/></svg>
                    </div>
                )}

                {showRouteContext && (
                    <div className="text-[16px] font-black text-green-600 bg-green-50 px-3 py-1 rounded-xl">
                        {ad.price} <span className="text-[10px] text-green-700">RON</span>
                    </div>
                )}
            </div>

            <div className="flex flex-col items-end">
                <span className="text-[10px] font-black text-gray-300 uppercase tracking-tighter">
                    {new Date(ad.createdAt).toLocaleDateString('ro-RO')}
                </span>
            </div>
        </div>
      </div>
    </div>
  );
};

import React, { useEffect, useState, useMemo } from 'react';
import { AdCard } from '../components/AdCard';
import { Carousel, Slide } from '../components/Carousel';
import { CategoryNav } from '../components/CategoryNav';
import { fetchActiveAds } from '../services/mockBackend';
import { Ad, ToastType } from '../types';
import { getCounties, getCities } from '../data/locations';
import { getCountiesOnRoute } from '../utils/routeGraph';

interface HomeProps {
  onNavigate: (path: string) => void;
  onOpenCreateModal: () => void;
  onAdClick: (ad: Ad) => void;
  favoriteIds: string[];
  onToggleFavorite: (id: string) => void;
  onAddToast?: (type: ToastType, msg: string) => void;
}

export const Home: React.FC<HomeProps> = ({ 
  onNavigate, 
  onOpenCreateModal, 
  onAdClick,
  favoriteIds,
  onToggleFavorite,
  onAddToast
}) => {
  const [ads, setAds] = useState<Ad[]>([]);
  const [loading, setLoading] = useState(true);
  const [currentPage, setCurrentPage] = useState(1);
  const itemsPerPage = 12;

  const [searchMode, setSearchMode] = useState<'local' | 'route'>('local');
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCategory, setSelectedCategory] = useState('');
  const [showFavoritesOnly, setShowFavoritesOnly] = useState(false);

  const [filterCounty, setFilterCounty] = useState('');
  const [filterCity, setFilterCity] = useState('');

  const [availableCities, setAvailableCities] = useState<string[]>([]);

  const [routeStartCounty, setRouteStartCounty] = useState('');
  const [routeEndCounty, setRouteEndCounty] = useState('');
  const [calculatedRouteCounties, setCalculatedRouteCounties] = useState<string[]>([]);

  const loadAds = async () => {
    try {
      const data = await fetchActiveAds();
      setAds(data);
    } catch (err) { console.error(err); } 
    finally { setLoading(false); }
  };

  useEffect(() => {
    loadAds();
    window.addEventListener('miculproducator:ad_updated', loadAds);
    return () => window.removeEventListener('miculproducator:ad_updated', loadAds);
  }, []);

  useEffect(() => {
    if (filterCounty) {
      setAvailableCities(getCities(filterCounty));
      setFilterCity('');
    } else {
      setAvailableCities([]);
    }
  }, [filterCounty]);

  useEffect(() => {
    if (searchMode === 'route' && routeStartCounty && routeEndCounty) {
      const path = getCountiesOnRoute(routeStartCounty, routeEndCounty);
      setCalculatedRouteCounties(path);
    } else {
      setCalculatedRouteCounties([]);
    }
  }, [searchMode, routeStartCounty, routeEndCounty]);

  const processedAds = useMemo(() => {
    const filtered = ads.filter(ad => {
      const matchesSearch = ad.title.toLowerCase().includes(searchTerm.toLowerCase()) || ad.description.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesCategory = selectedCategory ? ad.categories.includes(selectedCategory) : true;
      let matchesLocation = true;

      if (searchMode === 'local') {
        const matchesCounty = filterCounty ? ad.location.county === filterCounty : true;
        const matchesCity = filterCity ? ad.location.city === filterCity : true;
        matchesLocation = matchesCounty && matchesCity;
      } else {
        if (routeStartCounty && routeEndCounty && calculatedRouteCounties.length > 0) {
          matchesLocation = calculatedRouteCounties.includes(ad.location.county);
        }
      }
      const matchesFavorite = showFavoritesOnly ? favoriteIds.includes(ad.id) : true;
      return matchesSearch && matchesCategory && matchesLocation && matchesFavorite;
    });

    return filtered.sort((a, b) => {
      if (a.isPremium && !b.isPremium) return -1;
      if (!a.isPremium && b.isPremium) return 1;

      if (searchMode === 'route' && calculatedRouteCounties.length > 0) {
        const idxA = calculatedRouteCounties.indexOf(a.location.county);
        const idxB = calculatedRouteCounties.indexOf(b.location.county);
        if (idxA !== idxB) return idxA - idxB;
      }

      return b.createdAt - a.createdAt;
    });
  }, [ads, searchTerm, selectedCategory, searchMode, filterCounty, filterCity, routeStartCounty, routeEndCounty, calculatedRouteCounties, showFavoritesOnly, favoriteIds]);

  const currentAds = processedAds.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage);

  const heroSlides: Slide[] = [
    {
      id: '1',
      image: 'https://images.unsplash.com/photo-1488459716781-31db52582fe9?auto=format&fit=crop&q=80&w=2000',
      title: 'Hrană Curată de la Oameni Gospodari',
      description: 'Conectăm producătorii locali din România direct cu masa ta. Descoperă gustul autentic.',
      ctaText: 'Publică Anunț',
      onCtaClick: onOpenCreateModal,
    }
  ];

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
      <Carousel slides={heroSlides} />
      <CategoryNav selectedCategory={selectedCategory} onSelectCategory={setSelectedCategory} />

      {/* SEARCH MODE SWITCHER */}
      <div id="listings" className="mb-8 flex flex-col md:flex-row justify-between items-end gap-6">
          <div className="w-full md:w-auto">
              <label className="block text-[10px] font-black text-gray-400 uppercase tracking-[0.2em] mb-3 ml-1">Mod de Explorare</label>
              <div className="inline-flex p-1.5 bg-gray-100 rounded-2xl shadow-inner border border-gray-200">
                  <button 
                    onClick={() => setSearchMode('local')} 
                    className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${searchMode === 'local' ? 'bg-white shadow-md text-indigo-600' : 'text-gray-400 hover:text-gray-600'}`}
                  >
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" /></svg>
                    Local
                  </button>
                  <button 
                    onClick={() => setSearchMode('route')} 
                    className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${searchMode === 'route' ? 'bg-white shadow-md text-indigo-600' : 'text-gray-400 hover:text-gray-600'}`}
                  >
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 5l7 7-7 7M5 5l7 7-7 7" /></svg>
                    La Drum
                  </button>
              </div>
          </div>

          <div className="relative w-full md:w-96 group">
              <input 
                type="text" 
                placeholder="Caută produse, producători..." 
                value={searchTerm} 
                onChange={e => setSearchTerm(e.target.value)} 
                className="w-full bg-white border-2 border-gray-100 rounded-2xl py-4 px-12 focus:border-indigo-500 shadow-sm outline-none transition-all font-bold text-sm placeholder:text-gray-300 placeholder:font-medium" 
              />
              <svg className="absolute left-4 top-1/2 -translate-y-1/2 w-6 h-6 text-gray-300 group-focus-within:text-indigo-500 transition-colors" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
          </div>
      </div>

      {/* FILTER AREA */}
      {searchMode === 'local' ? (
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-10 bg-white p-4 rounded-[2rem] border border-gray-100 shadow-xl shadow-gray-100">
              <div className="relative">
                <select value={filterCounty} onChange={e => setFilterCounty(e.target.value)} className="w-full bg-gray-50 border-none rounded-2xl p-4 outline-none text-sm font-black text-gray-700 appearance-none">
                    <option value="">Toate Județele</option>
                    {getCounties().map(c => <option key={c} value={c}>{c}</option>)}
                </select>
                <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-gray-400">
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" /></svg>
                </div>
              </div>

              <div className="relative">
                <select value={filterCity} onChange={e => setFilterCity(e.target.value)} disabled={!filterCounty} className="w-full bg-gray-50 border-none rounded-2xl p-4 outline-none text-sm font-black text-gray-700 appearance-none disabled:opacity-40">
                    <option value="">Toate Localitățile</option>
                    {availableCities.map(c => <option key={c} value={c}>{c}</option>)}
                </select>
                <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-gray-400">
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" /></svg>
                </div>
              </div>

              <button 
                onClick={() => setShowFavoritesOnly(!showFavoritesOnly)} 
                className={`flex items-center justify-center gap-2 rounded-2xl p-4 text-xs font-black uppercase tracking-widest border-2 transition-all ${showFavoritesOnly ? 'bg-red-50 border-red-200 text-red-600 shadow-inner shadow-red-100' : 'bg-white border-gray-100 text-gray-400 hover:border-gray-200'}`}
              >
                  {showFavoritesOnly ? (
                    <><svg className="w-4 h-4 fill-current" viewBox="0 0 20 20"><path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z"/></svg> Favorite</>
                  ) : (
                    <><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11.049 2.927c.3-.921 1.603-.921 1.902 0l1.519 4.674a1 1 0 00.95.69h4.915c.969 0 1.371 1.24.588 1.81l-3.976 2.888a1 1 0 00-.363 1.118l1.518 4.674c.3.922-.755 1.688-1.538 1.118l-3.976-2.888a1 1 0 00-1.176 0l-3.976 2.888c-.783.57-1.838-.197-1.538-1.118l1.518-4.674a1 1 0 00-.363-1.118l-3.976-2.888c-.784-.57-.38-1.81.588-1.81h4.914a1 1 0 00.951-.69l1.519-4.674z" /></svg> Toate</>
                  )}
              </button>
          </div>
      ) : (
          <div className="mb-10 animate-fade-in">
              <div className="bg-indigo-600 p-8 md:p-12 rounded-[2.5rem] shadow-2xl shadow-indigo-200 text-white relative overflow-hidden">
                  {/* Background decoration */}
                  <div className="absolute top-0 right-0 w-96 h-96 bg-white/5 rounded-full -mr-32 -mt-32 blur-[100px]"></div>
                  <div className="absolute bottom-0 left-0 w-64 h-64 bg-indigo-400/10 rounded-full -ml-20 -mb-20 blur-[80px]"></div>

                  <div className="relative z-10 flex flex-col md:flex-row items-center gap-12">
                      <div className="flex-1 space-y-6">
                          <div>
                            <span className="inline-block px-3 py-1 bg-white/10 rounded-full text-[10px] font-black uppercase tracking-widest mb-4 border border-white/10">Premium Feature</span>
                            <h3 className="text-3xl md:text-4xl font-black tracking-tight leading-none">Călătorește cu Gust</h3>
                          </div>
                          <p className="text-indigo-100 text-base font-medium leading-relaxed max-w-sm">
                              Planificăm ruta ta prin România gospodară. Găsește cei mai buni producători locali direct în drumul tău spre destinație.
                          </p>
                          <div className="flex items-center gap-6 pt-2">
                             <div className="flex flex-col">
                               <span className="text-2xl font-black">{calculatedRouteCounties.length || '--'}</span>
                               <span className="text-[10px] font-black uppercase tracking-widest text-indigo-300">Județe traversate</span>
                             </div>
                             <div className="w-px h-8 bg-white/10"></div>
                             <div className="flex flex-col">
                               <span className="text-2xl font-black">{processedAds.length || '--'}</span>
                               <span className="text-[10px] font-black uppercase tracking-widest text-indigo-300">Puncte de interes</span>
                             </div>
                          </div>
                      </div>
                      <div className="flex-1 w-full bg-white/5 backdrop-blur-xl border border-white/10 rounded-3xl p-6 md:p-8 space-y-6">
                          <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                              <div className="space-y-2">
                                  <label className="block text-[10px] font-black uppercase tracking-widest text-indigo-200 ml-1">Plecare din</label>
                                  <select 
                                    value={routeStartCounty} 
                                    onChange={e => setRouteStartCounty(e.target.value)} 
                                    className="w-full bg-white text-gray-900 rounded-2xl p-4 outline-none text-sm font-black border-none shadow-xl focus:ring-4 focus:ring-indigo-400/30 transition-all appearance-none"
                                  >
                                      <option value="">Alege Județ</option>
                                      {getCounties().map(c => <option key={c} value={c}>{c}</option>)}
                                  </select>
                              </div>
                              <div className="space-y-2">
                                  <label className="block text-[10px] font-black uppercase tracking-widest text-indigo-200 ml-1">Destinație</label>
                                  <select 
                                    value={routeEndCounty} 
                                    onChange={e => setRouteEndCounty(e.target.value)} 
                                    className="w-full bg-white text-gray-900 rounded-2xl p-4 outline-none text-sm font-black border-none shadow-xl focus:ring-4 focus:ring-indigo-400/30 transition-all appearance-none"
                                  >
                                      <option value="">Alege Județ</option>
                                      {getCounties().map(c => <option key={c} value={c}>{c}</option>)}
                                  </select>
                              </div>
                          </div>

                          {calculatedRouteCounties.length > 0 && (
                            <div className="bg-white/10 rounded-2xl p-4 flex items-center justify-between">
                                <span className="text-[11px] font-black uppercase tracking-widest text-indigo-100 flex items-center gap-2">
                                   <span className="w-2 h-2 bg-green-400 rounded-full animate-pulse"></span>
                                   Rută optimizată activă
                                </span>
                                <button 
                                  onClick={() => { setRouteStartCounty(''); setRouteEndCounty(''); }}
                                  className="text-[10px] font-black uppercase tracking-widest text-white/60 hover:text-white transition-colors"
                                >
                                  Resetează
                                </button>
                            </div>
                          )}
                      </div>
                  </div>

                  {calculatedRouteCounties.length > 0 && (
                      <div className="mt-12 pt-10 border-t border-white/10">
                          <div className="flex items-center gap-6 overflow-x-auto pb-6 scrollbar-hide">
                              {calculatedRouteCounties.map((county, idx) => (
                                  <React.Fragment key={county}>
                                      <div className="flex flex-col items-center flex-shrink-0 group">
                                          <div className={`w-14 h-14 rounded-2xl flex items-center justify-center font-black text-xs border-2 shadow-2xl transition-all group-hover:scale-110 ${
                                            idx === 0 || idx === calculatedRouteCounties.length - 1 
                                              ? 'bg-white text-indigo-600 border-white' 
                                              : 'bg-indigo-500/50 text-white border-white/20 backdrop-blur-md'
                                          }`}>
                                              {county.slice(0, 2).toUpperCase()}
                                          </div>
                                          <span className="mt-3 text-[10px] font-black uppercase tracking-widest opacity-60 group-hover:opacity-100 transition-opacity">{county}</span>
                                      </div>
                                      {idx < calculatedRouteCounties.length - 1 && (
                                          <div className="w-16 h-1 bg-white/10 flex-shrink-0 mb-8 rounded-full"></div>
                                      )}
                                  </React.Fragment>
                              ))}
                          </div>
                      </div>
                  )}
              </div>
          </div>
      )}

      {/* RESULTS GRID */}
      {loading ? (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-8 animate-pulse">
          {[...Array(8)].map((_, i) => (
            <div key={i} className="space-y-4">
              <div className="bg-gray-200 h-64 rounded-[2rem]"></div>
              <div className="h-4 bg-gray-200 rounded-full w-3/4"></div>
              <div className="h-3 bg-gray-200 rounded-full w-1/2"></div>
            </div>
          ))}
        </div>
      ) : (
        <>
          {processedAds.length === 0 ? (
            <div className="py-24 text-center">
              <div className="inline-flex items-center justify-center w-24 h-24 bg-gray-100 rounded-full mb-6">
                <svg className="w-12 h-12 text-gray-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" /></svg>
              </div>
              <h3 className="text-xl font-black text-gray-900 mb-2">Niciun rezultat găsit</h3>
              <p className="text-gray-500 max-w-sm mx-auto text-sm leading-relaxed">
                Încearcă să schimbi județul sau categoria pentru a găsi produsele dorite.
              </p>
            </div>
          ) : (
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-8">
              {currentAds.map(ad => (
                <AdCard 
                    key={ad.id} 
                    ad={ad} 
                    onClick={() => onAdClick(ad)} 
                    isFavorite={favoriteIds.includes(ad.id)} 
                    onToggleFavorite={() => onToggleFavorite(ad.id)}
                    showRouteContext={searchMode === 'route'}
                    routePosition={searchMode === 'route' ? calculatedRouteCounties.indexOf(ad.location.county) : undefined}
                />
              ))}
            </div>
          )}
        </>
      )}

      {/* PAGINATION */}
      {!loading && processedAds.length > itemsPerPage && (
        <div className="mt-16 flex justify-center gap-2">
            {[...Array(Math.ceil(processedAds.length / itemsPerPage))].map((_, i) => (
                <button 
                  key={i} 
                  onClick={() => { setCurrentPage(i + 1); window.scrollTo({ top: document.getElementById('listings')?.offsetTop || 0, behavior: 'smooth' }); }}
                  className={`w-10 h-10 rounded-xl font-black text-sm transition-all ${currentPage === i + 1 ? 'bg-indigo-600 text-white shadow-lg' : 'bg-white border border-gray-100 text-gray-400 hover:bg-gray-50'}`}
                >
                    {i + 1}
                </button>
            ))}
        </div>
      )}
    </div>
  );
};

import React, { useEffect, useState, useMemo } from 'react';
import { AdCard } from '../components/AdCard';
import { Carousel, Slide } from '../components/Carousel';
import { CategoryNav } from '../components/CategoryNav';
import { fetchActiveAds } from '../services/mockBackend';
import { Ad, ToastType } from '../types';
import { getCounties, getCities } from '../data/locations';
import { getCountiesOnRoute } from '../utils/routeGraph';

interface HomeProps {
  onNavigate: (path: string) => void;
  onOpenCreateModal: () => void;
  onAdClick: (ad: Ad) => void;
  favoriteIds: string[];
  onToggleFavorite: (id: string) => void;
  onAddToast?: (type: ToastType, msg: string) => void;
}

export const Home: React.FC<HomeProps> = ({ 
  onNavigate, 
  onOpenCreateModal, 
  onAdClick,
  favoriteIds,
  onToggleFavorite,
  onAddToast
}) => {
  const [ads, setAds] = useState<Ad[]>([]);
  const [loading, setLoading] = useState(true);
  const [currentPage, setCurrentPage] = useState(1);
  const itemsPerPage = 12;

  const [searchMode, setSearchMode] = useState<'local' | 'route'>('local');
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCategory, setSelectedCategory] = useState('');
  const [showFavoritesOnly, setShowFavoritesOnly] = useState(false);

  const [filterCounty, setFilterCounty] = useState('');
  const [filterCity, setFilterCity] = useState('');

  const [availableCities, setAvailableCities] = useState<string[]>([]);

  const [routeStartCounty, setRouteStartCounty] = useState('');
  const [routeEndCounty, setRouteEndCounty] = useState('');
  const [calculatedRouteCounties, setCalculatedRouteCounties] = useState<string[]>([]);

  const loadAds = async () => {
    try {
      const data = await fetchActiveAds();
      setAds(data);
    } catch (err) { console.error(err); } 
    finally { setLoading(false); }
  };

  useEffect(() => {
    loadAds();
    window.addEventListener('miculproducator:ad_updated', loadAds);
    return () => window.removeEventListener('miculproducator:ad_updated', loadAds);
  }, []);

  useEffect(() => {
    if (filterCounty) {
      setAvailableCities(getCities(filterCounty));
      setFilterCity('');
    } else {
      setAvailableCities([]);
    }
  }, [filterCounty]);

  useEffect(() => {
    if (searchMode === 'route' && routeStartCounty && routeEndCounty) {
      const path = getCountiesOnRoute(routeStartCounty, routeEndCounty);
      setCalculatedRouteCounties(path);
    } else {
      setCalculatedRouteCounties([]);
    }
  }, [searchMode, routeStartCounty, routeEndCounty]);

  const processedAds = useMemo(() => {
    const filtered = ads.filter(ad => {
      const matchesSearch = ad.title.toLowerCase().includes(searchTerm.toLowerCase()) || ad.description.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesCategory = selectedCategory ? ad.categories.includes(selectedCategory) : true;
      let matchesLocation = true;

      if (searchMode === 'local') {
        const matchesCounty = filterCounty ? ad.location.county === filterCounty : true;
        const matchesCity = filterCity ? ad.location.city === filterCity : true;
        matchesLocation = matchesCounty && matchesCity;
      } else {
        if (routeStartCounty && routeEndCounty && calculatedRouteCounties.length > 0) {
          matchesLocation = calculatedRouteCounties.includes(ad.location.county);
        }
      }
      const matchesFavorite = showFavoritesOnly ? favoriteIds.includes(ad.id) : true;
      return matchesSearch && matchesCategory && matchesLocation && matchesFavorite;
    });

    return filtered.sort((a, b) => {
      if (a.isPremium && !b.isPremium) return -1;
      if (!a.isPremium && b.isPremium) return 1;

      if (searchMode === 'route' && calculatedRouteCounties.length > 0) {
        const idxA = calculatedRouteCounties.indexOf(a.location.county);
        const idxB = calculatedRouteCounties.indexOf(b.location.county);
        if (idxA !== idxB) return idxA - idxB;
      }

      return b.createdAt - a.createdAt;
    });
  }, [ads, searchTerm, selectedCategory, searchMode, filterCounty, filterCity, routeStartCounty, routeEndCounty, calculatedRouteCounties, showFavoritesOnly, favoriteIds]);

  const currentAds = processedAds.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage);

  const heroSlides: Slide[] = [
    {
      id: '1',
      image: 'https://images.unsplash.com/photo-1488459716781-31db52582fe9?auto=format&fit=crop&q=80&w=2000',
      title: 'Hrană Curată de la Oameni Gospodari',
      description: 'Conectăm producătorii locali din România direct cu masa ta. Descoperă gustul autentic.',
      ctaText: 'Publică Anunț',
      onCtaClick: onOpenCreateModal,
    }
  ];

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
      <Carousel slides={heroSlides} />
      <CategoryNav selectedCategory={selectedCategory} onSelectCategory={setSelectedCategory} />

      {/* SEARCH MODE SWITCHER */}
      <div id="listings" className="mb-8 flex flex-col md:flex-row justify-between items-end gap-6">
          <div className="w-full md:w-auto">
              <label className="block text-[10px] font-black text-gray-400 uppercase tracking-[0.2em] mb-3 ml-1">Mod de Explorare</label>
              <div className="inline-flex p-1.5 bg-gray-100 rounded-2xl shadow-inner border border-gray-200">
                  <button 
                    onClick={() => setSearchMode('local')} 
                    className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${searchMode === 'local' ? 'bg-white shadow-md text-slate-900' : 'text-gray-400 hover:text-gray-600'}`}
                  >
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" /></svg>
                    Local
                  </button>
                  <button 
                    onClick={() => setSearchMode('route')} 
                    className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${searchMode === 'route' ? 'bg-white shadow-md text-emerald-600' : 'text-gray-400 hover:text-gray-600'}`}
                  >
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 5l7 7-7 7M5 5l7 7-7 7" /></svg>
                    La Drum
                  </button>
              </div>
          </div>

          <div className="relative w-full md:w-96 group">
              <input 
                type="text" 
                placeholder="Caută produse, producători..." 
                value={searchTerm} 
                onChange={e => setSearchTerm(e.target.value)} 
                className="w-full bg-white border-2 border-gray-100 rounded-2xl py-4 px-12 focus:border-slate-900 shadow-sm outline-none transition-all font-bold text-sm placeholder:text-gray-300 placeholder:font-medium" 
              />
              <svg className="absolute left-4 top-1/2 -translate-y-1/2 w-6 h-6 text-gray-300 group-focus-within:text-slate-900 transition-colors" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
          </div>
      </div>

      {/* FILTER AREA */}
      {searchMode === 'local' ? (
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-10 bg-white p-4 rounded-[2rem] border border-gray-100 shadow-xl shadow-gray-100">
              <div className="relative">
                <select value={filterCounty} onChange={e => setFilterCounty(e.target.value)} className="w-full bg-gray-50 border-none rounded-2xl p-4 outline-none text-sm font-black text-gray-700 appearance-none">
                    <option value="">Toate Județele</option>
                    {getCounties().map(c => <option key={c} value={c}>{c}</option>)}
                </select>
                <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-gray-400">
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" /></svg>
                </div>
              </div>

              <div className="relative">
                <select value={filterCity} onChange={e => setFilterCity(e.target.value)} disabled={!filterCounty} className="w-full bg-gray-50 border-none rounded-2xl p-4 outline-none text-sm font-black text-gray-700 appearance-none disabled:opacity-40">
                    <option value="">Toate Localitățile</option>
                    {availableCities.map(c => <option key={c} value={c}>{c}</option>)}
                </select>
                <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-gray-400">
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" /></svg>
                </div>
              </div>

              <button 
                onClick={() => setShowFavoritesOnly(!showFavoritesOnly)} 
                className={`flex items-center justify-center gap-2 rounded-2xl p-4 text-xs font-black uppercase tracking-widest border-2 transition-all ${showFavoritesOnly ? 'bg-red-50 border-red-200 text-red-600 shadow-inner shadow-red-100' : 'bg-white border-gray-100 text-gray-400 hover:border-gray-200'}`}
              >
                  {showFavoritesOnly ? (
                    <><svg className="w-4 h-4 fill-current" viewBox="0 0 20 20"><path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z"/></svg> Favorite</>
                  ) : (
                    <><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11.049 2.927c.3-.921 1.603-.921 1.902 0l1.519 4.674a1 1 0 00.95.69h4.915c.969 0 1.371 1.24.588 1.81l-3.976 2.888a1 1 0 00-.363 1.118l1.518 4.674c.3.922-.755 1.688-1.538 1.118l-3.976-2.888a1 1 0 00-1.176 0l-3.976 2.888c-.783.57-1.838-.197-1.538-1.118l1.518-4.674a1 1 0 00-.363-1.118l-3.976-2.888c-.784-.57-.38-1.81.588-1.81h4.914a1 1 0 00.951-.69l1.519-4.674z" /></svg> Toate</>
                  )}
              </button>
          </div>
      ) : (
          <div className="mb-10 animate-fade-in">
              <div className="bg-slate-900 p-8 md:p-12 rounded-[3rem] shadow-2xl shadow-slate-200 text-white relative overflow-hidden border border-slate-800">
                  {/* Background decoration - subtle gradients instead of bright colors */}
                  <div className="absolute top-0 right-0 w-96 h-96 bg-emerald-500/10 rounded-full -mr-32 -mt-32 blur-[100px]"></div>
                  <div className="absolute bottom-0 left-0 w-64 h-64 bg-slate-400/5 rounded-full -ml-20 -mb-20 blur-[80px]"></div>

                  <div className="relative z-10 flex flex-col md:flex-row items-center gap-12">
                      <div className="flex-1 space-y-6">
                          <div>
                            <span className="inline-block px-3 py-1 bg-emerald-500/10 text-emerald-400 rounded-full text-[10px] font-black uppercase tracking-widest mb-4 border border-emerald-500/20">Premium Feature</span>
                            <h3 className="text-3xl md:text-4xl font-black tracking-tight leading-none text-white">Călătorește cu Gust</h3>
                          </div>
                          <p className="text-slate-400 text-base font-medium leading-relaxed max-w-sm">
                              Planificăm ruta ta prin România gospodară. Găsește cei mai buni producători locali direct în drumul tău spre destinație.
                          </p>
                          <div className="flex items-center gap-6 pt-2">
                             <div className="flex flex-col">
                               <span className="text-2xl font-black text-white">{calculatedRouteCounties.length || '--'}</span>
                               <span className="text-[10px] font-black uppercase tracking-widest text-slate-500">Județe traversate</span>
                             </div>
                             <div className="w-px h-8 bg-slate-800"></div>
                             <div className="flex flex-col">
                               <span className="text-2xl font-black text-emerald-400">{processedAds.length || '--'}</span>
                               <span className="text-[10px] font-black uppercase tracking-widest text-slate-500">Producători pe rută</span>
                             </div>
                          </div>
                      </div>

                      <div className="flex-1 w-full bg-slate-800/30 backdrop-blur-xl border border-slate-700/50 rounded-[2.5rem] p-6 md:p-8 space-y-6">
                          <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                              <div className="space-y-2">
                                  <label className="block text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1">Plecare din</label>
                                  <div className="relative">
                                    <select 
                                      value={routeStartCounty} 
                                      onChange={e => setRouteStartCounty(e.target.value)} 
                                      className="w-full bg-slate-900/80 text-white rounded-2xl p-4 outline-none text-sm font-black border border-slate-700 shadow-xl focus:ring-4 focus:ring-emerald-500/10 transition-all appearance-none"
                                    >
                                        <option value="" className="text-white">Alege Județ</option>
                                        {getCounties().map(c => <option key={c} value={c} className="bg-slate-900">{c}</option>)}
                                    </select>
                                    <svg className="absolute right-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500 pointer-events-none" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" /></svg>
                                  </div>
                              </div>
                              <div className="space-y-2">
                                  <label className="block text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1">Destinație</label>
                                  <div className="relative">
                                    <select 
                                      value={routeEndCounty} 
                                      onChange={e => setRouteEndCounty(e.target.value)} 
                                      className="w-full bg-slate-900/80 text-white rounded-2xl p-4 outline-none text-sm font-black border border-slate-700 shadow-xl focus:ring-4 focus:ring-emerald-500/10 transition-all appearance-none"
                                    >
                                        <option value="" className="text-white">Alege Județ</option>
                                        {getCounties().map(c => <option key={c} value={c} className="bg-slate-900">{c}</option>)}
                                    </select>
                                    <svg className="absolute right-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500 pointer-events-none" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" /></svg>
                                  </div>
                              </div>
                          </div>

                          {calculatedRouteCounties.length > 0 && (
                            <div className="bg-emerald-500/5 rounded-2xl p-4 flex items-center justify-between border border-emerald-500/10">
                                <span className="text-[11px] font-black uppercase tracking-widest text-emerald-400 flex items-center gap-2">
                                   <span className="w-2 h-2 bg-emerald-400 rounded-full animate-pulse"></span>
                                   Rută detectată
                                </span>
                                <button 
                                  onClick={() => { setRouteStartCounty(''); setRouteEndCounty(''); }}
                                  className="text-[10px] font-black uppercase tracking-widest text-slate-400 hover:text-white transition-colors"
                                >
                                  Resetează
                                </button>
                            </div>
                          )}
                      </div>
                  </div>

                  {calculatedRouteCounties.length > 0 && (
                      <div className="mt-12 pt-10 border-t border-slate-800">
                          <div className="flex items-center gap-6 overflow-x-auto pb-6 scrollbar-hide">
                              {calculatedRouteCounties.map((county, idx) => (
                                  <React.Fragment key={county}>
                                      <div className="flex flex-col items-center flex-shrink-0 group">
                                          <div className={`w-14 h-14 rounded-2xl flex items-center justify-center font-black text-xs border-2 shadow-2xl transition-all group-hover:scale-110 ${
                                            idx === 0 || idx === calculatedRouteCounties.length - 1 
                                              ? 'bg-white text-slate-900 border-white' 
                                              : 'bg-slate-800 text-slate-300 border-slate-700 backdrop-blur-md'
                                          }`}>
                                              {county.slice(0, 2).toUpperCase()}
                                          </div>
                                          <span className="mt-3 text-[10px] font-black uppercase tracking-widest text-slate-500 group-hover:text-white transition-colors">{county}</span>
                                      </div>
                                      {idx < calculatedRouteCounties.length - 1 && (
                                          <div className="w-16 h-0.5 bg-slate-800 flex-shrink-0 mb-8 rounded-full"></div>
                                      )}
                                  </React.Fragment>
                              ))}
                          </div>
                      </div>
                  )}
              </div>
          </div>
      )}

      {/* RESULTS GRID */}
      {loading ? (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-8 animate-pulse">
          {[...Array(8)].map((_, i) => (
            <div key={i} className="space-y-4">
              <div className="bg-gray-200 h-64 rounded-[2rem]"></div>
              <div className="h-4 bg-gray-200 rounded-full w-3/4"></div>
              <div className="h-3 bg-gray-200 rounded-full w-1/2"></div>
            </div>
          ))}
        </div>
      ) : (
        <>
          {processedAds.length === 0 ? (
            <div className="py-24 text-center">
              <div className="inline-flex items-center justify-center w-24 h-24 bg-gray-100 rounded-full mb-6">
                <svg className="w-12 h-12 text-gray-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" /></svg>
              </div>
              <h3 className="text-xl font-black text-gray-900 mb-2">Niciun rezultat găsit</h3>
              <p className="text-gray-500 max-w-sm mx-auto text-sm leading-relaxed">
                Încearcă să schimbi județul sau categoria pentru a găsi produsele dorite.
              </p>
            </div>
          ) : (
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-8">
              {currentAds.map(ad => (
                <AdCard 
                    key={ad.id} 
                    ad={ad} 
                    onClick={() => onAdClick(ad)} 
                    isFavorite={favoriteIds.includes(ad.id)} 
                    onToggleFavorite={() => onToggleFavorite(ad.id)}
                    showRouteContext={searchMode === 'route'}
                    routePosition={searchMode === 'route' ? calculatedRouteCounties.indexOf(ad.location.county) : undefined}
                />
              ))}
            </div>
          )}
        </>
      )}

      {/* PAGINATION */}
      {!loading && processedAds.length > itemsPerPage && (
        <div className="mt-16 flex justify-center gap-2">
            {[...Array(Math.ceil(processedAds.length / itemsPerPage))].map((_, i) => (
                <button 
                  key={i} 
                  onClick={() => { setCurrentPage(i + 1); window.scrollTo({ top: document.getElementById('listings')?.offsetTop || 0, behavior: 'smooth' }); }}
                  className={`w-10 h-10 rounded-xl font-black text-sm transition-all ${currentPage === i + 1 ? 'bg-slate-900 text-white shadow-lg' : 'bg-white border border-gray-100 text-gray-400 hover:bg-gray-50'}`}
                >
                    {i + 1}
                </button>
            ))}
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { Ad } from '../types';

interface AdCardProps {
  ad: Ad;
  onClick: () => void;
  isFavorite: boolean;
  onToggleFavorite: (e: React.MouseEvent | React.KeyboardEvent) => void;
  mini?: boolean; 
  priority?: boolean;
  showRouteContext?: boolean;
  routePosition?: number;
}

export const AdCard: React.FC<AdCardProps> = ({ 
    ad, 
    onClick, 
    isFavorite, 
    onToggleFavorite, 
    mini = false, 
    showRouteContext = false,
    routePosition
}) => {
  const isBio = ad.title.toLowerCase().includes('bio') || ad.description.toLowerCase().includes('natural');
  const [imageLoaded, setImageLoaded] = useState(false);

  const primaryCategory = ad.categories[0] || 'Produs';
  const showRating = ad.rating > 0;

  // Mocked detour time for premium "La Drum" feel
  const mockDetourTime = Math.floor(Math.random() * 8) + 2; 

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' || e.key === ' ') {
      e.preventDefault();
      onClick();
    }
  };

  const mapsLink = `https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(`${ad.title} ${ad.location.city} ${ad.location.county} Romania`)}`;

  if (mini) {
    return (
      <div 
        onClick={onClick}
        className={`group bg-white rounded-2xl border shadow-sm overflow-hidden hover:shadow-md cursor-pointer flex flex-col h-full relative transition-all ${ad.isPremium ? 'border-amber-200' : 'border-gray-100'}`}
      >
        <div className="relative h-32 w-full bg-gray-100">
           {!imageLoaded && <div className="absolute inset-0 bg-gray-200 animate-pulse z-10" />}
           <img 
              src={ad.images[0] || 'https://via.placeholder.com/400x300?text=Fără+Imagine'} 
              alt=""
              className={`w-full h-full object-cover transition-all duration-500 group-hover:scale-110 ${imageLoaded ? 'opacity-100' : 'opacity-0'}`}
              onLoad={() => setImageLoaded(true)}
            />
           <div className="absolute bottom-1 right-1 z-20">
             <span className="px-2 py-0.5 rounded-lg text-xs font-black bg-green-600 text-white shadow-lg">
               {ad.price} RON
             </span>
           </div>
        </div>
        <div className="p-3">
          <h4 className="text-xs font-black text-gray-900 line-clamp-1 flex items-center gap-1 uppercase tracking-tight">
            {ad.title}
            {ad.isPremium && <span className="text-amber-500 text-[10px]">★</span>}
          </h4>
        </div>
      </div>
    );
  }

  return (
    <div 
      onClick={onClick}
      onKeyDown={handleKeyDown}
      role="button"
      tabIndex={0}
      className={`group bg-white rounded-[2rem] border-2 transition-all duration-500 cursor-pointer flex flex-col h-full relative ${
        ad.isPremium 
          ? 'border-amber-200 shadow-2xl shadow-amber-50 hover:border-amber-400' 
          : 'border-gray-50 shadow-xl shadow-gray-100 hover:border-slate-200 hover:-translate-y-2'
      }`}
    >
      <div className="relative h-64 w-full overflow-hidden bg-gray-100 rounded-t-[1.8rem]">
        {!imageLoaded && <div className="absolute inset-0 bg-gray-100 animate-pulse z-10" />}
        <img 
          src={ad.images[0] || 'https://via.placeholder.com/400x300?text=Fără+Imagine'} 
          alt=""
          className={`w-full h-full object-cover transform group-hover:scale-110 transition-all duration-700 ease-out ${imageLoaded ? 'opacity-100' : 'opacity-0'}`}
          onLoad={() => setImageLoaded(true)}
        />

        {/* Route Context Overlay - Premium Midnight Forest Styling */}
        {showRouteContext && typeof routePosition === 'number' && (
            <div className="absolute bottom-0 left-0 right-0 bg-gradient-to-t from-slate-900/90 via-slate-900/40 to-transparent p-4 pt-12 z-20">
                <div className="flex items-center justify-between">
                    <div className="flex items-center gap-2">
                        <div className="w-6 h-6 rounded-full bg-slate-800 text-emerald-400 flex items-center justify-center text-[10px] font-black border-2 border-emerald-500/30 shadow-lg">
                            {routePosition + 1}
                        </div>
                        <span className="text-[10px] font-black uppercase tracking-[0.1em] text-white">Oprire pe rută</span>
                    </div>
                    <div className="flex items-center gap-1.5 bg-slate-900/60 backdrop-blur-md px-2 py-1 rounded-lg border border-white/10">
