                <svg className={`w-5 h-5 ${isFavorite ? 'text-red-500 fill-current' : 'text-gray-400'}`} xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M20.84 4.61a5.5 5.5 0 0 0-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 0 0-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 0 0 0-7.78z"></path></svg>
            </button>

            {showRouteContext && (
                <a
                    href={mapsLink}
                    target="_blank"
                    rel="noreferrer"
                    onClick={(e) => e.stopPropagation()}
                    className="p-3 rounded-2xl bg-emerald-600 text-white shadow-xl hover:bg-emerald-700 transition-all transform active:scale-90"
                    title="Navighează"
                >
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 11a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
                </a>
            )}
        </div>

        {/* Price Tag Overlay (only in local mode) */}
        {!showRouteContext && (
            <div className="absolute bottom-4 right-4 z-20">
                <span className="inline-flex items-center px-4 py-2 rounded-2xl text-sm font-black bg-green-600 text-white shadow-2xl tracking-tight">
                    {ad.price} RON
                </span>
            </div>
        )}
      </div>

      <div className="p-6 flex flex-col flex-grow">
        <div className="mb-3">
            <h3 className="text-xl font-black text-gray-900 line-clamp-1 group-hover:text-emerald-600 transition-colors uppercase tracking-tight">
                {ad.title}
            </h3>
            <div className="flex items-center text-[10px] font-black text-gray-400 uppercase tracking-widest mt-1.5 bg-gray-50 inline-flex px-2 py-1 rounded-md">
                <svg className="w-3 h-3 mr-1.5 text-slate-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 11a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
                {ad.location.city}, {ad.location.county}
            </div>
        </div>

        <p className="text-sm text-gray-500 line-clamp-2 mb-6 leading-relaxed font-medium italic">
            "{ad.description}"
