        <div className="pt-5 border-t border-gray-100 flex items-center justify-between mt-auto">
            <div className="flex items-center gap-3">
                {showRating && (
                    <div className="flex items-center text-xs font-black text-amber-500 bg-amber-50 px-2.5 py-1 rounded-lg">
                        <span className="mr-1.5">{ad.rating.toFixed(1)}</span>
                        <svg className="w-3.5 h-3.5 fill-current" viewBox="0 0 20 20"><path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z"/></svg>
                    </div>
                )}

                {showRouteContext && (
                    <div className="text-[16px] font-black text-emerald-600 bg-emerald-50 px-3 py-1 rounded-xl">
                        {ad.price} <span className="text-[10px] text-emerald-700">RON</span>
                    </div>
                )}
            </div>

            <div className="flex flex-col items-end">
                <span className="text-[10px] font-black text-gray-300 uppercase tracking-tighter">
                    {new Date(ad.createdAt).toLocaleDateString('ro-RO')}
                </span>
            </div>
        </div>
      </div>
    </div>
  );
};

import React, { useEffect, useState, useMemo } from 'react';
import { AdCard } from '../components/AdCard';
import { Carousel, Slide } from '../components/Carousel';
import { CategoryNav } from '../components/CategoryNav';
import { fetchActiveAds } from '../services/mockBackend';
import { Ad, ToastType } from '../types';
import { getCounties, getCities } from '../data/locations';
import { getCountiesOnRoute } from '../utils/routeGraph';

interface HomeProps {
  onNavigate: (path: string) => void;
  onOpenCreateModal: () => void;
  onAdClick: (ad: Ad) => void;
  favoriteIds: string[];
  onToggleFavorite: (id: string) => void;
  onAddToast?: (type: ToastType, msg: string) => void;
}

export const Home: React.FC<HomeProps> = ({ 
  onNavigate, 
  onOpenCreateModal, 
  onAdClick,
  favoriteIds,
  onToggleFavorite,
  onAddToast
}) => {
  const [ads, setAds] = useState<Ad[]>([]);
  const [loading, setLoading] = useState(true);
  const [currentPage, setCurrentPage] = useState(1);
  const itemsPerPage = 12;

  const [searchMode, setSearchMode] = useState<'local' | 'route'>('local');
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCategory, setSelectedCategory] = useState('');
  const [showFavoritesOnly, setShowFavoritesOnly] = useState(false);

  const [filterCounty, setFilterCounty] = useState('');
  const [filterCity, setFilterCity] = useState('');

  const [availableCities, setAvailableCities] = useState<string[]>([]);

  const [routeStartCounty, setRouteStartCounty] = useState('');
  const [routeEndCounty, setRouteEndCounty] = useState('');
  const [calculatedRouteCounties, setCalculatedRouteCounties] = useState<string[]>([]);

  const loadAds = async () => {
    try {
      const data = await fetchActiveAds();
      setAds(data);
    } catch (err) { console.error(err); } 
    finally { setLoading(false); }
  };

  useEffect(() => {
    loadAds();
    window.addEventListener('miculproducator:ad_updated', loadAds);
    return () => window.removeEventListener('miculproducator:ad_updated', loadAds);
  }, []);

  useEffect(() => {
    if (filterCounty) {
      setAvailableCities(getCities(filterCounty));
      setFilterCity('');
    } else {
      setAvailableCities([]);
    }
  }, [filterCounty]);

  useEffect(() => {
    if (searchMode === 'route' && routeStartCounty && routeEndCounty) {
      const path = getCountiesOnRoute(routeStartCounty, routeEndCounty);
      setCalculatedRouteCounties(path);
    } else {
      setCalculatedRouteCounties([]);
    }
  }, [searchMode, routeStartCounty, routeEndCounty]);

  const processedAds = useMemo(() => {
    const filtered = ads.filter(ad => {
      const matchesSearch = ad.title.toLowerCase().includes(searchTerm.toLowerCase()) || ad.description.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesCategory = selectedCategory ? ad.categories.includes(selectedCategory) : true;
      let matchesLocation = true;

      if (searchMode === 'local') {
        const matchesCounty = filterCounty ? ad.location.county === filterCounty : true;
        const matchesCity = filterCity ? ad.location.city === filterCity : true;
        matchesLocation = matchesCounty && matchesCity;
      } else {
        if (routeStartCounty && routeEndCounty && calculatedRouteCounties.length > 0) {
          matchesLocation = calculatedRouteCounties.includes(ad.location.county);
        }
      }
      const matchesFavorite = showFavoritesOnly ? favoriteIds.includes(ad.id) : true;
      return matchesSearch && matchesCategory && matchesLocation && matchesFavorite;
    });

    return filtered.sort((a, b) => {
      if (a.isPremium && !b.isPremium) return -1;
      if (!a.isPremium && b.isPremium) return 1;

      if (searchMode === 'route' && calculatedRouteCounties.length > 0) {
        const idxA = calculatedRouteCounties.indexOf(a.location.county);
        const idxB = calculatedRouteCounties.indexOf(b.location.county);
        if (idxA !== idxB) return idxA - idxB;
      }

      return b.createdAt - a.createdAt;
    });
  }, [ads, searchTerm, selectedCategory, searchMode, filterCounty, filterCity, routeStartCounty, routeEndCounty, calculatedRouteCounties, showFavoritesOnly, favoriteIds]);

  const currentAds = processedAds.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage);

  const heroSlides: Slide[] = [
    {
      id: '1',
      image: 'https://images.unsplash.com/photo-1488459716781-31db52582fe9?auto=format&fit=crop&q=80&w=2000',
      title: 'Hrană Curată de la Oameni Gospodari',
      description: 'Conectăm producătorii locali din România direct cu masa ta. Descoperă gustul autentic.',
      ctaText: 'Publică Anunț',
      onCtaClick: onOpenCreateModal,
    }
  ];

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
      <Carousel slides={heroSlides} />
      <CategoryNav selectedCategory={selectedCategory} onSelectCategory={setSelectedCategory} />

      {/* SEARCH MODE SWITCHER */}
      <div id="listings" className="mb-8 flex flex-col md:flex-row justify-between items-end gap-6">
          <div className="w-full md:w-auto">
              <label className="block text-[10px] font-black text-zinc-400 uppercase tracking-[0.2em] mb-3 ml-1">Mod de Explorare</label>
              <div className="inline-flex p-1.5 bg-zinc-100 rounded-2xl shadow-inner border border-zinc-200">
                  <button 
                    onClick={() => setSearchMode('local')} 
                    className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${searchMode === 'local' ? 'bg-white shadow-md text-zinc-900' : 'text-zinc-400 hover:text-zinc-600'}`}
                  >
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" /></svg>
                    Local
                  </button>
                  <button 
                    onClick={() => setSearchMode('route')} 
                    className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${searchMode === 'route' ? 'bg-zinc-900 shadow-md text-amber-400' : 'text-zinc-400 hover:text-zinc-600'}`}
                  >
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 5l7 7-7 7M5 5l7 7-7 7" /></svg>
                    La Drum
                  </button>
              </div>
          </div>

          <div className="relative w-full md:w-96 group">
              <input 
                type="text" 
                placeholder="Caută produse, producători..." 
                value={searchTerm} 
                onChange={e => setSearchTerm(e.target.value)} 
                className="w-full bg-white border-2 border-zinc-100 rounded-2xl py-4 px-12 focus:border-zinc-900 shadow-sm outline-none transition-all font-bold text-sm placeholder:text-zinc-300 placeholder:font-medium" 
              />
              <svg className="absolute left-4 top-1/2 -translate-y-1/2 w-6 h-6 text-zinc-300 group-focus-within:text-zinc-900 transition-colors" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
          </div>
      </div>

      {/* FILTER AREA */}
      {searchMode === 'local' ? (
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-10 bg-white p-4 rounded-[2rem] border border-zinc-100 shadow-xl shadow-zinc-100">
              <div className="relative">
                <select value={filterCounty} onChange={e => setFilterCounty(e.target.value)} className="w-full bg-zinc-50 border-none rounded-2xl p-4 outline-none text-sm font-black text-zinc-700 appearance-none">
                    <option value="">Toate Județele</option>
                    {getCounties().map(c => <option key={c} value={c}>{c}</option>)}
                </select>
                <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-zinc-400">
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" /></svg>
                </div>
              </div>

              <div className="relative">
                <select value={filterCity} onChange={e => setFilterCity(e.target.value)} disabled={!filterCounty} className="w-full bg-zinc-50 border-none rounded-2xl p-4 outline-none text-sm font-black text-zinc-700 appearance-none disabled:opacity-40">
                    <option value="">Toate Localitățile</option>
                    {availableCities.map(c => <option key={c} value={c}>{c}</option>)}
                </select>
                <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-zinc-400">
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" /></svg>
                </div>
              </div>

              <button 
                onClick={() => setShowFavoritesOnly(!showFavoritesOnly)} 
                className={`flex items-center justify-center gap-2 rounded-2xl p-4 text-xs font-black uppercase tracking-widest border-2 transition-all ${showFavoritesOnly ? 'bg-red-50 border-red-200 text-red-600 shadow-inner shadow-red-100' : 'bg-white border-zinc-100 text-zinc-400 hover:border-zinc-200'}`}
              >
                  {showFavoritesOnly ? (
                    <><svg className="w-4 h-4 fill-current" viewBox="0 0 20 20"><path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z"/></svg> Favorite</>
                  ) : (
                    <><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11.049 2.927c.3-.921 1.603-.921 1.902 0l1.519 4.674a1 1 0 00.95.69h4.915c.969 0 1.371 1.24.588 1.81l-3.976 2.888a1 1 0 00-.363 1.118l1.518 4.674c.3.922-.755 1.688-1.538 1.118l-3.976-2.888a1 1 0 00-1.176 0l-3.976 2.888c-.783.57-1.838-.197-1.538-1.118l1.518-4.674a1 1 0 00-.363-1.118l-3.976-2.888c-.784-.57-.38-1.81.588-1.81h4.914a1 1 0 00.951-.69l1.519-4.674z" /></svg> Toate</>
                  )}
              </button>
          </div>
      ) : (
          <div className="mb-10 animate-fade-in">
              <div className="bg-zinc-950 p-8 md:p-12 rounded-[3.5rem] shadow-2xl shadow-zinc-200 text-white relative overflow-hidden border border-zinc-800">
                  {/* Visual Glow Decorations */}
                  <div className="absolute top-0 right-0 w-[500px] h-[500px] bg-amber-500/5 rounded-full -mr-64 -mt-64 blur-[120px]"></div>
                  <div className="absolute bottom-0 left-0 w-[300px] h-[300px] bg-emerald-500/5 rounded-full -ml-32 -mb-32 blur-[100px]"></div>

                  <div className="relative z-10 flex flex-col lg:flex-row items-center gap-16">
                      <div className="flex-1 space-y-8">
                          <div className="space-y-4">
                            <div className="flex items-center gap-2">
                                <span className="inline-block px-3 py-1 bg-amber-500/10 text-amber-500 rounded-full text-[10px] font-black uppercase tracking-[0.2em] border border-amber-500/20">Modul Traseu</span>
                                <span className="w-1 h-1 rounded-full bg-zinc-700"></span>
                                <span className="text-[10px] font-bold text-zinc-500 uppercase tracking-widest">Premium Travel UI</span>
                            </div>
                            <h3 className="text-4xl md:text-5xl font-black tracking-tighter leading-[0.9] text-white">
                                <span className="text-amber-500">Gustul</span> Local,<br/>Direct în Drum.
                            </h3>
                          </div>
                          <p className="text-zinc-400 text-lg font-medium leading-relaxed max-w-md">
                              Găsește puncte de desfacere direct de la producător, fără ocolișuri inutile în călătoria ta.
                          </p>
                          <div className="flex items-center gap-8 pt-4">
                             <div className="flex flex-col">
                               <span className="text-3xl font-black text-white">{calculatedRouteCounties.length || '0'}</span>
                               <span className="text-[10px] font-black uppercase tracking-widest text-zinc-500">Județe vizitate</span>
                             </div>
                             <div className="w-px h-12 bg-zinc-800"></div>
                             <div className="flex flex-col">
                               <span className="text-3xl font-black text-emerald-400">{processedAds.length || '0'}</span>
                               <span className="text-[10px] font-black uppercase tracking-widest text-zinc-500">Opriri recomandate</span>
                             </div>
                          </div>
                      </div>

                      <div className="flex-1 w-full bg-zinc-900/40 backdrop-blur-2xl border border-zinc-800 rounded-[3rem] p-8 md:p-10 space-y-8 shadow-inner shadow-white/5">
                          <div className="grid grid-cols-1 sm:grid-cols-2 gap-8">
                              <div className="space-y-3">
                                  <label className="block text-[10px] font-black uppercase tracking-[0.2em] text-zinc-500 ml-1">Punct de Plecare</label>
                                  <div className="relative group">
                                    <select 
                                      value={routeStartCounty} 
                                      onChange={e => setRouteStartCounty(e.target.value)} 
                                      className="w-full bg-zinc-900 text-white rounded-2xl p-5 outline-none text-sm font-black border border-zinc-700 shadow-xl focus:border-amber-500/50 focus:ring-4 focus:ring-amber-500/5 transition-all appearance-none cursor-pointer"
                                    >
                                        <option value="" className="text-zinc-500">Alege Județ</option>
                                        {getCounties().map(c => <option key={c} value={c} className="bg-zinc-900">{c}</option>)}
                                    </select>
                                    <svg className="absolute right-5 top-1/2 -translate-y-1/2 w-4 h-4 text-zinc-600 pointer-events-none group-focus-within:text-amber-500 transition-colors" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" /></svg>
                                  </div>
                              </div>
                              <div className="space-y-3">
                                  <label className="block text-[10px] font-black uppercase tracking-[0.2em] text-zinc-500 ml-1">Destinație Finală</label>
                                  <div className="relative group">
                                    <select 
                                      value={routeEndCounty} 
                                      onChange={e => setRouteEndCounty(e.target.value)} 
                                      className="w-full bg-zinc-900 text-white rounded-2xl p-5 outline-none text-sm font-black border border-zinc-700 shadow-xl focus:border-amber-500/50 focus:ring-4 focus:ring-amber-500/5 transition-all appearance-none cursor-pointer"
                                    >
                                        <option value="" className="text-zinc-500">Alege Județ</option>
                                        {getCounties().map(c => <option key={c} value={c} className="bg-zinc-900">{c}</option>)}
                                    </select>
                                    <svg className="absolute right-5 top-1/2 -translate-y-1/2 w-4 h-4 text-zinc-600 pointer-events-none group-focus-within:text-amber-500 transition-colors" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" /></svg>
                                  </div>
                              </div>
                          </div>

                          {calculatedRouteCounties.length > 0 && (
                            <div className="bg-zinc-950 rounded-2xl p-5 flex items-center justify-between border border-zinc-800">
                                <span className="text-[11px] font-black uppercase tracking-widest text-emerald-400 flex items-center gap-3">
                                   <span className="relative flex h-2 w-2">
                                     <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-emerald-400 opacity-75"></span>
                                     <span className="relative inline-flex rounded-full h-2 w-2 bg-emerald-500"></span>
                                   </span>
                                   Algoritm de Rutare Activat
                                </span>
                                <button 
                                  onClick={() => { setRouteStartCounty(''); setRouteEndCounty(''); }}
                                  className="text-[10px] font-black uppercase tracking-widest text-zinc-600 hover:text-white transition-colors"
                                >
                                  Resetează
                                </button>
                            </div>
                          )}
                      </div>
