                                          <span className="mt-4 text-[10px] font-black uppercase tracking-[0.2em] text-zinc-600 group-hover:text-zinc-200 transition-colors">{county}</span>
                                      </div>
                                      {idx < calculatedRouteCounties.length - 1 && (
                                          <div className="w-20 h-px bg-zinc-800 flex-shrink-0 mb-10"></div>
                                      )}
                                  </React.Fragment>
                              ))}
                          </div>
                      </div>
                  )}
              </div>
          </div>
      )}

      {/* RESULTS GRID */}
      {loading ? (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-8 animate-pulse">
          {[...Array(8)].map((_, i) => (
            <div key={i} className="space-y-4">
              <div className="bg-zinc-200 h-64 rounded-[2rem]"></div>
              <div className="h-4 bg-zinc-200 rounded-full w-3/4"></div>
              <div className="h-3 bg-zinc-200 rounded-full w-1/2"></div>
            </div>
          ))}
        </div>
      ) : (
        <>
          {processedAds.length === 0 ? (
            <div className="py-24 text-center">
              <div className="inline-flex items-center justify-center w-24 h-24 bg-zinc-100 rounded-full mb-6">
                <svg className="w-12 h-12 text-zinc-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" /></svg>
              </div>
              <h3 className="text-xl font-black text-zinc-900 mb-2">Niciun rezultat găsit</h3>
              <p className="text-zinc-500 max-w-sm mx-auto text-sm leading-relaxed">
                Încearcă să schimbi județul sau categoria pentru a găsi produsele dorite.
              </p>
            </div>
          ) : (
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-8">
              {currentAds.map(ad => (
                <AdCard 
                    key={ad.id} 
                    ad={ad} 
                    onClick={() => onAdClick(ad)} 
                    isFavorite={favoriteIds.includes(ad.id)} 
                    onToggleFavorite={() => onToggleFavorite(ad.id)}
                    showRouteContext={searchMode === 'route'}
                    routePosition={searchMode === 'route' ? calculatedRouteCounties.indexOf(ad.location.county) : undefined}
                />
              ))}
            </div>
          )}
        </>
      )}

      {/* PAGINATION */}
      {!loading && processedAds.length > itemsPerPage && (
        <div className="mt-16 flex justify-center gap-2">
            {[...Array(Math.ceil(processedAds.length / itemsPerPage))].map((_, i) => (
                <button 
                  key={i} 
                  onClick={() => { setCurrentPage(i + 1); window.scrollTo({ top: (document.getElementById('listings')?.offsetTop || 0) - 100, behavior: 'smooth' }); }}
                  className={`w-12 h-12 rounded-2xl font-black text-sm transition-all ${currentPage === i + 1 ? 'bg-zinc-950 text-amber-400 shadow-xl' : 'bg-white border border-zinc-100 text-zinc-400 hover:bg-zinc-50'}`}
                >
                    {i + 1}
                </button>
            ))}
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { Ad } from '../types';

interface AdCardProps {
  ad: Ad;
  onClick: () => void;
  isFavorite: boolean;
  onToggleFavorite: (e: React.MouseEvent | React.KeyboardEvent) => void;
  mini?: boolean; 
  priority?: boolean;
  showRouteContext?: boolean;
  routePosition?: number;
}

export const AdCard: React.FC<AdCardProps> = ({ 
    ad, 
    onClick, 
    isFavorite, 
    onToggleFavorite, 
    mini = false, 
    showRouteContext = false,
    routePosition
}) => {
  const isBio = ad.title.toLowerCase().includes('bio') || ad.description.toLowerCase().includes('natural');
  const [imageLoaded, setImageLoaded] = useState(false);

  const primaryCategory = ad.categories[0] || 'Produs';
  const showRating = ad.rating > 0;

  // Mocked detour time for premium "La Drum" feel
  const mockDetourTime = Math.floor(Math.random() * 8) + 2; 

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' || e.key === ' ') {
      e.preventDefault();
      onClick();
