          alt=""
          className={`w-full h-full object-cover transform group-hover:scale-110 transition-all duration-700 ease-out ${imageLoaded ? 'opacity-100' : 'opacity-0'}`}
          onLoad={() => setImageLoaded(true)}
        />

        {/* Route Context Overlay - Premium Golden Harvest Styling */}
        {showRouteContext && typeof routePosition === 'number' && (
            <div className="absolute bottom-0 left-0 right-0 bg-gradient-to-t from-zinc-950 via-zinc-950/40 to-transparent p-5 pt-16 z-20">
