        {/* Top Badges */}
        <div className="absolute top-4 left-4 flex flex-col space-y-1.5 items-start z-20">
           <div className="flex items-center gap-1.5">
             <span className="inline-flex items-center px-3 py-1 rounded-full text-[9px] font-black bg-white/95 text-zinc-900 shadow-lg backdrop-blur-md uppercase tracking-widest border border-white/20">
