import React, { useEffect, useState, useMemo } from 'react';
import { AdCard } from '../components/AdCard';
import { Carousel, Slide } from '../components/Carousel';
import { CategoryNav } from '../components/CategoryNav';
import { fetchActiveAds } from '../services/mockBackend';
import { Ad, ToastType } from '../types';
import { getCounties, getCities } from '../data/locations';
import { getCountiesOnRoute } from '../utils/routeGraph';

interface HomeProps {
  onNavigate: (path: string) => void;
  onOpenCreateModal: () => void;
  onAdClick: (ad: Ad) => void;
  favoriteIds: string[];
  onToggleFavorite: (id: string) => void;
  onAddToast?: (type: ToastType, msg: string) => void;
}

export const Home: React.FC<HomeProps> = ({ 
  onNavigate, 
  onOpenCreateModal, 
  onAdClick,
  favoriteIds,
  onToggleFavorite,
  onAddToast
}) => {
  const [ads, setAds] = useState<Ad[]>([]);
  const [loading, setLoading] = useState(true);
  const [currentPage, setCurrentPage] = useState(1);
  const itemsPerPage = 12;

  const [searchMode, setSearchMode] = useState<'local' | 'route'>('local');
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCategory, setSelectedCategory] = useState('');
  const [showFavoritesOnly, setShowFavoritesOnly] = useState(false);

  const [filterCounty, setFilterCounty] = useState('');
  const [filterCity, setFilterCity] = useState('');

  const [availableCities, setAvailableCities] = useState<string[]>([]);

  const [routeStartCounty, setRouteStartCounty] = useState('');
  const [routeEndCounty, setRouteEndCounty] = useState('');
  const [calculatedRouteCounties, setCalculatedRouteCounties] = useState<string[]>([]);

  const loadAds = async () => {
    try {
      const data = await fetchActiveAds();
      setAds(data);
    } catch (err) { console.error(err); } 
    finally { setLoading(false); }
  };

  useEffect(() => {
    loadAds();
    window.addEventListener('miculproducator:ad_updated', loadAds);
    return () => window.removeEventListener('miculproducator:ad_updated', loadAds);
  }, []);

  useEffect(() => {
    if (filterCounty) {
      setAvailableCities(getCities(filterCounty));
      setFilterCity('');
    } else {
      setAvailableCities([]);
    }
  }, [filterCounty]);

  useEffect(() => {
    if (searchMode === 'route' && routeStartCounty && routeEndCounty) {
      const path = getCountiesOnRoute(routeStartCounty, routeEndCounty);
      setCalculatedRouteCounties(path);
    } else {
      setCalculatedRouteCounties([]);
    }
  }, [searchMode, routeStartCounty, routeEndCounty]);

  const processedAds = useMemo(() => {
    const filtered = ads.filter(ad => {
      const matchesSearch = ad.title.toLowerCase().includes(searchTerm.toLowerCase()) || ad.description.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesCategory = selectedCategory ? ad.categories.includes(selectedCategory) : true;
      let matchesLocation = true;

      if (searchMode === 'local') {
        const matchesCounty = filterCounty ? ad.location.county === filterCounty : true;
        const matchesCity = filterCity ? ad.location.city === filterCity : true;
        matchesLocation = matchesCounty && matchesCity;
      } else {
        if (routeStartCounty && routeEndCounty && calculatedRouteCounties.length > 0) {
          matchesLocation = calculatedRouteCounties.includes(ad.location.county);
        }
      }
      const matchesFavorite = showFavoritesOnly ? favoriteIds.includes(ad.id) : true;
      return matchesSearch && matchesCategory && matchesLocation && matchesFavorite;
    });

    return filtered.sort((a, b) => {
      if (a.isPremium && !b.isPremium) return -1;
      if (!a.isPremium && b.isPremium) return 1;

      if (searchMode === 'route' && calculatedRouteCounties.length > 0) {
        const idxA = calculatedRouteCounties.indexOf(a.location.county);
        const idxB = calculatedRouteCounties.indexOf(b.location.county);
        if (idxA !== idxB) return idxA - idxB;
      }

      return b.createdAt - a.createdAt;
    });
  }, [ads, searchTerm, selectedCategory, searchMode, filterCounty, filterCity, routeStartCounty, routeEndCounty, calculatedRouteCounties, showFavoritesOnly, favoriteIds]);

  const currentAds = processedAds.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage);

  const heroSlides: Slide[] = [
    {
      id: '1',
      image: 'https://images.unsplash.com/photo-1488459716781-31db52582fe9?auto=format&fit=crop&q=80&w=2000',
      title: 'Hrană Curată de la Oameni Gospodari',
      description: 'Conectăm producătorii locali din România direct cu masa ta. Descoperă gustul autentic.',
      ctaText: 'Publică Anunț',
      onCtaClick: onOpenCreateModal,
    }
  ];

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8 bg-white">
      <Carousel slides={heroSlides} />
      <CategoryNav selectedCategory={selectedCategory} onSelectCategory={setSelectedCategory} />

      {/* SEARCH MODE SWITCHER - More refined, neutral styling */}
      <div id="listings" className="mb-10 flex flex-col md:flex-row justify-between items-end gap-6">
          <div className="w-full md:w-auto">
              <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-[0.2em] mb-3 ml-1">Căutare după Context</label>
              <div className="inline-flex p-1 bg-stone-100 rounded-xl border border-stone-200">
                  <button 
                    onClick={() => setSearchMode('local')} 
                    className={`flex items-center gap-2 px-6 py-2 rounded-lg text-[11px] font-bold uppercase tracking-widest transition-all ${searchMode === 'local' ? 'bg-white shadow-sm text-stone-800' : 'text-stone-400 hover:text-stone-600'}`}
                  >
                    <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" /></svg>
                    Explorare Locală
                  </button>
                  <button 
                    onClick={() => setSearchMode('route')} 
                    className={`flex items-center gap-2 px-6 py-2 rounded-lg text-[11px] font-bold uppercase tracking-widest transition-all ${searchMode === 'route' ? 'bg-white shadow-sm text-emerald-700' : 'text-stone-400 hover:text-stone-600'}`}
                  >
                    <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M13 5l7 7-7 7M5 5l7 7-7 7" /></svg>
                    Planificator Traseu
                  </button>
              </div>
          </div>

          <div className="relative w-full md:w-96 group">
              <input 
                type="text" 
                placeholder="Caută produse naturale..." 
                value={searchTerm} 
                onChange={e => setSearchTerm(e.target.value)} 
                className="w-full bg-stone-50 border border-stone-200 rounded-xl py-4 px-12 focus:border-stone-400 focus:bg-white shadow-sm outline-none transition-all font-medium text-sm placeholder:text-stone-300" 
              />
              <svg className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-stone-300 group-focus-within:text-stone-500 transition-colors" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
          </div>
      </div>

      {/* FILTER AREA - Light & Clean */}
      {searchMode === 'local' ? (
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-12 bg-white p-2 rounded-2xl border border-stone-100 shadow-sm">
              <div className="relative">
                <select value={filterCounty} onChange={e => setFilterCounty(e.target.value)} className="w-full bg-stone-50 border-none rounded-xl p-4 outline-none text-sm font-bold text-stone-700 appearance-none">
                    <option value="">Toate Județele</option>
                    {getCounties().map(c => <option key={c} value={c}>{c}</option>)}
                </select>
                <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-stone-300">
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" /></svg>
                </div>
              </div>

              <div className="relative">
                <select value={filterCity} onChange={e => setFilterCity(e.target.value)} disabled={!filterCounty} className="w-full bg-stone-50 border-none rounded-xl p-4 outline-none text-sm font-bold text-stone-700 appearance-none disabled:opacity-40">
                    <option value="">Toate Localitățile</option>
                    {availableCities.map(c => <option key={c} value={c}>{c}</option>)}
                </select>
                <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-stone-300">
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" /></svg>
                </div>
              </div>

              <button 
                onClick={() => setShowFavoritesOnly(!showFavoritesOnly)} 
                className={`flex items-center justify-center gap-2 rounded-xl p-4 text-[11px] font-bold uppercase tracking-widest border transition-all ${showFavoritesOnly ? 'bg-rose-50 border-rose-100 text-rose-600' : 'bg-white border-stone-100 text-stone-400 hover:border-stone-200'}`}
              >
                  <svg className={`w-4 h-4 ${showFavoritesOnly ? 'fill-current' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z" /></svg>
                  {showFavoritesOnly ? 'Favorite' : 'Toate Produsele'}
              </button>
          </div>
      ) : (
          <div className="mb-12 animate-fade-in">
              <div className="bg-stone-50 p-10 md:p-14 rounded-[2.5rem] border border-stone-200 text-stone-800 relative overflow-hidden">
                  <div className="relative z-10 flex flex-col lg:flex-row items-center gap-16">
