      e.preventDefault();
      onClick();
    }
  };

  const mapsLink = `https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(`${ad.title} ${ad.location.city} ${ad.location.county} Romania`)}`;

  if (mini) {
    return (
      <div 
