export default App;

import { Ad, AdStatus, CreateAdPayload, Review, AppNotification } from '../types';
import { getCounties, getCities, getVillages } from '../data/locations';
import { supabase } from './supabaseClient';

const USE_SUPABASE = !!supabase;
const ADS_KEY = 'miculproducator_ads_v8';

const delay = (ms: number) => new Promise((resolve) => setTimeout(resolve, ms));

const generateId = (): string => {
  if (typeof crypto !== 'undefined' && crypto.randomUUID) return crypto.randomUUID();
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
    var r = Math.random() * 16 | 0, v = c == 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
};

const fileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => resolve(reader.result as string);
    reader.onerror = error => reject(error);
  });
};

const mapAdFromDB = (row: any): Ad => ({
    ...row,
    createdAt: new Date(row.created_at).getTime(),
    expiresAt: row.expires_at ? new Date(row.expires_at).getTime() : null,
    reviews: Array.isArray(row.reviews) ? row.reviews : [],
    price: Number(row.price),
    rating: Number(row.rating),
    phoneNumber: row.phone_number,
    isPremium: row.is_premium || false,
    stats: row.stats || { views: Math.floor(Math.random() * 200), whatsappClicks: Math.floor(Math.random() * 15), favorites: 0 }
});

const uploadImages = async (files: File[]): Promise<string[]> => {
  if (!supabase || files.length === 0) return [];

  const urls: string[] = [];
  for (const file of files) {
    const fileExt = file.name.split('.').pop();
    const fileName = `${generateId()}.${fileExt}`;
    const filePath = `${fileName}`;

    const { error: uploadError } = await supabase.storage
      .from('images')
      .upload(filePath, file);

    if (uploadError) {
      console.error('Supabase Storage Error:', uploadError);
      continue;
    }

    const { data: { publicUrl } } = supabase.storage
      .from('images')
      .getPublicUrl(filePath);

    urls.push(publicUrl);
  }
  return urls;
};

export const startPaymentSession = async (adId: string, planId: string, email: string) => {
  if (!supabase) {
    console.warn("Supabase not initialized. Simulation mode. Auto-activating in 2 seconds...");
    return { url: null };
  }

  try {
    const { data, error } = await supabase.functions.invoke('create-stripe-session', {
      body: { adId, planId, customerEmail: email }
    });
    if (error) throw error;
    return data; 
  } catch (err) {
    console.error("Payment Edge Function call failed:", err);
    return { url: null };
  }
};

export const verifyPaymentSession = async (adId: string): Promise<{ success: boolean; ad?: Ad }> => {
  if (USE_SUPABASE) {
    const { data, error } = await supabase!.from('ads').select('*').eq('id', adId).single();
    if (!error && data.status === 'active') return { success: true, ad: mapAdFromDB(data) };
    return { success: false };
  }
  const adsRaw = localStorage.getItem(ADS_KEY);
  const ads = adsRaw ? JSON.parse(adsRaw) : [];
  const ad = ads.find((a: any) => a.id === adId);
  return { success: !!ad, ad };
};

export const fetchActiveAds = async (): Promise<Ad[]> => {
  if (USE_SUPABASE) {
    const { data, error } = await supabase!.from('ads').select('*').eq('status', 'active').order('created_at', { ascending: false });
    if (!error) return data.map(mapAdFromDB);
  }
  const adsRaw = localStorage.getItem(ADS_KEY);
  const ads = adsRaw ? JSON.parse(adsRaw) : [];
  return ads.filter((a: any) => a.status === AdStatus.ACTIVE).sort((a: any, b: any) => b.createdAt - a.createdAt);
};

export const fetchAdById = async (id: string): Promise<Ad | null> => {
  if (USE_SUPABASE) {
    const { data, error } = await supabase!.from('ads').select('*').eq('id', id).single();
    if (!error) return mapAdFromDB(data);
  }
  const adsRaw = localStorage.getItem(ADS_KEY);
  const ads = adsRaw ? JSON.parse(adsRaw) : [];
  return ads.find((a: any) => String(a.id) === String(id)) || null;
};

export const createAd = async (payload: CreateAdPayload): Promise<{ adId: string; token: string }> => {
  const token = generateId().replace(/-/g, '');
  const initialStatus = AdStatus.PENDING;

  if (USE_SUPABASE) {
    const uploadedImageUrls = await uploadImages(payload.images);
    const { data, error } = await supabase!.from('ads').insert({
      title: payload.title,
      description: payload.description,
      price: payload.price,
      categories: payload.categories,
      email: payload.email,
      phone_number: payload.phoneNumber,
      location: payload.location,
      images: uploadedImageUrls, 
      token,
      status: initialStatus
    }).select().single();
    if (!error) return { adId: data.id, token };
    throw error;
  }

  const base64Images = await Promise.all(payload.images.map(file => fileToBase64(file)));
  const newAd: Ad = {
    id: generateId(),
    ...payload,
    images: base64Images.length > 0 ? base64Images : ['https://via.placeholder.com/400x300?text=Produs+Local'],
    token,
    status: initialStatus,
    createdAt: Date.now(),
    expiresAt: Date.now() + (28 * 24 * 60 * 60 * 1000),
    reviews: [],
    rating: 0,
    isPremium: false,
    stats: { views: 0, whatsappClicks: 0, favorites: 0 }
  };

  const adsRaw = localStorage.getItem(ADS_KEY);
  const ads = adsRaw ? JSON.parse(adsRaw) : [];
  localStorage.setItem(ADS_KEY, JSON.stringify([...ads, newAd]));
  return { adId: newAd.id, token };
};

export const simulatePaymentSuccess = async (adId: string): Promise<void> => {
  await delay(1500);
  if (USE_SUPABASE) {
    await supabase!.from('ads').update({ status: 'active', is_premium: true, expires_at: new Date(Date.now() + 28*86400000).toISOString() }).eq('id', adId);
  } else {
    const adsRaw = localStorage.getItem(ADS_KEY);
    const ads = adsRaw ? JSON.parse(adsRaw) : [];
    localStorage.setItem(ADS_KEY, JSON.stringify(ads.map((a: any) => a.id === adId ? { ...a, status: 'active', isPremium: true } : a)));
  }
};

export const verifyManageToken = async (id: string, token: string): Promise<Ad | null> => {
  if (USE_SUPABASE) {
    const { data } = await supabase!.from('ads').select('*').eq('id', id).eq('token', token).single();
    if (data) return mapAdFromDB(data);
  }
  const adsRaw = localStorage.getItem(ADS_KEY);
  const ads = adsRaw ? JSON.parse(adsRaw) : [];
  const ad = ads.find((a: any) => String(a.id) === String(id));
  return ad?.token === token ? mapAdFromDB(ad) : null;
};

export const updateAd = async (id: string, token: string, updates: Partial<Ad>): Promise<boolean> => {
  const isAdminBypass = token === 'admin_override';
  if (USE_SUPABASE) {
    const dbUpdates: any = { ...updates };
    if (updates.phoneNumber) dbUpdates.phone_number = updates.phoneNumber;
    if (updates.location) dbUpdates.location = updates.location;
    let query = supabase!.from('ads').update(dbUpdates).eq('id', id);
    if (!isAdminBypass) query = query.eq('token', token);
    const { error } = await query;
    return !error;
  }
  const adsRaw = localStorage.getItem(ADS_KEY);
  const ads = adsRaw ? JSON.parse(adsRaw) : [];
  const idx = ads.findIndex((a: any) => String(a.id) === String(id) && (isAdminBypass || a.token === token));
  if (idx === -1) return false;
  ads[idx] = { ...ads[idx], ...updates };
  localStorage.setItem(ADS_KEY, JSON.stringify(ads));
  return true;
};

export const deleteAd = async (id: string, token: string): Promise<boolean> => {
  const isAdminBypass = token === 'admin_override';
  if (USE_SUPABASE) {
    let query = supabase!.from('ads').delete().eq('id', id);
    if (!isAdminBypass) query = query.eq('token', token);
    const { error } = await query;
    return !error;
  }
  const adsRaw = localStorage.getItem(ADS_KEY);
  if (!adsRaw) return false;
  const ads = JSON.parse(adsRaw);
  const remainingAds = ads.filter((a: any) => !(String(a.id) === String(id) && (isAdminBypass || a.token === token)));
  if (remainingAds.length < ads.length) {
    localStorage.setItem(ADS_KEY, JSON.stringify(remainingAds));
    return true;
  }
  return false;
};

export const getAllAds = async (): Promise<Ad[]> => {
    if (USE_SUPABASE) {
        const { data, error } = await supabase!.from('ads').select('*').order('created_at', { ascending: false });
        if (!error) return data.map(mapAdFromDB);
    }
    const adsRaw = localStorage.getItem(ADS_KEY);
    const ads = adsRaw ? JSON.parse(adsRaw) : [];
    return ads.sort((a: any, b: any) => b.createdAt - a.createdAt);
};

export const adminDeleteAd = async (id: string): Promise<boolean> => deleteAd(id, 'admin_override');
export const adminUpdateAd = async (id: string, updates: Partial<Ad>): Promise<boolean> => updateAd(id, 'admin_override', updates);

export const addReview = async (adId: string, review: any): Promise<Review> => {
  const newReview = { ...review, id: generateId(), createdAt: Date.now() };
  if (USE_SUPABASE) {
    const { data } = await supabase!.from('ads').select('reviews').eq('id', adId).single();
    const reviews = [...(data?.reviews || []), newReview];
    const rating = reviews.reduce((s, r) => s + r.rating, 0) / reviews.length;
    await supabase!.from('ads').update({ reviews, rating }).eq('id', adId);
    return newReview;
  }
  const adsRaw = localStorage.getItem(ADS_KEY);
  const ads = adsRaw ? JSON.parse(adsRaw) : [];
  const idx = ads.findIndex((a: any) => a.id === adId);
  if (idx !== -1) {
    ads[idx].reviews = [...(ads[idx].reviews || []), newReview];
    ads[idx].rating = ads[idx].reviews.reduce((s: any, r: any) => s + r.rating, 0) / ads[idx].reviews.length;
    localStorage.setItem(ADS_KEY, JSON.stringify(ads));
  }
  return newReview;
};

