        </div>
        <h2 className="text-2xl font-bold text-stone-900 mb-2">Anunț publicat!</h2>
        <p className="text-stone-500 mb-8 text-sm max-w-xs mx-auto leading-relaxed">Verifică emailul pentru link-ul de gestionare și factura Stripe.</p>

        <div className="bg-stone-50 border border-stone-200 rounded-[2rem] p-8 max-w-sm mx-auto shadow-sm mb-8">
          <h3 className="text-[10px] font-bold text-stone-400 uppercase tracking-[0.2em] mb-4">Referință Anunț</h3>
          <div className="bg-white border border-stone-200 rounded-xl p-4 font-mono text-2xl font-bold text-stone-800 select-all tracking-wider">
            {createdAdData.adId.slice(0, 8).toUpperCase()}
          </div>
        </div>
        <button 
          className="w-full h-14 bg-stone-900 text-white rounded-xl font-bold uppercase tracking-widest text-xs hover:bg-stone-800 transition-all"
          onClick={() => { if (onClose) onClose(); else onNavigate('/'); }}
        >
          Închide
