/**
 * BFS (Breadth-First Search) Algorithm
 * Used to find the shortest path between two counties in the Romanian graph.
 * In the context of MiculProducator, this defines the "Travel Corridor".
 * 
 * @param start - The name of the departure county
 * @param end   - The name of the destination county
 * @returns An array of county names in order, or just start/end if no path is found.
 */
export const getCountiesOnRoute = (start: string, end: string): string[] => {
  // Edge cases: empty input or same location
  if (!start || !end) return [];
  if (start === end) return [start];

  // Validation: Check if counties exist in our map
  if (!COUNTY_ADJACENCY[start] || !COUNTY_ADJACENCY[end]) {
      return [start, end];
  }

  // Standard BFS implementation using a queue of paths
  const queue: string[][] = [[start]];
  const visited = new Set<string>();
  visited.add(start);

  while (queue.length > 0) {
    const path = queue.shift()!;
    const node = path[path.length - 1];

    // Destination found: return the full path array
    if (node === end) {
      return path;
    }

    const neighbors = COUNTY_ADJACENCY[node] || [];
    for (const neighbor of neighbors) {
      if (!visited.has(neighbor)) {
        visited.add(neighbor);
        const newPath = [...path, neighbor];
        queue.push(newPath);
      }
    }
  }

  // Fallback: If for some reason the graph is disconnected (impossible with current dataset)
  return [start, end];
};

