      ) : (
          <div className="mb-12 animate-fade-in">
              <div className="bg-stone-50 p-10 md:p-14 rounded-[3rem] border border-stone-200 text-stone-800 relative overflow-hidden">
                  <div className="relative z-10 flex flex-col lg:flex-row items-center gap-16">
                      <div className="flex-1 space-y-6">
                          <div className="space-y-2">
                            <span className="text-[10px] font-bold text-emerald-600 uppercase tracking-[0.3em]">Călătorie cu Gust</span>
                            <h3 className="text-4xl md:text-5xl font-light tracking-tight text-stone-900 leading-[0.9]">
