                          </p>
                          <div className="flex items-center gap-10 pt-4">
                             <div className="flex flex-col">
                               <span className="text-2xl font-semibold text-stone-800">{calculatedRouteCounties.length || '0'}</span>
                               <span className="text-[9px] font-bold uppercase tracking-widest text-stone-400">Județe traversate</span>
                             </div>
                             <div className="w-px h-8 bg-stone-200"></div>
                             <div className="flex flex-col">
                               <span className="text-2xl font-semibold text-emerald-600">{processedAds.length || '0'}</span>
                               <span className="text-[9px] font-bold uppercase tracking-widest text-stone-400">Opriri recomandate</span>
                             </div>
                          </div>
                      </div>

                      <div className="flex-1 w-full bg-white border border-stone-200 rounded-[2.5rem] p-8 md:p-10 space-y-8 shadow-xl shadow-stone-200/50">
                          <div className="grid grid-cols-1 sm:grid-cols-2 gap-8">
                              <div className="space-y-3">
                                  <label className="block text-[10px] font-bold uppercase tracking-widest text-stone-400 ml-1">Punct de Plecare</label>
                                  <div className="relative">
                                    <select 
                                      value={routeStartCounty} 
                                      onChange={e => setRouteStartCounty(e.target.value)} 
                                      className="w-full bg-stone-50 text-stone-700 rounded-xl p-4 outline-none text-sm font-bold border border-stone-100 focus:border-stone-300 transition-all appearance-none cursor-pointer"
                                    >
                                        <option value="">Alege Județ</option>
                                        {getCounties().map(c => <option key={c} value={c}>{c}</option>)}
                                    </select>
                                    <svg className="absolute right-4 top-1/2 -translate-y-1/2 w-4 h-4 text-stone-400 pointer-events-none" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" /></svg>
                                  </div>
                              </div>
                              <div className="space-y-3">
                                  <label className="block text-[10px] font-bold uppercase tracking-widest text-stone-400 ml-1">Destinație Finală</label>
                                  <div className="relative">
                                    <select 
                                      value={routeEndCounty} 
                                      onChange={e => setRouteEndCounty(e.target.value)} 
                                      className="w-full bg-stone-50 text-stone-700 rounded-xl p-4 outline-none text-sm font-bold border border-stone-100 focus:border-stone-300 transition-all appearance-none cursor-pointer"
                                    >
                                        <option value="">Alege Județ</option>
                                        {getCounties().map(c => <option key={c} value={c}>{c}</option>)}
                                    </select>
                                    <svg className="absolute right-4 top-1/2 -translate-y-1/2 w-4 h-4 text-stone-400 pointer-events-none" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" /></svg>
                                  </div>
                              </div>
                          </div>

                          {calculatedRouteCounties.length > 0 && (
                            <div className="bg-emerald-50 rounded-xl p-4 flex items-center justify-between border border-emerald-100/50">
                                <span className="text-[10px] font-bold uppercase tracking-widest text-emerald-700 flex items-center gap-3">
                                   <span className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></span>
