                                </span>
                                <button 
                                  onClick={() => { setRouteStartCounty(''); setRouteEndCounty(''); }}
                                  className="text-[10px] font-bold uppercase tracking-widest text-stone-400 hover:text-stone-600 transition-colors"
                                >
                                  Resetează
                                </button>
                            </div>
                          )}
                      </div>
                  </div>

                  {/* UI: ROUTE VISUALIZER */}
                  {calculatedRouteCounties.length > 0 && (
                      <div className="mt-16 pt-12 border-t border-stone-200/60">
                          <div className="flex items-center gap-6 overflow-x-auto pb-6 scrollbar-hide">
                              {calculatedRouteCounties.map((county, idx) => (
                                  <React.Fragment key={county}>
                                      <div className="flex flex-col items-center flex-shrink-0 group">
                                          <div className={`w-14 h-14 rounded-xl flex items-center justify-center font-bold text-[11px] border transition-all ${
                                            idx === 0 || idx === calculatedRouteCounties.length - 1 
                                              ? 'bg-stone-800 text-white border-stone-800 shadow-lg' 
                                              : 'bg-white text-stone-500 border-stone-200 hover:border-stone-400'
                                          }`}>
                                              {county.slice(0, 2).toUpperCase()}
                                          </div>
                                          <span className="mt-3 text-[9px] font-bold uppercase tracking-widest text-stone-400 group-hover:text-stone-700 transition-colors">{county}</span>
                                      </div>
                                      {idx < calculatedRouteCounties.length - 1 && (
                                          <div className="flex-shrink-0 w-12 border-t-2 border-dotted border-stone-200 mt-[-22px]"></div>
                                      )}
                                  </React.Fragment>
                              ))}
                          </div>
                      </div>
                  )}
              </div>
          </div>
      )}

      {/* UI: RESULTS GRID */}
      {loading ? (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-8 animate-pulse">
          {[...Array(8)].map((_, i) => (
            <div key={i} className="space-y-4">
              <div className="bg-stone-100 h-64 rounded-2xl"></div>
              <div className="h-4 bg-stone-100 rounded-full w-3/4"></div>
              <div className="h-3 bg-stone-100 rounded-full w-1/2"></div>
            </div>
          ))}
        </div>
      ) : (
        <>
          {processedAds.length === 0 ? (
            <div className="py-24 text-center">
              <div className="inline-flex items-center justify-center w-20 h-20 bg-stone-50 rounded-full mb-6">
                <svg className="w-8 h-8 text-stone-200" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" /></svg>
              </div>
              <h3 className="text-lg font-bold text-stone-900 mb-2 tracking-tight">Nicio recomandare găsită</h3>
              <p className="text-stone-400 max-w-sm mx-auto text-sm leading-relaxed font-medium">
                Nu am găsit producători activi pe acest segment. Încearcă să schimbi județul sau categoria.
              </p>
            </div>
          ) : (
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-8">
              {currentAds.map(ad => (
                <AdCard 
                    key={ad.id} 
                    ad={ad} 
                    onClick={() => onAdClick(ad)} 
                    isFavorite={favoriteIds.includes(ad.id)} 
                    onToggleFavorite={() => onToggleFavorite(ad.id)}
                    showRouteContext={searchMode === 'route'}
                    routePosition={searchMode === 'route' ? calculatedRouteCounties.indexOf(ad.location.county) : undefined}
                />
              ))}
            </div>
          )}
        </>
      )}

      {/* UI: PAGINATION */}
      {!loading && processedAds.length > itemsPerPage && (
        <div className="mt-20 flex justify-center gap-3">
            {[...Array(Math.ceil(processedAds.length / itemsPerPage))].map((_, i) => (
                <button 
                  key={i} 
                  onClick={() => { setCurrentPage(i + 1); window.scrollTo({ top: (document.getElementById('listings')?.offsetTop || 0) - 100, behavior: 'smooth' }); }}
                  className={`w-10 h-10 rounded-lg text-xs font-bold transition-all ${currentPage === i + 1 ? 'bg-stone-900 text-white shadow-md' : 'bg-white border border-stone-100 text-stone-400 hover:border-stone-200 hover:text-stone-600'}`}
                >
                    {i + 1}
                </button>
            ))}
        </div>
      )}
    </div>
  );
};

import React, { useEffect, useState, useRef } from 'react';
import { Home } from './pages/Home';
import { CreateAd } from './pages/CreateAd';
import { AdDetails } from './pages/AdDetails';
import { Admin } from './pages/Admin';
import { Terms } from './pages/Terms';
import { Privacy } from './pages/Privacy';
import { PaymentSuccess } from './pages/PaymentSuccess';
import { Modal } from './components/Modal';
import { ToastContainer } from './components/Toast';
import { Ad, AppNotification, ToastMessage, ToastType } from './types';
import { fetchNotifications, clearAllNotifications } from './services/mockBackend';

/**
 * ROOT APPLICATION COMPONENT
 * Handles routing, global modals, notifications, and shared state like favorites.
 */
const App: React.FC = () => {
  // NAVIGATION: Uses hash-based routing (#/) to ensure SPA works across all hosting providers.
  const [currentPath, setCurrentPath] = useState(window.location.hash || '#/');

  // MODAL STATES: Controlled at root to allow them to be opened from anywhere in the tree.
  const [isCreateModalOpen, setIsCreateModalOpen] = useState(false);
  const [isTermsModalOpen, setIsTermsModalOpen] = useState(false);
  const [isPrivacyModalOpen, setIsPrivacyModalOpen] = useState(false);

  // SELECTED AD: Used when opening the Ad Details modal from the Home grid.
  const [selectedAd, setSelectedAd] = useState<Ad | null>(null);

  // SHARED STATE: Favorites and Toasts are managed globally for cross-page consistency.
  const [toasts, setToasts] = useState<ToastMessage[]>([]);
  const [favorites, setFavorites] = useState<string[]>([]);
  const [notifications, setNotifications] = useState<AppNotification[]>([]);
  const [showNotifDropdown, setShowNotifDropdown] = useState(false);
  const notifDropdownRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    // Initial load of favorites from client storage
    const saved = localStorage.getItem('miculproducator_favorites');
    if (saved) setFavorites(JSON.parse(saved));
    loadNotifications();

    // Event listener for backend changes to trigger notification refreshes
    const handleNotifUpdate = () => loadNotifications();
    window.addEventListener('miculproducator:notifications_updated', handleNotifUpdate);

    // Outside click detection for the Notification dropdown UI
    const handleClickOutside = (event: MouseEvent) => {
        if (notifDropdownRef.current && !notifDropdownRef.current.contains(event.target as Node)) {
            setShowNotifDropdown(false);
        }
    };
    document.addEventListener('mousedown', handleClickOutside);

    return () => {
        window.removeEventListener('miculproducator:notifications_updated', handleNotifUpdate);
        document.removeEventListener('mousedown', handleClickOutside);
    };
  }, []);

  const loadNotifications = async () => {
      const data = await fetchNotifications();
      setNotifications(data);
  };

  /** Global feedback system for user actions */
  const addToast = (type: ToastType, message: string) => {
    const id = Math.random().toString(36).substr(2, 9);
    setToasts((prev) => [...prev, { id, type, message }]);
  };

  const removeToast = (id: string) => {
    setToasts((prev) => prev.filter((t) => t.id !== id));
  };

  /** Handles the addition/removal of ads to local wishlist */
  const handleToggleFavorite = (id: string) => {
    let newFavs: string[];
    if (favorites.includes(id)) {
      newFavs = favorites.filter(fav => fav !== id);
      addToast('info', 'Eliminat de la favorite');
    } else {
      newFavs = [...favorites, id];
      addToast('success', 'Adăugat la favorite');
    }
    setFavorites(newFavs);
    localStorage.setItem('miculproducator_favorites', JSON.stringify(newFavs));
  };

  /** Centralized navigation handler */
  const navigate = (path: string) => {
    window.location.hash = path;
    window.scrollTo(0, 0);
  };

  /** Syncs internal state with browser URL changes */
  useEffect(() => {
    const handleHashChange = () => setCurrentPath(window.location.hash || '#/');
    window.addEventListener('hashchange', handleHashChange);
    return () => window.removeEventListener('hashchange', handleHashChange);
  }, []);

  /** 
   * ROUTER SWITCH
   * Determines which page to render based on the URL hash.
   */
  const renderRoute = () => {
    const path = currentPath.replace('#', '');
    const cleanPath = path.split('?')[0];

    if (cleanPath === '/' || cleanPath === '') {
      return (
        <Home 
          onNavigate={navigate} 
          onOpenCreateModal={() => setIsCreateModalOpen(true)}
          onAdClick={(ad) => setSelectedAd(ad)}
          favoriteIds={favorites}
          onToggleFavorite={handleToggleFavorite}
          onAddToast={addToast}
        />
      );
    }

    // Hidden route for platform administrators
    if (cleanPath === '/adminAccess') return <Admin onNavigate={navigate} />;

    // Post-checkout landing page
    if (cleanPath === '/payment-success') return <PaymentSuccess onNavigate={navigate} />;

    // Direct link to an ad listing
    if (cleanPath.startsWith('/ad/')) {
      const id = cleanPath.split('/ad/')[1];
      return (
        <AdDetails 
          id={id} 
          onNavigate={navigate} 
          isFavorite={favorites.includes(id)}
          onToggleFavorite={() => handleToggleFavorite(id)}
          onAddToast={addToast}
        />
      );
    }

    return <div className="p-24 text-center text-stone-400 font-medium animate-fade-in">404 - Pagina nu a fost găsită</div>;
  };

  const unreadCount = notifications.filter(n => !n.isRead).length;

  return (
    <div className="min-h-screen flex flex-col font-sans text-stone-800 bg-white">
      <header className="bg-white/80 backdrop-blur-md sticky top-0 z-30 border-b border-stone-100">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-24 items-center">
            {/* BRANDING: Modified to include the patriotic subtitle with Romanian Colors */}
            <div className="flex flex-col cursor-pointer group" onClick={() => navigate('/')}>
              <span className="text-xl font-bold text-stone-900 tracking-tight transition-colors group-hover:text-emerald-700 leading-none">
                MiculProducator
              </span>
              {/* SUBTITLE: Using bg-gradient-to-r with clip-text to achieve the tricolor look (Blue-Yellow-Red) */}
              <span className="text-[9px] font-bold uppercase tracking-[0.15em] bg-gradient-to-r from-blue-700 via-yellow-500 to-red-600 bg-clip-text text-transparent mt-1.5 transition-all group-hover:opacity-80">
                Creat cu dragoste si pasiune pentru Romania
              </span>
            </div>

            <div className="flex items-center space-x-4">
              <div className="relative" ref={notifDropdownRef}>
                  <button onClick={() => setShowNotifDropdown(!showNotifDropdown)} className="p-2 rounded-xl text-stone-400 hover:bg-stone-50 hover:text-stone-600 transition-all relative">
                      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 17h5l-1.405-1.405A2.032 2.032 0 0118 14.158V11a6.002 6.002 0 00-4-5.659V5a2 2 0 10-4 0v.341C7.67 6.165 6 8.388 6 11v3.159c0 .538-.214 1.055-.595 1.436L4 17h5m6 0v1a3 3 0 11-6 0v-1m6 0H9" /></svg>
                      {unreadCount > 0 && <span className="absolute top-2 right-2 block h-2 w-2 rounded-full bg-rose-500 ring-2 ring-white"></span>}
                  </button>
                  {showNotifDropdown && (
                      <div className="absolute right-0 mt-3 w-80 bg-white rounded-2xl shadow-xl shadow-stone-200/50 z-50 border border-stone-100 animate-scale-in">
                          <div className="py-3 px-5 bg-stone-50/50 border-b border-stone-100 flex justify-between items-center text-[10px] font-bold uppercase tracking-widest text-stone-400">
