   * ROUTER SWITCH
   * Determines which page to render based on the URL hash.
   */
  const renderRoute = () => {
    const path = currentPath.replace('#', '');
    const cleanPath = path.split('?')[0];

    if (cleanPath === '/' || cleanPath === '') {
      return (
        <Home 
          onNavigate={navigate} 
          onOpenCreateModal={() => setIsCreateModalOpen(true)}
          onAdClick={(ad) => setSelectedAd(ad)}
          favoriteIds={favorites}
          onToggleFavorite={handleToggleFavorite}
          onAddToast={addToast}
        />
      );
    }

    // Hidden route for platform administrators
    if (cleanPath === '/adminAccess') return <Admin onNavigate={navigate} />;

    // Post-checkout landing page
    if (cleanPath === '/payment-success') return <PaymentSuccess onNavigate={navigate} />;

    // Direct link to an ad listing
    if (cleanPath.startsWith('/ad/')) {
      const id = cleanPath.split('/ad/')[1];
      return (
        <AdDetails 
          id={id} 
          onNavigate={navigate} 
          isFavorite={favorites.includes(id)}
          onToggleFavorite={() => handleToggleFavorite(id)}
          onAddToast={addToast}
        />
      );
    }

    return <div className="p-24 text-center text-stone-400 font-medium animate-fade-in">404 - Pagina nu a fost găsită</div>;
  };

