              <span className="text-[9px] font-bold uppercase tracking-[0.15em] bg-gradient-to-r from-blue-700 via-yellow-500 to-red-600 bg-clip-text text-transparent mt-1.5 transition-all group-hover:opacity-80">
                Din Dragoste Si Pasiune Pentru Romania
              </span>
            </div>

            <div className="flex items-center space-x-4">
              <div className="relative" ref={notifDropdownRef}>
                  <button onClick={() => setShowNotifDropdown(!showNotifDropdown)} className="p-2 rounded-xl text-stone-400 hover:bg-stone-50 hover:text-stone-600 transition-all relative">
                      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 17h5l-1.405-1.405A2.032 2.032 0 0118 14.158V11a6.002 6.002 0 00-4-5.659V5a2 2 0 10-4 0v.341C7.67 6.165 6 8.388 6 11v3.159c0 .538-.214 1.055-.595 1.436L4 17h5m6 0v1a3 3 0 11-6 0v-1m6 0H9" /></svg>
                      {unreadCount > 0 && <span className="absolute top-2 right-2 block h-2 w-2 rounded-full bg-rose-500 ring-2 ring-white"></span>}
                  </button>
