import React, { useEffect, useState } from 'react';
import { fetchAdById, fetchActiveAds, addReview } from '../services/mockBackend';
import { Ad, Review } from '../types';
import { Button } from '../components/Button';
import { AdCard } from '../components/AdCard';

interface AdDetailsProps {
  id: string;
  initialData?: Ad | null;
  onNavigate?: (path: string) => void;
  onClose?: () => void;
  isFavorite?: boolean;
  onToggleFavorite?: () => void;
  onAddToast?: (type: 'success' | 'info' | 'error', msg: string) => void;
}

export const AdDetails: React.FC<AdDetailsProps> = ({ 
  id, 
  initialData, 
  onNavigate, 
  onClose,
  isFavorite,
  onToggleFavorite,
  onAddToast 
}) => {
  const [ad, setAd] = useState<Ad | null>(initialData || null);
  const [loading, setLoading] = useState(!initialData);
  const [currentImageIndex, setCurrentImageIndex] = useState(0);

  // Obfuscation State: Protects against spambots
  const [showEmail, setShowEmail] = useState(false);

  // Review Form State
  const [reviewName, setReviewName] = useState('');
  const [reviewComment, setReviewComment] = useState('');
  const [reviewRating, setReviewRating] = useState(5);
  const [submittingReview, setSubmittingReview] = useState(false);
  const [reviewFormVisible, setReviewFormVisible] = useState(false);

  // Related Ads State
  const [relatedAds, setRelatedAds] = useState<Ad[]>([]);

  useEffect(() => {
    if (initialData) {
        setAd(initialData);
    } else {
        const load = async () => {
          try {
            setLoading(true);
            const data = await fetchAdById(id);
            setAd(data);
          } catch (err) {
            console.error(err);
          } finally {
            setLoading(false);
          }
        };
        load();
    }
  }, [id, initialData]);

  useEffect(() => {
    if (ad) {
      const loadRelated = async () => {
        try {
          const allAds = await fetchActiveAds();
          const similar = allAds
            .filter(a => 
              a.id !== ad.id && 
              a.categories.some(cat => ad.categories.includes(cat))
            )
            .slice(0, 3);
          setRelatedAds(similar);
        } catch (e) { }
      };
      loadRelated();
    }
  }, [ad]);

  const handleRelatedClick = (relatedAd: Ad) => {
    setAd(relatedAd);
    setCurrentImageIndex(0);
    setShowEmail(false); // Reset obfuscation when switching products
  };

  const nextImage = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (ad && ad.images.length > 0) {
      setCurrentImageIndex((prev) => (prev + 1) % ad.images.length);
    }
  };

  const prevImage = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (ad && ad.images.length > 0) {
      setCurrentImageIndex((prev) => (prev - 1 + ad.images.length) % ad.images.length);
    }
  };

  const handleShare = async () => {
    const url = window.location.origin + `/#/ad/${id}`;
    if (navigator.share) {
      try {
        await navigator.share({
          title: ad?.title,
          text: `Vezi acest produs pe MiculProducator: ${ad?.title}`,
          url: url,
        });
      } catch (err) { }
    } else {
      await navigator.clipboard.writeText(url);
      if (onAddToast) onAddToast('info', 'Link copiat în clipboard!');
    }
  };

  const handleSubmitReview = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!ad) return;

    setSubmittingReview(true);
    try {
        const newReview = await addReview(ad.id, {
            author: reviewName || 'Anonim',
            rating: reviewRating,
            comment: reviewComment
        });

        setAd(prev => {
            if (!prev) return null;
            const updatedReviews = [...(prev.reviews || []), newReview];
            const newRating = updatedReviews.reduce((sum, r) => sum + r.rating, 0) / updatedReviews.length;
            return { ...prev, reviews: updatedReviews, rating: newRating };
        });

        window.dispatchEvent(new CustomEvent('miculproducator:ad_updated', { detail: { adId: ad.id } }));
        setReviewName('');
        setReviewComment('');
        setReviewRating(5);
        setReviewFormVisible(false);
        if (onAddToast) onAddToast('success', 'Recenzie adăugată cu succes!');
    } catch (error) {
        if (onAddToast) onAddToast('info', 'Eroare la adăugarea recenziei');
    } finally {
        setSubmittingReview(false);
