    name: 'Pro Market',
    productCount: 5,
    basePrice: 30,
    features: ['Vinde până la 5 produse', 'Vizibil în 5 Categorii', 'Suport Prioritar'],
  }
];

const DURATIONS = [
  { days: 30, multiplier: 1, discount: 0, label: '30 Zile' },
  { days: 90, multiplier: 3, discount: 5, label: '90 Zile' },
  { days: 180, multiplier: 6, discount: 10, label: '180 Zile' },
  { days: 360, multiplier: 12, discount: 15, label: '360 Zile' },
];

export const CreateAd: React.FC<CreateAdProps> = ({ onNavigate, onClose, onOpenTerms, onOpenPrivacy }) => {
  const [step, setStep] = useState<'plan' | 'form' | 'payment' | 'success'>('plan');
  const [loading, setLoading] = useState(false);

  // Selection State
  const [selectedPlan, setSelectedPlan] = useState<Plan | null>(null);
  const [selectedDuration, setSelectedDuration] = useState(DURATIONS[0]);

  // Form State
  const [title, setTitle] = useState('');
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [price, setPrice] = useState('');
  const [description, setDescription] = useState('');
  const [email, setEmail] = useState('');
  const [phoneNumber, setPhoneNumber] = useState('');
  const [images, setImages] = useState<File[]>([]);
  const [previews, setPreviews] = useState<string[]>([]);
  const [agreedToTerms, setAgreedToTerms] = useState(false);

  // Location State
  const [county, setCounty] = useState('');
  const [city, setCity] = useState('');
  const [village, setVillage] = useState('');
  const [availableCities, setAvailableCities] = useState<string[]>([]);

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (county) {
      setAvailableCities(getCities(county));
      setCity('');
    }
  }, [county]);

  const [createdAdData, setCreatedAdData] = useState<{ adId: string } | null>(null);

  const calculateTotalPrice = (basePrice: number) => {
      const total = basePrice * selectedDuration.multiplier;
      const discounted = total * (1 - selectedDuration.discount / 100);
      return Math.round(discounted);
  };

  const toggleCategory = (cat: string) => {
    if (!selectedPlan) return;
    if (selectedCategories.includes(cat)) {
      setSelectedCategories(prev => prev.filter(c => c !== cat));
    } else {
      if (selectedCategories.length < selectedPlan.productCount) {
        setSelectedCategories(prev => [...prev, cat]);
      }
    }
  };

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const filesArray = Array.from(e.target.files) as File[];
      const validFiles = filesArray.filter(f => f.type.startsWith('image/'));
      if (images.length + validFiles.length > 5) {
        alert("Puteți adăuga maxim 5 fotografii.");
        return;
      }
      setImages(prev => [...prev, ...validFiles]);
      validFiles.forEach(file => {
        const reader = new FileReader();
        reader.onloadend = () => setPreviews(prev => [...prev, reader.result as string]);
        reader.readAsDataURL(file);
      });
    }
  };

  const removeImage = (index: number) => {
    setImages(prev => prev.filter((_, i) => i !== index));
    setPreviews(prev => prev.filter((_, i) => i !== index));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!agreedToTerms) return;
    setLoading(true);
    try {
      const result = await createAd({
        title,
        description,
        categories: selectedCategories,
        price: Number(price),
        email,
        phoneNumber,
        location: { county, city, village: village || undefined },
        images,
        duration: selectedDuration.days
      });
      setCreatedAdData({ adId: result.adId });
      setStep('payment');
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const handlePayment = async () => {
    if (!createdAdData || !selectedPlan) return;
    setLoading(true);
    try {
      const session = await startPaymentSession(createdAdData.adId, selectedPlan.id, email);
      if (session.url) {
        window.location.href = session.url;
      } else {
        await simulatePaymentSuccess(createdAdData.adId);
        window.dispatchEvent(new CustomEvent('miculproducator:ad_updated'));
        setStep('success');
      }
    } catch (error) {
      console.error("Payment initiation error:", error);
    } finally {
      setLoading(false);
    }
  };

  if (step === 'success' && createdAdData) {
    return (
      <div className="px-4 py-8 text-center animate-fade-in">
        <div className="mx-auto flex items-center justify-center h-20 w-20 rounded-full bg-emerald-50 mb-6 border border-emerald-100">
          <svg className="h-10 w-10 text-emerald-600" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" /></svg>
        </div>
        <h2 className="text-2xl font-bold text-stone-900 mb-2">Anunț publicat!</h2>
        <p className="text-stone-500 mb-8 text-sm max-w-xs mx-auto leading-relaxed">Verifică emailul pentru link-ul de gestionare și factura Stripe.</p>
        <button 
          className="w-full h-14 bg-stone-900 text-white rounded-xl font-bold uppercase tracking-widest text-xs hover:bg-stone-800 transition-all"
          onClick={() => { if (onClose) onClose(); else onNavigate('/'); }}
        >
          Închide
        </button>
      </div>
    );
  }

  if (step === 'payment') {
    return (
      <div className="px-4 py-8 text-center animate-fade-in">
        <h2 className="text-2xl font-bold text-stone-900 mb-4">Confirmare & Plată</h2>
        <p className="text-stone-500 mb-10 text-sm">Toate plățile sunt securizate prin Stripe Checkout.</p>
        <div className="bg-stone-50 p-8 rounded-[2rem] border border-stone-200 mb-10 text-left">
          <div className="flex justify-between items-center mb-2">
            <span className="text-xs font-bold text-stone-400 uppercase tracking-widest">Plan & Durată</span>
            <span className="font-bold text-stone-800">{selectedPlan?.name} / {selectedDuration.label}</span>
          </div>
          <div className="flex justify-between items-center border-t border-stone-200 pt-6">
            <span className="text-xs font-bold text-stone-400 uppercase tracking-widest">Total de Plată</span>
            <span className="text-3xl font-bold text-emerald-700">{calculateTotalPrice(selectedPlan?.basePrice || 0)} <span className="text-sm">RON</span></span>
          </div>
        </div>
        <button onClick={handlePayment} disabled={loading} className="w-full h-16 bg-stone-900 text-white rounded-2xl font-bold uppercase tracking-widest text-xs hover:bg-stone-800 transition-all flex items-center justify-center gap-3 disabled:opacity-50">
          {loading ? 'Se procesează...' : 'Deschide Stripe Checkout'}
        </button>
      </div>
    );
  }

  if (step === 'plan') {
    return (
      <div className="w-full animate-fade-in">
        <div className="text-center mb-10">
           <h2 className="text-2xl font-bold text-stone-900">Alege Planul de Promovare</h2>
           <p className="text-sm text-stone-400 mt-2">Susține platforma și obține mai mulți clienți.</p>
        </div>

        {/* DURATION SELECTOR */}
        <div className="flex justify-center mb-12">
            <div className="p-1.5 bg-stone-100 rounded-2xl flex gap-1 shadow-inner border border-stone-200/50">
                {DURATIONS.map(d => (
                    <button
                        key={d.days}
                        onClick={() => setSelectedDuration(d)}
                        className={`relative px-5 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${selectedDuration.days === d.days ? 'bg-white text-stone-900 shadow-sm' : 'text-stone-400 hover:text-stone-600'}`}
                    >
                        {d.label}
                        {d.discount > 0 && (
                            <span className="absolute -top-2 -right-1 bg-rose-500 text-white px-1.5 py-0.5 rounded-full text-[7px] border border-white">
                                -{d.discount}%
                            </span>
                        )}
                    </button>
                ))}
            </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          {PLANS.map(plan => {
            const finalPrice = calculateTotalPrice(plan.basePrice);
            return (
              <div 
                key={plan.id} 
                onClick={() => { setSelectedPlan(plan); setStep('form'); }} 
                className={`group relative bg-white border border-stone-100 rounded-[2rem] p-8 cursor-pointer hover:border-emerald-200 hover:shadow-2xl transition-all duration-500 ${plan.id === 'standard' ? 'shadow-xl shadow-emerald-50 ring-1 ring-emerald-50' : ''}`}
              >
                {plan.id === 'standard' && <div className="absolute -top-3 left-1/2 -translate-x-1/2 bg-emerald-500 text-white text-[9px] font-bold px-4 py-1 rounded-full uppercase tracking-widest">Popular</div>}
                <h3 className="text-lg font-bold text-stone-800">{plan.name}</h3>
                <div className="mt-6 flex flex-col">
                  <div className="flex items-baseline">
                    <span className="text-3xl font-bold text-stone-900">{finalPrice}</span>
                    <span className="ml-1 text-stone-400 text-xs font-medium tracking-widest">RON</span>
                  </div>
                  <span className="text-[9px] text-stone-300 font-bold uppercase mt-1">Pentru {selectedDuration.label}</span>
                </div>
                <ul className="mt-8 space-y-4">
                  {plan.features.map((f, i) => (
                    <li key={i} className="flex items-start text-xs text-stone-500 leading-relaxed font-medium">
                      <svg className="h-4 w-4 text-emerald-500 mr-3 flex-shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M5 13l4 4L19 7" /></svg>
                      {f}
                    </li>
                  ))}
                  <li className="flex items-start text-xs text-stone-800 leading-relaxed font-bold">
                    <svg className="h-4 w-4 text-emerald-500 mr-3 flex-shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M12 8v4l3 3" /></svg>
                    Valabilitate: {selectedDuration.label}
                  </li>
                </ul>
                <div className="mt-10 text-center bg-stone-50 text-stone-800 group-hover:bg-stone-900 group-hover:text-white py-4 rounded-xl text-[10px] font-bold uppercase tracking-widest transition-all">Alege Plan</div>
              </div>
            );
          })}
        </div>
      </div>
    );
  }

  return (
    <form onSubmit={handleSubmit} className="space-y-8 animate-fade-in">
      <div className="flex justify-between items-center bg-stone-50 p-4 rounded-2xl border border-stone-100">
          <div className="flex flex-col">
            <span className="text-[9px] font-black text-stone-400 uppercase tracking-widest">Plan & Durată</span>
            <span className="text-xs font-bold text-stone-700">{selectedPlan?.name} / {selectedDuration.label}</span>
          </div>
          <button type="button" onClick={() => setStep('plan')} className="text-[9px] font-black text-emerald-600 uppercase underline">Schimbă</button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <div className="space-y-2">
          <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest ml-1">Titlu Produs</label>
          <input type="text" required value={title} onChange={e => setTitle(e.target.value)} className="w-full bg-stone-50 border border-stone-100 rounded-xl p-4 focus:bg-white focus:border-stone-300 outline-none font-bold text-stone-800 transition-all" placeholder="ex: Miere de Salcâm 2024" />
        </div>
        <div className="space-y-2">
          <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest ml-1">Preț Vânzare (RON)</label>
          <input type="number" required value={price} onChange={e => setPrice(e.target.value)} className="w-full bg-stone-50 border border-stone-100 rounded-xl p-4 focus:bg-white focus:border-stone-300 outline-none font-bold text-stone-800 transition-all" />
        </div>
      </div>

      <div className="space-y-3">
        <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest ml-1">Categorii (Maxim {selectedPlan?.productCount})</label>
        <div className="flex flex-wrap gap-2">
          {PRODUCT_CATEGORIES.map(cat => (
            <button key={cat} type="button" onClick={() => toggleCategory(cat)} className={`px-5 py-2.5 rounded-full text-[10px] font-bold uppercase tracking-widest border transition-all ${selectedCategories.includes(cat) ? 'bg-stone-900 border-stone-900 text-white' : 'bg-white border-stone-100 text-stone-400 hover:border-stone-200'}`}>
              {cat}
            </button>
          ))}
        </div>
      </div>

      <div className="grid grid-cols-2 gap-6">
        <div className="space-y-2">
          <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest ml-1">Județ</label>
          <select value={county} onChange={e => setCounty(e.target.value)} className="w-full bg-stone-50 border border-stone-100 rounded-xl p-4 focus:bg-white outline-none appearance-none cursor-pointer text-sm font-bold text-stone-700" required>
            <option value="">Alege Județ</option>
            {getCounties().map(c => <option key={c} value={c}>{c}</option>)}
          </select>
        </div>
        <div className="space-y-2">
          <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest ml-1">Localitate</label>
          <select value={city} onChange={e => setCity(e.target.value)} disabled={!county} className="w-full bg-stone-50 border border-stone-100 rounded-xl p-4 focus:bg-white outline-none appearance-none cursor-pointer text-sm font-bold text-stone-700 disabled:opacity-40" required>
            <option value="">Alege Localitate</option>
            {availableCities.map(c => <option key={c} value={c}>{c}</option>)}
          </select>
        </div>
      </div>

      <div className="space-y-2">
        <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest ml-1">Descriere Produs</label>
        <textarea required rows={4} value={description} onChange={e => setDescription(e.target.value)} className="w-full bg-stone-50 border border-stone-100 rounded-xl p-4 focus:bg-white focus:border-stone-300 outline-none font-medium text-sm leading-relaxed text-stone-600 transition-all" />
      </div>

      <div className="space-y-4">
        <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest ml-1">Fotografii (Maxim 5)</label>
        <div className="grid grid-cols-3 sm:grid-cols-5 gap-4">
          {previews.map((src, idx) => (
            <div key={idx} className="relative aspect-square rounded-2xl overflow-hidden group border border-stone-100 shadow-sm bg-stone-50">
              <img src={src} className="w-full h-full object-cover" alt="" />
              <button type="button" onClick={() => removeImage(idx)} className="absolute inset-0 bg-stone-900/40 text-white flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>
          ))}
          {previews.length < 5 && (
            <button type="button" onClick={() => fileInputRef.current?.click()} className="aspect-square rounded-2xl border-2 border-dashed border-stone-200 flex flex-col items-center justify-center text-stone-300 hover:border-emerald-300 hover:text-emerald-500 transition-all bg-stone-50 group">
              <svg className="w-8 h-8 mb-1 group-hover:scale-110 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" /></svg>
              <span className="text-[8px] font-bold uppercase tracking-widest">Adaugă Foto</span>
            </button>
          )}
        </div>
        <input type="file" ref={fileInputRef} onChange={handleImageChange} className="hidden" multiple accept="image/*" />
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8 pt-4">
        <div className="space-y-2">
          <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest ml-1">Email pentru factură</label>
          <input type="email" required value={email} onChange={e => setEmail(e.target.value)} className="w-full bg-stone-50 border border-stone-100 rounded-xl p-4 focus:bg-white outline-none font-medium text-stone-700" placeholder="contact@exemplu.ro" />
        </div>
        <div className="space-y-2">
          <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest ml-1">Telefon WhatsApp</label>
          <input type="tel" required value={phoneNumber} onChange={e => setPhoneNumber(e.target.value)} className="w-full bg-stone-50 border border-stone-100 rounded-xl p-4 focus:bg-white outline-none font-medium text-stone-700" placeholder="07xx xxx xxx" />
        </div>
      </div>

      <div className="pt-10 border-t border-stone-100 flex flex-col sm:flex-row items-center justify-between gap-6">
        <div className="flex items-center gap-3">
          <input type="checkbox" id="agreed" checked={agreedToTerms} onChange={e => setAgreedToTerms(e.target.checked)} className="rounded border-stone-300 text-stone-900 focus:ring-stone-900 w-5 h-5 cursor-pointer" required />
          <label htmlFor="agreed" className="text-[11px] text-stone-500 font-medium cursor-pointer">Sunt de acord cu <button type="button" onClick={onOpenTerms} className="text-stone-900 underline">termenii & condițiile</button></label>
        </div>
        <div className="flex gap-4 w-full sm:w-auto">
          <button type="button" onClick={() => setStep('plan')} className="flex-1 px-8 py-4 text-[10px] font-bold uppercase tracking-widest text-stone-400 hover:text-stone-600 transition-colors">Înapoi</button>
          <button type="submit" disabled={loading || !agreedToTerms} className="flex-[2] bg-stone-900 text-white px-10 py-4 rounded-xl text-[10px] font-bold uppercase tracking-[0.2em] hover:bg-stone-800 disabled:opacity-30 shadow-xl shadow-stone-200 transition-all">
            {loading ? 'Se salvează...' : 'Continuă spre Plată'}
          </button>
        </div>
      </div>
    </form>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Button } from '../components/Button';
import { createAd, simulatePaymentSuccess, startPaymentSession } from '../services/mockBackend';
import { getCounties, getCities, getVillages } from '../data/locations';
import { PRODUCT_CATEGORIES } from '../types';

interface CreateAdProps {
  onNavigate: (path: string) => void;
  onClose?: () => void;
  onOpenTerms?: () => void;
  onOpenPrivacy?: () => void;
}

interface Plan {
  id: 'basic' | 'standard' | 'premium';
  name: string;
  productCount: number;
  basePrice: number; // Price for 30 days
  features: string[];
}

const PLANS: Plan[] = [
  {
    id: 'basic',
    name: 'Starter',
    productCount: 1,
    basePrice: 10,
    features: ['Vinde 1 tip de produs', 'Vizibil în 1 Categorie', 'Suport Standard'],
  },
  {
    id: 'standard',
    name: 'Grower',
    productCount: 3,
    basePrice: 20,
    features: ['Vinde până la 3 produse', 'Vizibil în 3 Categorii', 'Recomandat'],
  },
  {
    id: 'premium',
    name: 'Pro Market',
    productCount: 5,
    basePrice: 30,
    features: ['Vinde până la 5 produse', 'Vizibil în 5 Categorii', 'Suport Prioritar'],
  }
];

const DURATIONS = [
  { days: 30, multiplier: 1, discount: 0, label: '30 Zile' },
  { days: 90, multiplier: 3, discount: 5, label: '90 Zile' },
  { days: 180, multiplier: 6, discount: 10, label: '180 Zile' },
  { days: 360, multiplier: 12, discount: 15, label: '360 Zile' },
];

export const CreateAd: React.FC<CreateAdProps> = ({ onNavigate, onClose, onOpenTerms, onOpenPrivacy }) => {
  const [step, setStep] = useState<'plan' | 'form' | 'payment' | 'success'>('plan');
  const [loading, setLoading] = useState(false);

  // Selection State
  const [selectedPlan, setSelectedPlan] = useState<Plan | null>(null);
  const [selectedDuration, setSelectedDuration] = useState(DURATIONS[0]);

  // Form State
  const [title, setTitle] = useState('');
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [price, setPrice] = useState('');
  const [description, setDescription] = useState('');
  const [email, setEmail] = useState('');
  const [phoneNumber, setPhoneNumber] = useState('');
  const [images, setImages] = useState<File[]>([]);
  const [previews, setPreviews] = useState<string[]>([]);
  const [agreedToTerms, setAgreedToTerms] = useState(false);

  // Location State
  const [county, setCounty] = useState('');
  const [city, setCity] = useState('');
  const [village, setVillage] = useState('');
  const [availableCities, setAvailableCities] = useState<string[]>([]);

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (county) {
      setAvailableCities(getCities(county));
      setCity('');
    }
  }, [county]);

  const [createdAdData, setCreatedAdData] = useState<{ adId: string } | null>(null);

  /**
   * BUSINESS LOGIC: Calculate price with specific rounding rules.
   * As requested: 5% of 30 RON = 1.5 -> round to 2 RON discount -> 28 RON unit price.
   */
  const getPricingDetails = (basePrice: number) => {
      const unitDiscount = Math.ceil(basePrice * (selectedDuration.discount / 100));
      const discountedUnitPrice = basePrice - unitDiscount;
      const totalPrice = discountedUnitPrice * selectedDuration.multiplier;
      const totalSavings = (basePrice * selectedDuration.multiplier) - totalPrice;

      return {
          unitPrice: discountedUnitPrice,
          totalPrice,
          savings: totalSavings
      };
  };

  const toggleCategory = (cat: string) => {
    if (!selectedPlan) return;
    if (selectedCategories.includes(cat)) {
      setSelectedCategories(prev => prev.filter(c => c !== cat));
    } else {
      if (selectedCategories.length < selectedPlan.productCount) {
        setSelectedCategories(prev => [...prev, cat]);
      }
    }
  };

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const filesArray = Array.from(e.target.files) as File[];
      const validFiles = filesArray.filter(f => f.type.startsWith('image/'));
      if (images.length + validFiles.length > 5) {
        alert("Puteți adăuga maxim 5 fotografii.");
        return;
      }
      setImages(prev => [...prev, ...validFiles]);
      validFiles.forEach(file => {
        const reader = new FileReader();
        reader.onloadend = () => setPreviews(prev => [...prev, reader.result as string]);
        reader.readAsDataURL(file);
      });
    }
  };

  const removeImage = (index: number) => {
    setImages(prev => prev.filter((_, i) => i !== index));
    setPreviews(prev => prev.filter((_, i) => i !== index));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!agreedToTerms) return;
    setLoading(true);
    try {
      const result = await createAd({
        title,
        description,
        categories: selectedCategories,
        price: Number(price),
        email,
        phoneNumber,
        location: { county, city, village: village || undefined },
        images,
        duration: selectedDuration.days
      });
      setCreatedAdData({ adId: result.adId });
      setStep('payment');
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const handlePayment = async () => {
    if (!createdAdData || !selectedPlan) return;
    setLoading(true);
    try {
      const session = await startPaymentSession(createdAdData.adId, selectedPlan.id, email);
      if (session.url) {
        window.location.href = session.url;
      } else {
        await simulatePaymentSuccess(createdAdData.adId);
        window.dispatchEvent(new CustomEvent('miculproducator:ad_updated'));
        setStep('success');
      }
    } catch (error) {
      console.error("Payment initiation error:", error);
    } finally {
      setLoading(false);
    }
  };

  if (step === 'success' && createdAdData) {
    return (
      <div className="px-4 py-8 text-center animate-fade-in">
        <div className="mx-auto flex items-center justify-center h-20 w-20 rounded-full bg-emerald-50 mb-6 border border-emerald-100">
          <svg className="h-10 w-10 text-emerald-600" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" /></svg>
        </div>
        <h2 className="text-2xl font-bold text-stone-900 mb-2">Anunț publicat!</h2>
        <p className="text-stone-500 mb-8 text-sm max-w-xs mx-auto leading-relaxed">Verifică emailul pentru link-ul de gestionare și factura Stripe.</p>
        <button 
          className="w-full h-14 bg-stone-900 text-white rounded-xl font-bold uppercase tracking-widest text-xs hover:bg-stone-800 transition-all"
          onClick={() => { if (onClose) onClose(); else onNavigate('/'); }}
        >
          Închide
        </button>
      </div>
    );
  }

  if (step === 'payment') {
    const pricing = getPricingDetails(selectedPlan?.basePrice || 0);
    return (
      <div className="px-4 py-8 text-center animate-fade-in">
        <h2 className="text-2xl font-bold text-stone-900 mb-4">Confirmare & Plată</h2>
        <p className="text-stone-500 mb-10 text-sm">Toate plățile sunt securizate prin Stripe Checkout.</p>
        <div className="bg-stone-50 p-8 rounded-[2rem] border border-stone-200 mb-10 text-left">
          <div className="flex justify-between items-center mb-2">
            <span className="text-xs font-bold text-stone-400 uppercase tracking-widest">Plan & Durată</span>
            <span className="font-bold text-stone-800">{selectedPlan?.name} / {selectedDuration.label}</span>
          </div>
          <div className="flex justify-between items-center mb-4">
             <span className="text-xs font-bold text-stone-400 uppercase tracking-widest">Preț Unitar</span>
             <span className="text-sm font-bold text-stone-600">{pricing.unitPrice} RON / lună</span>
          </div>
          <div className="flex justify-between items-center border-t border-stone-200 pt-6">
            <span className="text-xs font-bold text-stone-400 uppercase tracking-widest">Total de Plată</span>
            <span className="text-3xl font-bold text-emerald-700">{pricing.totalPrice} <span className="text-sm">RON</span></span>
          </div>
        </div>
        <button onClick={handlePayment} disabled={loading} className="w-full h-16 bg-stone-900 text-white rounded-2xl font-bold uppercase tracking-widest text-xs hover:bg-stone-800 transition-all flex items-center justify-center gap-3 disabled:opacity-50">
          {loading ? 'Se procesează...' : 'Deschide Stripe Checkout'}
        </button>
      </div>
    );
  }

  if (step === 'plan') {
    return (
      <div className="w-full animate-fade-in">
        <div className="text-center mb-10">
           <h2 className="text-2xl font-bold text-stone-900">Alege Planul de Promovare</h2>
           <p className="text-sm text-stone-400 mt-2">Susține platforma și obține mai mulți clienți prin vizibilitate extinsă.</p>
        </div>

        {/* DURATION SELECTOR */}
        <div className="flex justify-center mb-12">
            <div className="p-1.5 bg-stone-100 rounded-2xl flex gap-1 shadow-inner border border-stone-200/50">
                {DURATIONS.map(d => (
                    <button
                        key={d.days}
                        onClick={() => setSelectedDuration(d)}
                        className={`relative px-5 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${selectedDuration.days === d.days ? 'bg-white text-stone-900 shadow-sm' : 'text-stone-400 hover:text-stone-600'}`}
                    >
                        {d.label}
                        {d.discount > 0 && (
                            <span className="absolute -top-2 -right-1 bg-rose-500 text-white px-1.5 py-0.5 rounded-full text-[7px] border border-white">
                                -{d.discount}%
                            </span>
                        )}
                    </button>
                ))}
            </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          {PLANS.map(plan => {
            const pricing = getPricingDetails(plan.basePrice);
            return (
              <div 
                key={plan.id} 
                onClick={() => { setSelectedPlan(plan); setStep('form'); }} 
                className={`group relative bg-white border border-stone-100 rounded-[2rem] p-8 cursor-pointer hover:border-emerald-200 hover:shadow-2xl transition-all duration-500 flex flex-col ${plan.id === 'standard' ? 'shadow-xl shadow-emerald-50 ring-1 ring-emerald-50' : ''}`}
              >
                {plan.id === 'standard' && <div className="absolute -top-3 left-1/2 -translate-x-1/2 bg-emerald-500 text-white text-[9px] font-bold px-4 py-1 rounded-full uppercase tracking-widest">Popular</div>}

                {pricing.savings > 0 && (
                    <div className="absolute top-8 right-8 bg-rose-50 text-rose-600 px-3 py-1 rounded-lg text-[9px] font-black uppercase tracking-tighter border border-rose-100">
                        Economisești {pricing.savings} RON
                    </div>
                )}

                <h3 className="text-lg font-bold text-stone-800">{plan.name}</h3>

                <div className="mt-6 mb-8">
                  <div className="flex items-baseline gap-1">
                    <span className="text-4xl font-black text-stone-900 tracking-tight">{pricing.totalPrice}</span>
                    <span className="text-stone-400 text-xs font-bold tracking-widest uppercase">RON</span>
                  </div>
                  <div className="mt-1 flex items-center gap-2">
                     <span className="text-[10px] text-stone-500 font-bold uppercase tracking-widest">
                        {pricing.unitPrice} RON / lună
                     </span>
                     {selectedDuration.discount > 0 && (
                        <span className="text-[9px] text-emerald-600 font-black bg-emerald-50 px-1.5 py-0.5 rounded uppercase">
                            Redus
                        </span>
                     )}
                  </div>
                </div>

                <ul className="space-y-4 mb-10 flex-grow">
                  {plan.features.map((f, i) => (
                    <li key={i} className="flex items-start text-xs text-stone-500 leading-relaxed font-medium">
                      <svg className="h-4 w-4 text-emerald-500 mr-3 flex-shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M5 13l4 4L19 7" /></svg>
                      {f}
                    </li>
                  ))}
                  <li className="flex items-start text-xs text-stone-800 leading-relaxed font-bold border-t border-stone-50 pt-4">
                    <svg className="h-4 w-4 text-emerald-500 mr-3 flex-shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M12 8v4l3 3" /></svg>
                    Valabilitate: {selectedDuration.label}
                  </li>
                </ul>

                <div className="text-center bg-stone-50 text-stone-800 group-hover:bg-stone-900 group-hover:text-white py-4 rounded-xl text-[10px] font-bold uppercase tracking-widest transition-all">Alege {plan.name}</div>
              </div>
            );
          })}
        </div>
      </div>
    );
  }

  return (
    <form onSubmit={handleSubmit} className="space-y-8 animate-fade-in">
      <div className="flex justify-between items-center bg-stone-50 p-6 rounded-3xl border border-stone-100">
          <div className="flex flex-col">
            <span className="text-[9px] font-black text-stone-400 uppercase tracking-widest mb-1">Pachet Selectat</span>
            <span className="text-sm font-bold text-stone-700">{selectedPlan?.name} — {selectedDuration.label}</span>
          </div>
          <div className="text-right">
             <span className="block text-[9px] font-black text-stone-400 uppercase tracking-widest mb-1">Total de Plată</span>
             <span className="text-lg font-black text-emerald-700">{getPricingDetails(selectedPlan?.basePrice || 0).totalPrice} RON</span>
             <button type="button" onClick={() => setStep('plan')} className="block text-[9px] font-black text-stone-400 uppercase underline mt-1 hover:text-stone-600 transition-colors">Schimbă Planul</button>
          </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <div className="space-y-2">
          <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest ml-1">Titlu Produs</label>
          <input type="text" required value={title} onChange={e => setTitle(e.target.value)} className="w-full bg-stone-50 border border-stone-100 rounded-xl p-4 focus:bg-white focus:border-stone-300 outline-none font-bold text-stone-800 transition-all" placeholder="ex: Miere de Salcâm 2024" />
        </div>
        <div className="space-y-2">
          <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest ml-1">Preț Vânzare (RON)</label>
          <input type="number" required value={price} onChange={e => setPrice(e.target.value)} className="w-full bg-stone-50 border border-stone-100 rounded-xl p-4 focus:bg-white focus:border-stone-300 outline-none font-bold text-stone-800 transition-all" />
        </div>
      </div>

      <div className="space-y-3">
        <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest ml-1">Categorii (Maxim {selectedPlan?.productCount})</label>
        <div className="flex flex-wrap gap-2">
          {PRODUCT_CATEGORIES.map(cat => (
            <button key={cat} type="button" onClick={() => toggleCategory(cat)} className={`px-5 py-2.5 rounded-full text-[10px] font-bold uppercase tracking-widest border transition-all ${selectedCategories.includes(cat) ? 'bg-stone-900 border-stone-900 text-white' : 'bg-white border-stone-100 text-stone-400 hover:border-stone-200'}`}>
              {cat}
            </button>
          ))}
        </div>
      </div>

      <div className="grid grid-cols-2 gap-6">
        <div className="space-y-2">
          <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest ml-1">Județ</label>
          <select value={county} onChange={e => setCounty(e.target.value)} className="w-full bg-stone-50 border border-stone-100 rounded-xl p-4 focus:bg-white outline-none appearance-none cursor-pointer text-sm font-bold text-stone-700" required>
            <option value="">Alege Județ</option>
            {getCounties().map(c => <option key={c} value={c}>{c}</option>)}
          </select>
        </div>
        <div className="space-y-2">
          <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest ml-1">Localitate</label>
          <select value={city} onChange={e => setCity(e.target.value)} disabled={!county} className="w-full bg-stone-50 border border-stone-100 rounded-xl p-4 focus:bg-white outline-none appearance-none cursor-pointer text-sm font-bold text-stone-700 disabled:opacity-40" required>
            <option value="">Alege Localitate</option>
            {availableCities.map(c => <option key={c} value={c}>{c}</option>)}
          </select>
        </div>
      </div>

      <div className="space-y-2">
        <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest ml-1">Descriere Produs</label>
        <textarea required rows={4} value={description} onChange={e => setDescription(e.target.value)} className="w-full bg-stone-50 border border-stone-100 rounded-xl p-4 focus:bg-white focus:border-stone-300 outline-none font-medium text-sm leading-relaxed text-stone-600 transition-all" placeholder="Metoda de producție, disponibilitate, detalii livrare..." />
      </div>

      <div className="space-y-4">
        <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest ml-1">Fotografii (Maxim 5)</label>
        <div className="grid grid-cols-3 sm:grid-cols-5 gap-4">
          {previews.map((src, idx) => (
            <div key={idx} className="relative aspect-square rounded-2xl overflow-hidden group border border-stone-100 shadow-sm bg-stone-50">
              <img src={src} className="w-full h-full object-cover" alt="" />
              <button type="button" onClick={() => removeImage(idx)} className="absolute inset-0 bg-stone-900/40 text-white flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>
          ))}
          {previews.length < 5 && (
            <button type="button" onClick={() => fileInputRef.current?.click()} className="aspect-square rounded-2xl border-2 border-dashed border-stone-200 flex flex-col items-center justify-center text-stone-300 hover:border-emerald-300 hover:text-emerald-500 transition-all bg-stone-50 group">
              <svg className="w-8 h-8 mb-1 group-hover:scale-110 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" /></svg>
              <span className="text-[8px] font-bold uppercase tracking-widest">Adaugă Foto</span>
            </button>
          )}
        </div>
        <input type="file" ref={fileInputRef} onChange={handleImageChange} className="hidden" multiple accept="image/*" />
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8 pt-4">
        <div className="space-y-2">
          <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest ml-1">Email pentru factură</label>
          <input type="email" required value={email} onChange={e => setEmail(e.target.value)} className="w-full bg-stone-50 border border-stone-100 rounded-xl p-4 focus:bg-white outline-none font-medium text-stone-700" placeholder="contact@exemplu.ro" />
        </div>
        <div className="space-y-2">
          <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest ml-1">Telefon WhatsApp</label>
          <input type="tel" required value={phoneNumber} onChange={e => setPhoneNumber(e.target.value)} className="w-full bg-stone-50 border border-stone-100 rounded-xl p-4 focus:bg-white outline-none font-medium text-stone-700" placeholder="07xx xxx xxx" />
        </div>
      </div>

      <div className="pt-10 border-t border-stone-100 flex flex-col sm:flex-row items-center justify-between gap-6">
        <div className="flex items-center gap-3">
          <input type="checkbox" id="agreed" checked={agreedToTerms} onChange={e => setAgreedToTerms(e.target.checked)} className="rounded border-stone-300 text-stone-900 focus:ring-stone-900 w-5 h-5 cursor-pointer" required />
          <label htmlFor="agreed" className="text-[11px] text-stone-500 font-medium cursor-pointer">Sunt de acord cu <button type="button" onClick={onOpenTerms} className="text-stone-900 underline">termenii & condițiile</button></label>
        </div>
        <div className="flex gap-4 w-full sm:w-auto">
          <button type="button" onClick={() => setStep('plan')} className="flex-1 px-8 py-4 text-[10px] font-bold uppercase tracking-widest text-stone-400 hover:text-stone-600 transition-colors">Înapoi</button>
          <button type="submit" disabled={loading || !agreedToTerms} className="flex-[2] bg-stone-900 text-white px-10 py-4 rounded-xl text-[10px] font-bold uppercase tracking-[0.2em] hover:bg-stone-800 disabled:opacity-30 shadow-xl shadow-stone-200 transition-all">
            {loading ? 'Se salvează...' : 'Continuă spre Plată'}
          </button>
        </div>
      </div>
    </form>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Button } from '../components/Button';
import { createAd, simulatePaymentSuccess, startPaymentSession } from '../services/mockBackend';
import { getCounties, getCities, getVillages } from '../data/locations';
import { PRODUCT_CATEGORIES } from '../types';

interface CreateAdProps {
  onNavigate: (path: string) => void;
  onClose?: () => void;
  onOpenTerms?: () => void;
  onOpenPrivacy?: () => void;
}

interface Plan {
  id: 'basic' | 'standard' | 'premium';
  name: string;
  productCount: number;
  basePrice: number; // Price for 30 days
  features: string[];
}

const PLANS: Plan[] = [
  {
    id: 'basic',
    name: 'Starter',
    productCount: 1,
    basePrice: 10,
    features: ['Vinde 1 tip de produs', 'Vizibil în 1 Categorie', 'Suport Standard'],
  },
  {
    id: 'standard',
    name: 'Grower',
    productCount: 3,
    basePrice: 20,
    features: ['Vinde până la 3 produse', 'Vizibil în 3 Categorii', 'Recomandat'],
  },
  {
    id: 'premium',
    name: 'Pro Market',
    productCount: 5,
    basePrice: 30,
    features: ['Vinde până la 5 produse', 'Vizibil în 5 Categorii', 'Suport Prioritar'],
  }
];

const DURATIONS = [
  { days: 30, multiplier: 1, discount: 0, label: '30 Zile' },
  { days: 90, multiplier: 3, discount: 5, label: '90 Zile' },
  { days: 180, multiplier: 6, discount: 10, label: '180 Zile' },
  { days: 360, multiplier: 12, discount: 15, label: '360 Zile' },
];

export const CreateAd: React.FC<CreateAdProps> = ({ onNavigate, onClose, onOpenTerms, onOpenPrivacy }) => {
  const [step, setStep] = useState<'plan' | 'form' | 'payment' | 'success'>('plan');
  const [loading, setLoading] = useState(false);

  // Selection State
  const [selectedPlan, setSelectedPlan] = useState<Plan | null>(null);
  const [selectedDuration, setSelectedDuration] = useState(DURATIONS[0]);

  // Form State
  const [title, setTitle] = useState('');
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [price, setPrice] = useState('');
  const [description, setDescription] = useState('');
  const [email, setEmail] = useState('');
  const [phoneNumber, setPhoneNumber] = useState('');
  const [images, setImages] = useState<File[]>([]);
  const [previews, setPreviews] = useState<string[]>([]);
  const [agreedToTerms, setAgreedToTerms] = useState(false);

  // Location State
  const [county, setCounty] = useState('');
  const [city, setCity] = useState('');
  const [village, setVillage] = useState('');
  const [availableCities, setAvailableCities] = useState<string[]>([]);

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (county) {
      setAvailableCities(getCities(county));
      setCity('');
    }
  }, [county]);

  const [createdAdData, setCreatedAdData] = useState<{ adId: string } | null>(null);

  /**
   * BUSINESS LOGIC: Calculate price with producer-friendly rounding.
   * Logic: Calculate the discount per month, round that discount UP to the nearest RON, 
   * subtract from base price, then multiply by months.
   */
  const getPricingDetails = (basePrice: number) => {
      if (selectedDuration.discount === 0) {
          return { unitPrice: basePrice, totalPrice: basePrice * selectedDuration.multiplier, savings: 0 };
      }

      const unitDiscount = Math.ceil(basePrice * (selectedDuration.discount / 100));
      const discountedUnitPrice = basePrice - unitDiscount;
      const totalPrice = discountedUnitPrice * selectedDuration.multiplier;
      const totalSavings = (basePrice * selectedDuration.multiplier) - totalPrice;

      return {
          unitPrice: discountedUnitPrice,
          totalPrice,
          savings: totalSavings
      };
  };

  const toggleCategory = (cat: string) => {
    if (!selectedPlan) return;
    if (selectedCategories.includes(cat)) {
      setSelectedCategories(prev => prev.filter(c => c !== cat));
    } else {
      if (selectedCategories.length < selectedPlan.productCount) {
        setSelectedCategories(prev => [...prev, cat]);
      }
    }
  };

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const filesArray = Array.from(e.target.files) as File[];
      const validFiles = filesArray.filter(f => f.type.startsWith('image/'));
      if (images.length + validFiles.length > 5) {
        alert("Puteți adăuga maxim 5 fotografii.");
        return;
      }
      setImages(prev => [...prev, ...validFiles]);
      validFiles.forEach(file => {
        const reader = new FileReader();
        reader.onloadend = () => setPreviews(prev => [...prev, reader.result as string]);
        reader.readAsDataURL(file);
      });
    }
  };

  const removeImage = (index: number) => {
    setImages(prev => prev.filter((_, i) => i !== index));
    setPreviews(prev => prev.filter((_, i) => i !== index));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!agreedToTerms) return;
    setLoading(true);
    try {
      const result = await createAd({
        title,
        description,
        categories: selectedCategories,
        price: Number(price),
        email,
        phoneNumber,
        location: { county, city, village: village || undefined },
        images,
        duration: selectedDuration.days
      });
      setCreatedAdData({ adId: result.adId });
      setStep('payment');
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const handlePayment = async () => {
    if (!createdAdData || !selectedPlan) return;
    setLoading(true);
    try {
      const session = await startPaymentSession(createdAdData.adId, selectedPlan.id, email);
      if (session.url) {
        window.location.href = session.url;
      } else {
        await simulatePaymentSuccess(createdAdData.adId);
        window.dispatchEvent(new CustomEvent('miculproducator:ad_updated'));
        setStep('success');
      }
    } catch (error) {
      console.error("Payment initiation error:", error);
    } finally {
      setLoading(false);
    }
  };

  if (step === 'success' && createdAdData) {
    return (
      <div className="px-4 py-8 text-center animate-fade-in">
        <div className="mx-auto flex items-center justify-center h-20 w-20 rounded-full bg-emerald-50 mb-6 border border-emerald-100">
          <svg className="h-10 w-10 text-emerald-600" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" /></svg>
        </div>
        <h2 className="text-2xl font-bold text-stone-900 mb-2">Anunț publicat!</h2>
        <p className="text-stone-500 mb-8 text-sm max-w-xs mx-auto leading-relaxed">Verifică emailul pentru link-ul de gestionare și factura Stripe.</p>
        <button 
          className="w-full h-14 bg-stone-900 text-white rounded-xl font-bold uppercase tracking-widest text-xs hover:bg-stone-800 transition-all"
          onClick={() => { if (onClose) onClose(); else onNavigate('/'); }}
        >
          Închide
        </button>
      </div>
    );
  }

  if (step === 'payment') {
    const pricing = getPricingDetails(selectedPlan?.basePrice || 0);
    return (
      <div className="px-4 py-8 text-center animate-fade-in">
        <h2 className="text-2xl font-bold text-stone-900 mb-4">Confirmare & Plată</h2>
        <p className="text-stone-500 mb-10 text-sm">Toate plățile sunt securizate prin Stripe Checkout.</p>
        <div className="bg-stone-50 p-8 rounded-[2rem] border border-stone-200 mb-10 text-left">
          <div className="flex justify-between items-center mb-2">
            <span className="text-xs font-bold text-stone-400 uppercase tracking-widest">Plan & Durată</span>
            <span className="font-bold text-stone-800">{selectedPlan?.name} / {selectedDuration.label}</span>
          </div>
          <div className="flex justify-between items-center mb-4">
             <span className="text-xs font-bold text-stone-400 uppercase tracking-widest">Preț Promoțional</span>
             <span className="text-sm font-bold text-stone-600">{pricing.unitPrice} RON / lună</span>
          </div>
          <div className="flex justify-between items-center border-t border-stone-200 pt-6">
            <span className="text-xs font-bold text-stone-400 uppercase tracking-widest">Total de Plată</span>
            <span className="text-3xl font-bold text-emerald-700">{pricing.totalPrice} <span className="text-sm">RON</span></span>
          </div>
        </div>
        <button onClick={handlePayment} disabled={loading} className="w-full h-16 bg-stone-900 text-white rounded-2xl font-bold uppercase tracking-widest text-xs hover:bg-stone-800 transition-all flex items-center justify-center gap-3 disabled:opacity-50">
          {loading ? 'Se procesează...' : 'Deschide Stripe Checkout'}
        </button>
      </div>
    );
  }

  if (step === 'plan') {
    return (
      <div className="w-full animate-fade-in">
        <div className="text-center mb-10">
           <h2 className="text-2xl font-bold text-stone-900">Alege Planul de Promovare</h2>
           <p className="text-sm text-stone-400 mt-2">Alege perioada de valabilitate și beneficiază de reduceri progresive.</p>
        </div>

        {/* DURATION SELECTOR */}
        <div className="flex justify-center mb-12">
            <div className="p-1.5 bg-stone-100 rounded-2xl flex gap-1 shadow-inner border border-stone-200/50">
                {DURATIONS.map(d => (
                    <button
                        key={d.days}
                        onClick={() => setSelectedDuration(d)}
                        className={`relative px-5 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${selectedDuration.days === d.days ? 'bg-white text-stone-900 shadow-sm' : 'text-stone-400 hover:text-stone-600'}`}
                    >
                        {d.label}
                        {d.discount > 0 && (
                            <span className="absolute -top-2 -right-1 bg-rose-500 text-white px-1.5 py-0.5 rounded-full text-[7px] border border-white font-black">
                                -{d.discount}%
                            </span>
                        )}
                    </button>
                ))}
            </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          {PLANS.map(plan => {
            const pricing = getPricingDetails(plan.basePrice);
            return (
              <div 
                key={plan.id} 
                onClick={() => { setSelectedPlan(plan); setStep('form'); }} 
                className={`group relative bg-white border border-stone-100 rounded-[2rem] p-8 cursor-pointer hover:border-emerald-200 hover:shadow-2xl transition-all duration-500 flex flex-col ${plan.id === 'standard' ? 'shadow-xl shadow-emerald-50 ring-1 ring-emerald-50' : ''}`}
              >
                {plan.id === 'standard' && <div className="absolute -top-3 left-1/2 -translate-x-1/2 bg-emerald-500 text-white text-[9px] font-bold px-4 py-1 rounded-full uppercase tracking-widest">Popular</div>}

                {pricing.savings > 0 && (
                    <div className="absolute top-8 right-8 bg-emerald-50 text-emerald-600 px-3 py-1 rounded-lg text-[9px] font-black uppercase tracking-tighter border border-emerald-100">
                        Economisești {pricing.savings} RON
                    </div>
                )}

                <h3 className="text-lg font-bold text-stone-800">{plan.name}</h3>

                <div className="mt-6 mb-8">
                  <div className="flex items-baseline gap-1">
                    <span className="text-4xl font-black text-stone-900 tracking-tight">{pricing.totalPrice}</span>
                    <span className="text-stone-400 text-xs font-bold tracking-widest uppercase">RON</span>
                  </div>
                  <div className="mt-1 flex items-center gap-2">
                     <span className="text-[10px] text-stone-500 font-bold uppercase tracking-widest">
                        {pricing.unitPrice} RON / lună
                     </span>
                     {selectedDuration.discount > 0 && (
                        <span className="text-[9px] text-rose-600 font-black bg-rose-50 px-1.5 py-0.5 rounded uppercase border border-rose-100">
                            Pachet Redus
                        </span>
                     )}
                  </div>
                </div>

                <ul className="space-y-4 mb-10 flex-grow">
                  {plan.features.map((f, i) => (
                    <li key={i} className="flex items-start text-xs text-stone-500 leading-relaxed font-medium">
                      <svg className="h-4 w-4 text-emerald-500 mr-3 flex-shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M5 13l4 4L19 7" /></svg>
                      {f}
                    </li>
                  ))}
                  <li className="flex items-start text-xs text-stone-800 leading-relaxed font-bold border-t border-stone-50 pt-4">
                    <svg className="h-4 w-4 text-emerald-500 mr-3 flex-shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M12 8v4l3 3" /></svg>
                    Valabilitate: {selectedDuration.label}
                  </li>
                </ul>

                <div className="text-center bg-stone-50 text-stone-800 group-hover:bg-stone-900 group-hover:text-white py-4 rounded-xl text-[10px] font-bold uppercase tracking-widest transition-all">Alege {plan.name}</div>
              </div>
            );
          })}
        </div>
      </div>
    );
  }

  return (
    <form onSubmit={handleSubmit} className="space-y-8 animate-fade-in">
      <div className="flex justify-between items-center bg-stone-50 p-6 rounded-3xl border border-stone-100">
          <div className="flex flex-col">
            <span className="text-[9px] font-black text-stone-400 uppercase tracking-widest mb-1">Pachet Selectat</span>
            <span className="text-sm font-bold text-stone-700">{selectedPlan?.name} — {selectedDuration.label}</span>
          </div>
          <div className="text-right">
             <span className="block text-[9px] font-black text-stone-400 uppercase tracking-widest mb-1">Total de Plată</span>
             <span className="text-lg font-black text-emerald-700">{getPricingDetails(selectedPlan?.basePrice || 0).totalPrice} RON</span>
             <button type="button" onClick={() => setStep('plan')} className="block text-[9px] font-black text-stone-400 uppercase underline mt-1 hover:text-stone-600 transition-colors">Schimbă Planul</button>
          </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <div className="space-y-2">
          <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest ml-1">Titlu Produs</label>
          <input type="text" required value={title} onChange={e => setTitle(e.target.value)} className="w-full bg-stone-50 border border-stone-100 rounded-xl p-4 focus:bg-white focus:border-stone-300 outline-none font-bold text-stone-800 transition-all" placeholder="ex: Miere de Salcâm 2024" />
        </div>
        <div className="space-y-2">
          <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest ml-1">Preț Vânzare (RON)</label>
          <input type="number" required value={price} onChange={e => setPrice(e.target.value)} className="w-full bg-stone-50 border border-stone-100 rounded-xl p-4 focus:bg-white focus:border-stone-300 outline-none font-bold text-stone-800 transition-all" />
        </div>
      </div>

      <div className="space-y-3">
        <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest ml-1">Categorii (Maxim {selectedPlan?.productCount})</label>
        <div className="flex flex-wrap gap-2">
          {PRODUCT_CATEGORIES.map(cat => (
            <button key={cat} type="button" onClick={() => toggleCategory(cat)} className={`px-5 py-2.5 rounded-full text-[10px] font-bold uppercase tracking-widest border transition-all ${selectedCategories.includes(cat) ? 'bg-stone-900 border-stone-900 text-white' : 'bg-white border-stone-100 text-stone-400 hover:border-stone-200'}`}>
              {cat}
            </button>
          ))}
        </div>
      </div>

      <div className="grid grid-cols-2 gap-6">
        <div className="space-y-2">
          <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-widest ml-1">Județ</label>
          <select value={county} onChange={e => setCounty(e.target.value)} className="w-full bg-stone-50 border border-stone-100 rounded-xl p-4 focus:bg-white outline-none appearance-none cursor-pointer text-sm font-bold text-stone-700" required>
            <option value="">Alege Județ</option>
