import React, { useState, useEffect, useRef } from 'react';
import { Button } from '../components/Button';
import { createAd, simulatePaymentSuccess, startPaymentSession } from '../services/mockBackend';
import { getCounties, getCities, getVillages } from '../data/locations';
import { PRODUCT_CATEGORIES } from '../types';

interface CreateAdProps {
  onNavigate: (path: string) => void;
  onClose?: () => void;
  onOpenTerms?: () => void;
  onOpenPrivacy?: () => void;
}

interface Plan {
  id: 'basic' | 'standard' | 'premium';
  name: string;
  productCount: number;
  basePrice: number; // Price for 30 days
  features: string[];
}

const PLANS: Plan[] = [
  {
    id: 'basic',
    name: 'Starter',
    productCount: 1,
    basePrice: 10,
    features: ['Vinde 1 tip de produs', 'Vizibil în 1 Categorie', 'Suport Standard'],
  },
  {
    id: 'standard',
    name: 'Grower',
    productCount: 3,
    basePrice: 20,
    features: ['Vinde până la 3 produse', 'Vizibil în 3 Categorii', 'Recomandat'],
  },
  {
    id: 'premium',
    name: 'Pro Market',
    productCount: 5,
    basePrice: 30,
    features: ['Vinde până la 5 produse', 'Vizibil în 5 Categorii', 'Suport Prioritar'],
  }
];

const DURATIONS = [
  { days: 30, multiplier: 1, discount: 0, label: '30 Zile' },
  { days: 90, multiplier: 3, discount: 5, label: '90 Zile' },
  { days: 180, multiplier: 6, discount: 10, label: '180 Zile' },
  { days: 360, multiplier: 12, discount: 15, label: '360 Zile' },
];

export const CreateAd: React.FC<CreateAdProps> = ({ onNavigate, onClose, onOpenTerms, onOpenPrivacy }) => {
  const [step, setStep] = useState<'plan' | 'form' | 'payment' | 'success'>('plan');
  const [loading, setLoading] = useState(false);

  const [selectedPlan, setSelectedPlan] = useState<Plan | null>(null);
  const [selectedDuration, setSelectedDuration] = useState(DURATIONS[0]);

  const [title, setTitle] = useState('');
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [price, setPrice] = useState('');
  const [description, setDescription] = useState('');
  const [email, setEmail] = useState('');
  const [phoneNumber, setPhoneNumber] = useState('');
  const [images, setImages] = useState<File[]>([]);
  const [previews, setPreviews] = useState<string[]>([]);
  const [agreedToTerms, setAgreedToTerms] = useState(false);

  const [county, setCounty] = useState('');
  const [city, setCity] = useState('');
  const [village, setVillage] = useState('');
  const [availableCities, setAvailableCities] = useState<string[]>([]);

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (county) {
      setAvailableCities(getCities(county));
      setCity('');
    }
  }, [county]);

  const [createdAdData, setCreatedAdData] = useState<{ adId: string } | null>(null);

  /**
   * BUSINESS LOGIC: Calculate price with strict rounding rules.
   * Logic: Round the DISCOUNT UP to the next whole number.
   * As requested: 5% of 30 RON = 1.5 -> round to 2 RON reduction -> 28 RON monthly.
   */
  const getPricingDetails = (basePrice: number) => {
      if (selectedDuration.discount === 0) {
          return { unitPrice: basePrice, totalPrice: basePrice * selectedDuration.multiplier, savings: 0 };
      }

      const unitDiscount = Math.ceil(basePrice * (selectedDuration.discount / 100));
      const discountedUnitPrice = basePrice - unitDiscount;
      const totalPrice = discountedUnitPrice * selectedDuration.multiplier;
      const totalSavings = (basePrice * selectedDuration.multiplier) - totalPrice;

      return {
          unitPrice: discountedUnitPrice,
          totalPrice,
          savings: totalSavings
      };
  };

  const toggleCategory = (cat: string) => {
    if (!selectedPlan) return;
    if (selectedCategories.includes(cat)) {
      setSelectedCategories(prev => prev.filter(c => c !== cat));
    } else {
      if (selectedCategories.length < selectedPlan.productCount) {
        setSelectedCategories(prev => [...prev, cat]);
      }
    }
  };

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const filesArray = Array.from(e.target.files) as File[];
      const validFiles = filesArray.filter(f => f.type.startsWith('image/'));
      if (images.length + validFiles.length > 5) {
        alert("Puteți adăuga maxim 5 fotografii.");
        return;
      }
      setImages(prev => [...prev, ...validFiles]);
      validFiles.forEach(file => {
        const reader = new FileReader();
        reader.onloadend = () => setPreviews(prev => [...prev, reader.result as string]);
        reader.readAsDataURL(file);
      });
    }
  };

  const removeImage = (index: number) => {
    setImages(prev => prev.filter((_, i) => i !== index));
    setPreviews(prev => prev.filter((_, i) => i !== index));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!agreedToTerms) return;
    setLoading(true);
    try {
      const result = await createAd({
        title,
        description,
        categories: selectedCategories,
        price: Number(price),
        email,
        phoneNumber,
        location: { county, city, village: village || undefined },
        images,
        duration: selectedDuration.days
      });
      setCreatedAdData({ adId: result.adId });
      setStep('payment');
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const handlePayment = async () => {
    if (!createdAdData || !selectedPlan) return;
    setLoading(true);
    try {
      const session = await startPaymentSession(createdAdData.adId, selectedPlan.id, email);
      if (session.url) {
        window.location.href = session.url;
      } else {
        await simulatePaymentSuccess(createdAdData.adId);
        window.dispatchEvent(new CustomEvent('miculproducator:ad_updated'));
        setStep('success');
      }
    } catch (error) {
      console.error("Payment initiation error:", error);
    } finally {
      setLoading(false);
    }
  };

  if (step === 'success' && createdAdData) {
    return (
      <div className="px-4 py-8 text-center animate-fade-in">
        <div className="mx-auto flex items-center justify-center h-20 w-20 rounded-full bg-emerald-50 mb-6 border border-emerald-100">
          <svg className="h-10 w-10 text-emerald-600" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" /></svg>
        </div>
        <h2 className="text-2xl font-black text-stone-900 mb-2 uppercase">Anunț publicat!</h2>
        <p className="text-stone-500 mb-8 text-sm max-w-xs mx-auto leading-relaxed">Factura și link-ul de management au fost trimise prin email.</p>
        <button 
          className="w-full h-14 bg-stone-900 text-white rounded-2xl font-black uppercase tracking-widest text-xs hover:bg-stone-800 transition-all shadow-xl"
          onClick={() => { if (onClose) onClose(); else onNavigate('/'); }}
        >
          Închide
        </button>
      </div>
    );
  }

  if (step === 'payment') {
    const pricing = getPricingDetails(selectedPlan?.basePrice || 0);
    return (
      <div className="px-4 py-8 text-center animate-fade-in">
        <h2 className="text-2xl font-black text-stone-900 mb-4 uppercase tracking-tight">Confirmare & Plată</h2>
        <p className="text-stone-500 mb-10 text-sm">Toate plățile sunt securizate prin Stripe Checkout.</p>
        <div className="bg-stone-50 p-10 rounded-[2.5rem] border border-stone-200 mb-10 text-left shadow-inner">
          <div className="flex justify-between items-center mb-2">
            <span className="text-[10px] font-black text-stone-400 uppercase tracking-widest">Plan & Durată</span>
            <span className="font-black text-stone-800 uppercase text-xs">{selectedPlan?.name} / {selectedDuration.label}</span>
          </div>
          <div className="flex justify-between items-center mb-6">
             <span className="text-[10px] font-black text-stone-400 uppercase tracking-widest">Preț Promoțional</span>
             <span className="text-xs font-black text-stone-600">{pricing.unitPrice} RON / lună</span>
          </div>
          <div className="flex justify-between items-center border-t border-stone-200 pt-8">
            <span className="text-[10px] font-black text-stone-400 uppercase tracking-widest">Total de Plată</span>
            <span className="text-4xl font-black text-stone-900">{pricing.totalPrice} <span className="text-xs text-stone-400 uppercase">RON</span></span>
          </div>
        </div>
        <button onClick={handlePayment} disabled={loading} className="w-full h-16 bg-stone-900 text-white rounded-[2rem] font-black uppercase tracking-widest text-xs hover:bg-stone-800 transition-all flex items-center justify-center gap-3 disabled:opacity-50 shadow-2xl">
          {loading ? 'Se procesează...' : 'Deschide Stripe Checkout'}
        </button>
      </div>
    );
  }

  if (step === 'plan') {
    return (
      <div className="w-full animate-fade-in">
        <div className="text-center mb-10">
           <h2 className="text-3xl font-black text-stone-900 uppercase tracking-tighter leading-none">Pachete Promovare</h2>
           <p className="text-xs font-bold text-stone-400 mt-3 uppercase tracking-widest">Alege vizibilitatea optimă pentru produsele tale.</p>
        </div>

        {/* DURATION SELECTOR */}
        <div className="flex justify-center mb-12">
            <div className="p-1.5 bg-stone-100 rounded-2xl flex gap-1 shadow-inner border border-stone-200/40">
                {DURATIONS.map(d => (
                    <button
                        key={d.days}
                        onClick={() => setSelectedDuration(d)}
                        className={`relative px-6 py-3.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${selectedDuration.days === d.days ? 'bg-white text-stone-900 shadow-sm' : 'text-stone-400 hover:text-stone-600'}`}
                    >
                        {d.label}
                        {d.discount > 0 && (
                            <span className="absolute -top-2 -right-1 bg-rose-500 text-white px-2 py-0.5 rounded-full text-[7px] border border-white font-black">
                                -{d.discount}%
                            </span>
                        )}
                    </button>
                ))}
            </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
          {PLANS.map(plan => {
            const pricing = getPricingDetails(plan.basePrice);
            return (
              <div 
                key={plan.id} 
                onClick={() => { setSelectedPlan(plan); setStep('form'); }} 
                className={`group relative bg-white border border-stone-200/60 rounded-[2.5rem] p-10 cursor-pointer hover:border-emerald-400 shadow-xl shadow-stone-200/40 hover:shadow-2xl transition-all duration-500 flex flex-col ${plan.id === 'standard' ? 'ring-2 ring-emerald-50' : ''}`}
              >
                {plan.id === 'standard' && <div className="absolute -top-3 left-1/2 -translate-x-1/2 bg-stone-900 text-white text-[8px] font-black px-4 py-1.5 rounded-full uppercase tracking-[0.2em]">Popular</div>}

                {pricing.savings > 0 && (
                    <div className="absolute top-10 right-10 bg-emerald-50 text-emerald-700 px-3 py-1 rounded-lg text-[9px] font-black uppercase tracking-tighter border border-emerald-100">
                        Economisești {pricing.savings} RON
                    </div>
                )}

                <h3 className="text-xl font-black text-stone-900 uppercase tracking-tight">{plan.name}</h3>

                <div className="mt-8 mb-10">
                  <div className="flex items-baseline gap-1.5">
                    <span className="text-5xl font-black text-stone-900 tracking-tighter">{pricing.totalPrice}</span>
                    <span className="text-stone-300 text-sm font-black tracking-widest uppercase">RON</span>
                  </div>
                  <div className="mt-2 flex items-center gap-2">
                     <span className="text-[10px] text-stone-400 font-black uppercase tracking-widest">
                        {pricing.unitPrice} RON / lună
                     </span>
                     {selectedDuration.discount > 0 && (
                        <span className="text-[8px] text-emerald-600 font-black bg-emerald-50 px-2 py-0.5 rounded-full uppercase border border-emerald-100">
                            Preț Redus
                        </span>
                     )}
                  </div>
                </div>

                <ul className="space-y-5 mb-12 flex-grow">
                  {plan.features.map((f, i) => (
                    <li key={i} className="flex items-start text-[11px] text-stone-500 leading-relaxed font-bold uppercase tracking-tight">
                      <svg className="h-4 w-4 text-emerald-500 mr-3 flex-shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>
                      {f}
                    </li>
                  ))}
                </ul>

                <div className="text-center bg-stone-50 text-stone-900 group-hover:bg-stone-900 group-hover:text-white py-5 rounded-[1.5rem] text-[10px] font-black uppercase tracking-[0.2em] transition-all border border-stone-100">Alege Planul</div>
              </div>
            );
          })}
        </div>
      </div>
    );
  }

  return (
    <form onSubmit={handleSubmit} className="space-y-8 animate-fade-in">
      <div className="flex justify-between items-center bg-stone-50 p-8 rounded-[2rem] border border-stone-100 shadow-inner">
          <div className="flex flex-col">
            <span className="text-[9px] font-black text-stone-400 uppercase tracking-widest mb-1">Pachet Selectat</span>
            <span className="text-xs font-black text-stone-800 uppercase">{selectedPlan?.name} — {selectedDuration.label}</span>
          </div>
          <div className="text-right">
             <span className="block text-[9px] font-black text-stone-400 uppercase tracking-widest mb-1">Total de Plată</span>
             <span className="text-2xl font-black text-stone-900 tracking-tighter">{getPricingDetails(selectedPlan?.basePrice || 0).totalPrice} RON</span>
             <button type="button" onClick={() => setStep('plan')} className="block text-[9px] font-black text-emerald-600 uppercase underline mt-1.5 hover:text-emerald-700 transition-colors">Modifică Plan</button>
          </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <div className="space-y-2">
          <label className="block text-[10px] font-black text-stone-400 uppercase tracking-widest ml-1">Titlu Produs</label>
          <input type="text" required value={title} onChange={e => setTitle(e.target.value)} className="w-full bg-stone-50 border border-stone-100 rounded-2xl p-5 focus:bg-white focus:border-stone-400 outline-none font-black text-stone-800 transition-all uppercase text-xs" placeholder="ex: MIERE DE SALCÂM 2024" />
        </div>
        <div className="space-y-2">
          <label className="block text-[10px] font-black text-stone-400 uppercase tracking-widest ml-1">Preț Vânzare (RON)</label>
          <input type="number" required value={price} onChange={e => setPrice(e.target.value)} className="w-full bg-stone-50 border border-stone-100 rounded-2xl p-5 focus:bg-white focus:border-stone-400 outline-none font-black text-stone-800 transition-all" />
        </div>
      </div>

      <div className="space-y-3">
        <label className="block text-[10px] font-black text-stone-400 uppercase tracking-widest ml-1">Categorii Produse (Maxim {selectedPlan?.productCount})</label>
        <div className="flex flex-wrap gap-2.5">
          {PRODUCT_CATEGORIES.map(cat => (
            <button key={cat} type="button" onClick={() => toggleCategory(cat)} className={`px-6 py-3 rounded-full text-[9px] font-black uppercase tracking-widest border-2 transition-all ${selectedCategories.includes(cat) ? 'bg-stone-900 border-stone-900 text-white' : 'bg-white border-stone-100 text-stone-400 hover:border-stone-300'}`}>
              {cat}
            </button>
          ))}
        </div>
      </div>

      <div className="grid grid-cols-2 gap-6">
        <div className="space-y-2">
          <label className="block text-[10px] font-black text-stone-400 uppercase tracking-widest ml-1">Județ</label>
          <select value={county} onChange={e => setCounty(e.target.value)} className="w-full bg-stone-50 border border-stone-100 rounded-2xl p-5 focus:bg-white outline-none appearance-none cursor-pointer text-xs font-black text-stone-800 uppercase" required>
            <option value="">Alege Județ</option>
            {getCounties().map(c => <option key={c} value={c}>{c}</option>)}
          </select>
        </div>
        <div className="space-y-2">
          <label className="block text-[10px] font-black text-stone-400 uppercase tracking-widest ml-1">Localitate</label>
          <select value={city} onChange={e => setCity(e.target.value)} disabled={!county} className="w-full bg-stone-50 border border-stone-100 rounded-2xl p-5 focus:bg-white outline-none appearance-none cursor-pointer text-xs font-black text-stone-800 uppercase disabled:opacity-40" required>
            <option value="">Alege Localitate</option>
            {availableCities.map(c => <option key={c} value={c}>{c}</option>)}
          </select>
        </div>
      </div>

      <div className="space-y-2">
        <label className="block text-[10px] font-black text-stone-400 uppercase tracking-widest ml-1">Descriere Detaliată</label>
        <textarea required rows={5} value={description} onChange={e => setDescription(e.target.value)} className="w-full bg-stone-50 border border-stone-100 rounded-2xl p-6 focus:bg-white focus:border-stone-400 outline-none font-medium text-sm leading-relaxed text-stone-600 transition-all" placeholder="Metoda de producție, disponibilitatea și detaliile de livrare..." />
      </div>

      <div className="space-y-5">
        <label className="block text-[10px] font-black text-stone-400 uppercase tracking-widest ml-1">Galerie Foto (Maxim 5)</label>
        <div className="grid grid-cols-3 sm:grid-cols-5 gap-5">
          {previews.map((src, idx) => (
            <div key={idx} className="relative aspect-square rounded-[1.5rem] overflow-hidden group border border-stone-200 shadow-sm bg-stone-50">
              <img src={src} className="w-full h-full object-cover" alt="" />
              <button type="button" onClick={() => removeImage(idx)} className="absolute inset-0 bg-stone-900/60 text-white flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>
          ))}
          {previews.length < 5 && (
            <button type="button" onClick={() => fileInputRef.current?.click()} className="aspect-square rounded-[1.5rem] border-2 border-dashed border-stone-300 flex flex-col items-center justify-center text-stone-300 hover:border-emerald-400 hover:text-emerald-500 transition-all bg-stone-50 group">
              <svg className="w-8 h-8 mb-1.5 group-hover:scale-110 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M12 4v16m8-8H4" /></svg>
              <span className="text-[8px] font-black uppercase tracking-widest">Încarcă</span>
            </button>
          )}
        </div>
        <input type="file" ref={fileInputRef} onChange={handleImageChange} className="hidden" multiple accept="image/*" />
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8 pt-6">
        <div className="space-y-2">
          <label className="block text-[10px] font-black text-stone-400 uppercase tracking-widest ml-1">Email Gospodar (pentru factură)</label>
          <input type="email" required value={email} onChange={e => setEmail(e.target.value)} className="w-full bg-stone-50 border border-stone-100 rounded-2xl p-5 focus:bg-white outline-none font-bold text-stone-800 text-xs" placeholder="email@exemplu.ro" />
        </div>
        <div className="space-y-2">
          <label className="block text-[10px] font-black text-stone-400 uppercase tracking-widest ml-1">Telefon WhatsApp</label>
          <input type="tel" required value={phoneNumber} onChange={e => setPhoneNumber(e.target.value)} className="w-full bg-stone-50 border border-stone-100 rounded-2xl p-5 focus:bg-white outline-none font-bold text-stone-800 text-xs" placeholder="07XX XXX XXX" />
        </div>
      </div>

      <div className="pt-12 border-t border-stone-200 flex flex-col sm:flex-row items-center justify-between gap-8">
        <div className="flex items-center gap-4">
          <input type="checkbox" id="agreed" checked={agreedToTerms} onChange={e => setAgreedToTerms(e.target.checked)} className="rounded-lg border-stone-300 text-stone-900 focus:ring-stone-900 w-6 h-6 cursor-pointer shadow-sm" required />
          <label htmlFor="agreed" className="text-[11px] text-stone-500 font-bold cursor-pointer uppercase tracking-tight">Sunt de acord cu <button type="button" onClick={onOpenTerms} className="text-stone-900 underline">termenii & condițiile</button></label>
        </div>
        <div className="flex gap-4 w-full sm:w-auto">
          <button type="button" onClick={() => setStep('plan')} className="flex-1 px-10 py-5 text-[10px] font-black uppercase tracking-[0.2em] text-stone-400 hover:text-stone-900 transition-colors">Înapoi</button>
          <button type="submit" disabled={loading || !agreedToTerms} className="flex-[2] bg-stone-900 text-white px-12 py-5 rounded-2xl text-[10px] font-black uppercase tracking-[0.2em] hover:bg-stone-800 disabled:opacity-30 shadow-2xl transition-all">
            {loading ? 'Procesare...' : 'Spre Plată'}
          </button>
        </div>
      </div>
    </form>
  );
};

import React, { useState } from 'react';
import { Ad } from '../types';

interface AdCardProps {
  ad: Ad;
  onClick: () => void;
  isFavorite: boolean;
  onToggleFavorite: (e: React.MouseEvent | React.KeyboardEvent) => void;
  mini?: boolean; 
  priority?: boolean;
  showRouteContext?: boolean;
  routePosition?: number;
}

export const AdCard: React.FC<AdCardProps> = ({ 
    ad, 
    onClick, 
    isFavorite, 
    onToggleFavorite, 
    mini = false, 
    showRouteContext = false,
    routePosition
}) => {
  const isBio = ad.title.toLowerCase().includes('bio') || ad.description.toLowerCase().includes('natural');
  const [imageLoaded, setImageLoaded] = useState(false);

  const primaryCategory = ad.categories[0] || 'Produs';
  const showRating = ad.rating > 0;

  // Mocked detour time for professional travel feel
  const mockDetourTime = Math.floor(Math.random() * 8) + 2; 

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' || e.key === ' ') {
      e.preventDefault();
      onClick();
    }
  };

  const mapsLink = `https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(`${ad.title} ${ad.location.city} ${ad.location.county} Romania`)}`;

  if (mini) {
    return (
      <div 
        onClick={onClick}
        className={`group bg-white rounded-xl border overflow-hidden hover:shadow-lg cursor-pointer flex flex-col h-full relative transition-all ${ad.isPremium ? 'border-amber-100' : 'border-stone-100'}`}
      >
        <div className="relative h-32 w-full bg-stone-50">
           {!imageLoaded && <div className="absolute inset-0 bg-stone-100 animate-pulse z-10" />}
           <img 
              src={ad.images[0] || 'https://via.placeholder.com/400x300?text=Fără+Imagine'} 
              alt=""
              className={`w-full h-full object-cover transition-all duration-500 group-hover:scale-105 ${imageLoaded ? 'opacity-100' : 'opacity-0'}`}
              onLoad={() => setImageLoaded(true)}
            />
           <div className="absolute bottom-1.5 right-1.5 z-20">
             <span className="px-2 py-0.5 rounded-md text-[10px] font-black bg-stone-900 text-white shadow-md border border-stone-800">
               {ad.price} RON
             </span>
           </div>
        </div>
        <div className="p-3">
          <h4 className="text-[11px] font-bold text-stone-900 line-clamp-1 flex items-center gap-1 uppercase tracking-tight">
            {ad.title}
          </h4>
        </div>
      </div>
    );
  }

  return (
    <div 
      onClick={onClick}
      onKeyDown={handleKeyDown}
      role="button"
      tabIndex={0}
      className={`group bg-white rounded-2xl border transition-all duration-500 cursor-pointer flex flex-col h-full relative ${
        ad.isPremium 
          ? 'border-amber-200/60 shadow-xl shadow-amber-50 hover:border-amber-300' 
          : 'border-stone-100 shadow-sm hover:shadow-xl hover:shadow-stone-200/50 hover:border-stone-200 hover:-translate-y-1'
      }`}
    >
      <div className="relative h-64 w-full overflow-hidden bg-stone-50 rounded-t-2xl">
        {!imageLoaded && <div className="absolute inset-0 bg-stone-100 animate-pulse z-10" />}
        <img 
          src={ad.images[0] || 'https://via.placeholder.com/400x300?text=Fără+Imagine'} 
          alt=""
          className={`w-full h-full object-cover transform group-hover:scale-105 transition-all duration-700 ease-out ${imageLoaded ? 'opacity-100' : 'opacity-0'}`}
          onLoad={() => setImageLoaded(true)}
        />

        {/* Route Context Overlay - Frosted Glass Aesthetic */}
        {showRouteContext && typeof routePosition === 'number' && (
            <div className="absolute bottom-3 left-3 right-3 bg-white/70 backdrop-blur-md border border-white/50 p-3 rounded-xl z-20 shadow-sm flex items-center justify-between">
                <div className="flex items-center gap-2">
                    <div className="w-6 h-6 rounded-lg bg-stone-800 text-white flex items-center justify-center text-[10px] font-bold shadow-sm">
                        {routePosition + 1}
                    </div>
                    <span className="text-[9px] font-bold uppercase tracking-[0.2em] text-stone-700">Oprire pe rută</span>
                </div>
                <div className="flex items-center gap-1">
                    <svg className="w-3 h-3 text-stone-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M12 8v4l3 3" /></svg>
                    <span className="text-[9px] font-bold text-stone-500 uppercase tracking-tighter">+{mockDetourTime} min</span>
                </div>
            </div>
        )}

        {/* Top Badges - Refined & Minimal */}
        <div className="absolute top-3 left-3 flex flex-col space-y-1.5 items-start z-20">
           <div className="flex items-center gap-1.5">
             <span className="inline-flex items-center px-2.5 py-1 rounded-lg text-[8px] font-bold bg-white/90 text-stone-600 shadow-sm backdrop-blur-sm uppercase tracking-widest border border-white/20">
               {primaryCategory}
             </span>
             {ad.isPremium && (
               <span className="inline-flex items-center px-2.5 py-1 rounded-lg text-[8px] font-bold bg-amber-50 text-amber-700 shadow-sm uppercase tracking-widest border border-amber-100">
                 Prioritar
               </span>
             )}
           </div>
           {isBio && (
             <span className="inline-flex items-center px-2.5 py-1 rounded-lg text-[8px] font-bold bg-emerald-50 text-emerald-700 shadow-sm uppercase tracking-widest border border-emerald-100">
               Eco / Natural
             </span>
           )}
        </div>

        {/* Actions Overlay */}
        <div className="absolute top-3 right-3 flex flex-col gap-1.5 z-20">
            <button
                onClick={(e) => { e.stopPropagation(); onToggleFavorite(e); }}
                className="p-2.5 rounded-xl bg-white/90 backdrop-blur-md shadow-sm border border-white/50 text-stone-400 hover:text-rose-500 hover:bg-white transition-all transform active:scale-90"
                title="Adaugă la favorite"
            >
                <svg className={`w-4 h-4 ${isFavorite ? 'fill-current' : ''}`} xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M20.84 4.61a5.5 5.5 0 0 0-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 0 0-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 0 0 0-7.78z"></path></svg>
            </button>

            {showRouteContext && (
                <a
                    href={mapsLink}
                    target="_blank"
                    rel="noreferrer"
                    onClick={(e) => e.stopPropagation()}
                    className="p-2.5 rounded-xl bg-white/90 backdrop-blur-md shadow-sm border border-white/50 text-stone-400 hover:text-emerald-600 hover:bg-white transition-all transform active:scale-90"
