  // NAVIGATION: Uses hash-based routing (#/) to ensure SPA works across all hosting providers.
  const [currentPath, setCurrentPath] = useState(window.location.hash || '#/');

  // MODAL STATES: Controlled at root to allow them to be opened from anywhere in the tree.
  const [isCreateModalOpen, setIsCreateModalOpen] = useState(false);
  const [isTermsModalOpen, setIsTermsModalOpen] = useState(false);
  const [isPrivacyModalOpen, setIsPrivacyModalOpen] = useState(false);

  // SELECTED AD: Used when opening the Ad Details modal from the Home grid.
  const [selectedAd, setSelectedAd] = useState<Ad | null>(null);

  // SHARED STATE: Favorites and Toasts are managed globally for cross-page consistency.
  const [toasts, setToasts] = useState<ToastMessage[]>([]);
  const [favorites, setFavorites] = useState<string[]>([]);
  const [notifications, setNotifications] = useState<AppNotification[]>([]);
  const [showNotifDropdown, setShowNotifDropdown] = useState(false);
  const notifDropdownRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    // Initial load of favorites from client storage
    const saved = localStorage.getItem('miculproducator_favorites');
    if (saved) setFavorites(JSON.parse(saved));
    loadNotifications();

    // Event listener for backend changes to trigger notification refreshes
    const handleNotifUpdate = () => loadNotifications();
    window.addEventListener('miculproducator:notifications_updated', handleNotifUpdate);

    // Outside click detection for the Notification dropdown UI
    const handleClickOutside = (event: MouseEvent) => {
        if (notifDropdownRef.current && !notifDropdownRef.current.contains(event.target as Node)) {
            setShowNotifDropdown(false);
        }
    };
    document.addEventListener('mousedown', handleClickOutside);

    return () => {
        window.removeEventListener('miculproducator:notifications_updated', handleNotifUpdate);
        document.removeEventListener('mousedown', handleClickOutside);
    };
  }, []);

  const loadNotifications = async () => {
      const data = await fetchNotifications();
      setNotifications(data);
  };

  /** Global feedback system for user actions */
  const addToast = (type: ToastType, message: string) => {
    const id = Math.random().toString(36).substr(2, 9);
    setToasts((prev) => [...prev, { id, type, message }]);
  };

  const removeToast = (id: string) => {
    setToasts((prev) => prev.filter((t) => t.id !== id));
  };

  /** Handles the addition/removal of ads to local wishlist */
  const handleToggleFavorite = (id: string) => {
    let newFavs: string[];
    if (favorites.includes(id)) {
      newFavs = favorites.filter(fav => fav !== id);
      addToast('info', 'Eliminat de la favorite');
    } else {
      newFavs = [...favorites, id];
      addToast('success', 'Adăugat la favorite');
    }
    setFavorites(newFavs);
    localStorage.setItem('miculproducator_favorites', JSON.stringify(newFavs));
  };

  /** Centralized navigation handler */
  const navigate = (path: string) => {
    window.location.hash = path;
    window.scrollTo(0, 0);
  };

  /** Syncs internal state with browser URL changes */
  useEffect(() => {
    const handleHashChange = () => setCurrentPath(window.location.hash || '#/');
    window.addEventListener('hashchange', handleHashChange);
    return () => window.removeEventListener('hashchange', handleHashChange);
  }, []);

  /** 
   * ROUTER SWITCH
   * Determines which page to render based on the URL hash.
   */
  const renderRoute = () => {
    const path = currentPath.replace('#', '');
    const cleanPath = path.split('?')[0];

    // Home Route
    if (cleanPath === '/' || cleanPath === '') {
      return (
        <Home 
          onNavigate={navigate} 
          onOpenCreateModal={() => setIsCreateModalOpen(true)}
          onAdClick={(ad) => setSelectedAd(ad)}
          favoriteIds={favorites}
          onToggleFavorite={handleToggleFavorite}
          onAddToast={addToast}
        />
      );
    }

    // Platform Administration
    if (cleanPath === '/adminAccess') return <Admin onNavigate={navigate} />;

    // Post-checkout landing page
    if (cleanPath === '/payment-success') return <PaymentSuccess onNavigate={navigate} />;

    // Seller Management Route: #/manage/ID/TOKEN
    if (cleanPath.startsWith('/manage/')) {
      const parts = cleanPath.split('/');
      const id = parts[2];
      const token = parts[3];
      if (id && token) {
        return <ManageAd id={id} token={token} onNavigate={navigate} />;
      }
    }

    // Direct link to an ad listing
    if (cleanPath.startsWith('/ad/')) {
      const id = cleanPath.split('/ad/')[1];
      return (
        <AdDetails 
          id={id} 
          onNavigate={navigate} 
          isFavorite={favorites.includes(id)}
          onToggleFavorite={() => handleToggleFavorite(id)}
          onAddToast={addToast}
        />
      );
    }

    return (
      <div className="p-24 text-center animate-fade-in">
        <h2 className="text-4xl font-black text-stone-200 mb-4">404</h2>
        <p className="text-stone-400 font-medium mb-8">Pagina nu a fost găsită</p>
        <button onClick={() => navigate('/')} className="text-emerald-600 font-bold uppercase tracking-widest text-xs border-b-2 border-emerald-100 pb-1">Înapoi la Acasă</button>
      </div>
    );
  };

  const unreadCount = notifications.filter(n => !n.isRead).length;

  return (
    <div className="min-h-screen flex flex-col font-sans text-stone-800">
      <header className="bg-white/80 backdrop-blur-md sticky top-0 z-30 border-b border-stone-100">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-24 items-center">
            {/* BRANDING */}
            <div className="flex flex-col cursor-pointer group" onClick={() => navigate('/')}>
              <span className="text-xl font-bold text-stone-900 tracking-tight transition-colors group-hover:text-emerald-700 leading-none">
                MiculProducator
              </span>
              <span className="text-[9px] font-bold uppercase tracking-[0.15em] bg-gradient-to-r from-blue-700 via-yellow-500 to-red-600 bg-clip-text text-transparent mt-1.5 transition-all group-hover:opacity-80">
                Din Dragoste Si Pasiune Pentru Romania
              </span>
            </div>

            <div className="flex items-center space-x-4">
              <div className="relative" ref={notifDropdownRef}>
                  <button onClick={() => setShowNotifDropdown(!showNotifDropdown)} className="p-2 rounded-xl text-stone-400 hover:bg-stone-50 hover:text-stone-600 transition-all relative">
                      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 17h5l-1.405-1.405A2.032 2.032 0 0118 14.158V11a6.002 6.002 0 00-4-5.659V5a2 2 0 10-4 0v.341C7.67 6.165 6 8.388 6 11v3.159c0 .538-.214 1.055-.595 1.436L4 17h5m6 0v1a3 3 0 11-6 0v-1m6 0H9" /></svg>
                      {unreadCount > 0 && <span className="absolute top-2 right-2 block h-2 w-2 rounded-full bg-rose-500 ring-2 ring-white"></span>}
                  </button>
                  {showNotifDropdown && (
                      <div className="absolute right-0 mt-3 w-80 bg-white rounded-2xl shadow-xl shadow-stone-200/50 z-50 border border-stone-100 animate-scale-in">
                          <div className="py-3 px-5 bg-stone-50/50 border-b border-stone-100 flex justify-between items-center text-[10px] font-bold uppercase tracking-widest text-stone-400">
                              <span>Notificări</span>
                              <button onClick={async () => { await clearAllNotifications(); loadNotifications(); }} className="text-emerald-600 hover:underline">Șterge tot</button>
                          </div>
                          <div className="max-h-96 overflow-y-auto">
                              {notifications.length === 0 ? <div className="p-8 text-center text-xs text-stone-400 italic">Nicio notificare momentan.</div> : 
                                notifications.map(n => (
                                  <div key={n.id} className={`px-5 py-4 border-b border-stone-50 text-sm cursor-pointer hover:bg-stone-50 transition-colors ${!n.isRead ? 'bg-emerald-50/30' : ''}`}>
                                    <p className="font-bold text-stone-800">{n.title}</p>
                                    <p className="text-xs text-stone-500 mt-1 line-clamp-2 leading-relaxed">{n.message}</p>
                                  </div>
                                ))
                              }
                          </div>
                      </div>
                  )}
              </div>
              <button onClick={() => setIsCreateModalOpen(true)} className="px-6 py-2.5 text-xs font-bold uppercase tracking-widest rounded-xl shadow-sm text-white bg-stone-900 hover:bg-stone-800 transition-all hover:scale-[1.02] active:scale-95">
                Adaugă Anunț
              </button>
            </div>
          </div>
        </div>
      </header>

      <main className="flex-grow">{renderRoute()}</main>

      <footer className="bg-stone-50 border-t border-stone-200/60 pt-16 pb-12">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-12 mb-16">
            <div className="space-y-6">
              <span className="text-lg font-bold text-stone-900 tracking-tight">MiculProducator</span>
              <p className="text-xs text-stone-500 leading-relaxed max-w-xs">
                Susținem producătorii locali prin tehnologie intuitivă, conectând gospodăriile autentice cu consumatorii moderni.
              </p>
              <div className="flex gap-4">
                <a href="#" target="_blank" rel="noreferrer" className="w-10 h-10 rounded-xl bg-white border border-stone-200 flex items-center justify-center text-stone-500 hover:text-emerald-600 hover:border-emerald-200 hover:shadow-sm transition-all" aria-label="Facebook">
                  <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 24 24"><path d="M24 12.073c0-6.627-5.373-12-12-12s-12 5.373-12 12c0 5.99 4.388 10.954 10.125 11.854v-8.385H7.078v-3.47h3.047V9.43c0-3.007 1.792-4.669 4.533-4.669 1.312 0 2.686.235 2.686.235v2.953H15.83c-1.491 0-1.956.925-1.956 1.874v2.25h3.328l-.532 3.47h-2.796v8.385C19.612 23.027 24 18.062 24 12.073z"/></svg>
                </a>
                <a href="#" target="_blank" rel="noreferrer" className="w-10 h-10 rounded-xl bg-white border border-stone-200 flex items-center justify-center text-stone-500 hover:text-emerald-600 hover:border-emerald-200 hover:shadow-sm transition-all" aria-label="Instagram">
                  <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 24 24"><path d="M12 2.163c3.204 0 3.584.012 4.85.07 3.252.148 4.771 1.691 4.919 4.919.058 1.265.069 1.645.069 4.849 0 3.205-.012 3.584-.069 4.849-.149 3.225-1.664 4.771-4.919 4.919-1.266.058-1.644.07-4.85.07-3.204 0-3.584-.012-4.849-.07-3.26-.149-4.771-1.699-4.919-4.92-.058-1.265-.07-1.644-.07-4.849 0-3.204.013-3.583.07-4.849.149-3.227 1.664-4.771 4.919-4.919 1.266-.057 1.645-.069 4.849-.069zm0-2.163c-3.259 0-3.667.014-4.947.072-4.358.2-6.78 2.618-6.98 6.98-.059 1.281-.073 1.689-.073 4.948 0 3.259.014 3.668.072 4.948.2 4.358 2.618 6.78 6.98 6.98 1.281.058 1.689.072 4.948.072 3.259 0 3.668-.014 4.948-.072 4.354-.2 6.782-2.618 6.979-6.98.059-1.28.073-1.689.073-4.948 0-3.259-.014-3.667-.072-4.947-.196-4.354-2.617-6.78-6.979-6.98-1.281-.059-1.69-.073-4.949-.073zm0 5.838c-3.403 0-6.162 2.759-6.162 6.162s2.759 6.163 6.162 6.163 6.162-2.759 6.162-6.163c0-3.403-2.759-6.162-6.162-6.162zm0 10.162c-2.209 0-4-1.79-4-4 0-2.209 1.791-4 4-4s4 1.791 4 4c0 2.21-1.791 4-4 4zm6.406-11.845c-.796 0-1.441.645-1.441 1.44s.645 1.44 1.441 1.44c.795 0 1.439-.645 1.439-1.44s-.644-1.44-1.439-1.44z"/></svg>
                </a>
                <a href="#" target="_blank" rel="noreferrer" className="w-10 h-10 rounded-xl bg-white border border-stone-200 flex items-center justify-center text-stone-500 hover:text-emerald-600 hover:border-emerald-200 hover:shadow-sm transition-all" aria-label="LinkedIn">
                  <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 24 24"><path d="M19 0h-14c-2.761 0-5 2.239-5 5v14c0 2.761 2.239 5 5 5h14c2.762 0 5-2.239 5-5v-14c0-2.761-2.238-5-5-5zm-11 19h-3v-11h3v11zm-1.5-12.268c-.966 0-1.75-.79-1.75-1.764s.784-1.764 1.75-1.764 1.75.79 1.75 1.764-.783 1.764-1.75 1.764zm13.5 12.268h-3v-5.604c0-3.368-4-3.113-4 0v5.604h-3v-11h3v1.765c1.396-2.586 7-2.777 7 2.476v6.759z"/></svg>
                </a>
              </div>
            </div>

            <div className="space-y-6">
              <h4 className="text-[10px] font-bold text-stone-400 uppercase tracking-[0.2em]">Navigație</h4>
              <ul className="space-y-3 text-xs text-stone-600 font-medium">
                <li><button onClick={() => navigate('/')} className="hover:text-emerald-700 transition-colors">Acasă</button></li>
                <li><button onClick={() => setIsTermsModalOpen(true)} className="hover:text-emerald-700 transition-colors">Termeni și Condiții</button></li>
                <li><button onClick={() => setIsPrivacyModalOpen(true)} className="hover:text-emerald-700 transition-colors">Confidențialitate</button></li>
              </ul>
            </div>

            <div className="space-y-6">
              <h4 className="text-[10px] font-bold text-stone-400 uppercase tracking-[0.2em]">Contact Platformă</h4>
              <p className="text-xs text-stone-600 leading-relaxed">
                Ești producător și ai nevoie de suport tehnic?<br/>
                <a href="mailto:suport@miculproducator.ro" className="text-emerald-600 hover:underline font-bold">suport@miculproducator.ro</a>
              </p>
              <p className="text-[9px] font-bold text-stone-300 uppercase tracking-widest leading-loose">
                 Made with passion<br/>for Romanian heritage.
              </p>
            </div>
          </div>

          <div className="border-t border-stone-200 pt-8 flex flex-col md:flex-row justify-between items-center gap-4">
            <p className="text-[9px] font-bold text-stone-400 uppercase tracking-[0.2em]">
              &copy; {new Date().getFullYear()} MiculProducator. Digitalizing Tradition.
            </p>
            <div className="flex gap-6 text-[9px] font-bold text-stone-300 uppercase tracking-[0.2em]">
               <span>Sustenabil</span>
               <span>Local</span>
               <span>Transparent</span>
            </div>
          </div>
        </div>
      </footer>

      {/* MODALS */}
      <Modal isOpen={isCreateModalOpen} onClose={() => setIsCreateModalOpen(false)} title="Publică un Anunț Nou">
        <CreateAd 
          onNavigate={navigate} 
          onClose={() => setIsCreateModalOpen(false)} 
          onOpenTerms={() => setIsTermsModalOpen(true)}
          onOpenPrivacy={() => setIsPrivacyModalOpen(true)}
        />
      </Modal>

      <Modal isOpen={isTermsModalOpen} onClose={() => setIsTermsModalOpen(false)} title="Termeni și Condiții">
        <Terms />
      </Modal>

      <Modal isOpen={isPrivacyModalOpen} onClose={() => setIsPrivacyModalOpen(false)} title="Politică de Confidențialitate">
        <Privacy />
      </Modal>

      <Modal isOpen={!!selectedAd} onClose={() => setSelectedAd(null)} title="Detalii Anunț">
        {selectedAd && <AdDetails id={selectedAd.id} initialData={selectedAd} onClose={() => setSelectedAd(null)} isFavorite={favorites.includes(selectedAd.id)} onToggleFavorite={() => handleToggleFavorite(selectedAd.id)} onAddToast={addToast} />}
      </Modal>

      <ToastContainer toasts={toasts} removeToast={removeToast} />
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Ad } from '../types';

interface AdCardProps {
  ad: Ad;
  onClick: () => void;
  isFavorite: boolean;
  onToggleFavorite: (e: React.MouseEvent | React.KeyboardEvent) => void;
  mini?: boolean; 
  priority?: boolean;
  showRouteContext?: boolean;
  routePosition?: number;
}

export const AdCard: React.FC<AdCardProps> = ({ 
    ad, 
    onClick, 
    isFavorite, 
    onToggleFavorite, 
    mini = false, 
    showRouteContext = false,
    routePosition
}) => {
  const isBio = ad.title.toLowerCase().includes('bio') || ad.description.toLowerCase().includes('natural');
  const [imageLoaded, setImageLoaded] = useState(false);

  const primaryCategory = ad.categories[0] || 'Produs';
  const showRating = ad.rating > 0;

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' || e.key === ' ') {
      e.preventDefault();
      onClick();
    }
  };

  if (mini) {
    return (
      <div 
        onClick={onClick}
        className="group bg-white rounded-2xl border border-stone-200/60 shadow-xl shadow-stone-200/30 overflow-hidden hover:shadow-2xl cursor-pointer flex flex-col h-full relative transition-all"
      >
        <div className="relative h-32 w-full bg-stone-100">
           {!imageLoaded && <div className="absolute inset-0 bg-stone-100 animate-pulse z-10" />}
           <img 
              src={ad.images[0] || 'https://via.placeholder.com/400x300?text=Fără+Imagine'} 
              alt=""
              className={`w-full h-full object-cover transition-all duration-500 group-hover:scale-105 ${imageLoaded ? 'opacity-100' : 'opacity-0'}`}
              onLoad={() => setImageLoaded(true)}
            />
           <div className="absolute bottom-2 right-2 z-20">
             <span className="px-2.5 py-1 rounded-lg text-[10px] font-black bg-stone-900 text-white shadow-xl border border-white/20">
               {ad.price} RON
             </span>
           </div>
        </div>
        <div className="p-3">
          <h4 className="text-[11px] font-bold text-stone-900 line-clamp-1 uppercase tracking-tight">
            {ad.title}
          </h4>
        </div>
      </div>
    );
  }

  return (
    <div 
      onClick={onClick}
      onKeyDown={handleKeyDown}
      role="button"
      tabIndex={0}
      className={`group bg-white rounded-[2rem] border transition-all duration-500 cursor-pointer flex flex-col h-full relative ${
        ad.isPremium 
          ? 'border-amber-200 shadow-2xl shadow-amber-100/50 hover:border-amber-300' 
          : 'border-stone-200/60 shadow-xl shadow-stone-200/40 hover:shadow-2xl hover:shadow-stone-300/50 hover:border-stone-300 hover:-translate-y-1.5'
      }`}
    >
      <div className="relative h-64 w-full overflow-hidden bg-stone-100 rounded-t-[2rem]">
        {!imageLoaded && <div className="absolute inset-0 bg-stone-200 animate-pulse z-10" />}
        <img 
          src={ad.images[0] || 'https://via.placeholder.com/400x300?text=Fără+Imagine'} 
          alt=""
          className={`w-full h-full object-cover transform group-hover:scale-105 transition-all duration-700 ease-out ${imageLoaded ? 'opacity-100' : 'opacity-0'}`}
          onLoad={() => setImageLoaded(true)}
        />

        {/* Route Context Overlay */}
        {showRouteContext && typeof routePosition === 'number' && (
            <div className="absolute bottom-3 left-3 right-3 bg-white/80 backdrop-blur-md border border-white/50 p-3 rounded-2xl z-20 shadow-sm flex items-center justify-between">
                <div className="flex items-center gap-2">
                    <div className="w-6 h-6 rounded-lg bg-stone-900 text-white flex items-center justify-center text-[10px] font-bold">
                        {routePosition + 1}
                    </div>
                    <span className="text-[9px] font-bold uppercase tracking-[0.2em] text-stone-700">Oprire pe rută</span>
                </div>
            </div>
        )}

        {/* Top Badges */}
        <div className="absolute top-4 left-4 flex flex-col space-y-2 items-start z-20">
           <span className="inline-flex items-center px-3 py-1 rounded-full text-[9px] font-black bg-white/90 backdrop-blur-md text-stone-900 uppercase tracking-widest border border-stone-200/20 shadow-sm">
             {primaryCategory}
           </span>
           {ad.isPremium && (
             <span className="inline-flex items-center px-3 py-1 rounded-full text-[9px] font-black bg-amber-400 text-amber-900 uppercase tracking-widest shadow-sm">
               Prioritar
             </span>
           )}
        </div>

        {/* ULTRA HIGH VISIBILITY PRICE BADGE */}
        <div className="absolute bottom-4 right-4 z-20 scale-110">
            <div className="bg-stone-900 text-white px-5 py-2.5 rounded-2xl shadow-[0_20px_50px_rgba(0,0,0,0.3)] flex flex-col items-center group-hover:bg-emerald-700 transition-colors duration-300 border border-white/20">
                <span className="text-[7px] font-black uppercase tracking-[0.25em] opacity-60 mb-0.5 leading-none">Preț</span>
                <span className="text-lg font-black tracking-tighter leading-none">{ad.price} <span className="text-[10px] font-bold">RON</span></span>
            </div>
        </div>

        {/* Favorites button */}
        <button
            onClick={(e) => { e.stopPropagation(); onToggleFavorite(e); }}
            className="absolute top-4 right-4 p-2.5 rounded-2xl bg-white/80 backdrop-blur-md shadow-sm border border-stone-200/50 text-stone-400 hover:text-rose-500 hover:bg-white transition-all transform active:scale-90 z-20"
        >
            <svg className={`w-4 h-4 ${isFavorite ? 'fill-current text-rose-500' : ''}`} xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M20.84 4.61a5.5 5.5 0 0 0-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 0 0-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 0 0 0-7.78z"></path></svg>
        </button>
      </div>

      <div className="p-8 flex flex-col flex-grow">
        <div className="mb-4">
            <h3 className="text-xl font-black text-stone-900 line-clamp-1 group-hover:text-stone-700 transition-colors tracking-tight uppercase">
                {ad.title}
            </h3>
            <div className="flex items-center text-[10px] font-bold text-stone-400 uppercase tracking-widest mt-2">
                <svg className="w-3.5 h-3.5 mr-1.5 text-stone-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" /></svg>
                {ad.location.city}, {ad.location.county}
            </div>
        </div>

        <p className="text-sm text-stone-500 line-clamp-2 mb-8 leading-relaxed font-medium">
            {ad.description}
        </p>

        <div className="pt-6 border-t border-stone-100 flex items-center justify-between mt-auto">
            <div className="flex items-center gap-3">
                {showRating && (
